import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum StudioMode {
  VIDEO = 'video',
  PHOTO = 'photo',
  PAINT = 'paint',
  AD_BUILDER = 'ad_builder',
  SHOP = 'shop'
}

export interface Project {
  id: string;
  name: string;
  type: StudioMode;
  thumbnail: string;
  updatedAt: number;
  data: any;
}

export interface AdCategory {
  id: string;
  label: string;
  icon: string;
}

export interface TimelineLayer {
  id: string;
  name: string;
  type: 'video' | 'image' | 'audio' | 'text';
  start: number;
  duration: number;
  content: string;
}

import React, { useState, useEffect } from 'react';
import { HashRouter, Routes, Route, Navigate } from 'react-router-dom';
import Sidebar from './components/Sidebar';
import Header from './components/Header';
import Dashboard from './components/Dashboard';
import VideoEditor from './components/VideoEditor';
import PhotoEditor from './components/PhotoEditor';
import PaintStudio from './components/PaintStudio';
import AdBuilder from './components/AdBuilder';
import TemplatesGallery from './components/TemplatesGallery';
import { StudioMode, Project } from './types';

const App: React.FC = () => {
  const [activeMode, setActiveMode] = useState<StudioMode>(StudioMode.VIDEO);
  const [projects, setProjects] = useState<Project[]>([]);
  const [isSidebarOpen, setIsSidebarOpen] = useState(true);

  // Load projects from localStorage
  useEffect(() => {
    const saved = localStorage.getItem('lumina_projects');
    if (saved) {
      setProjects(JSON.parse(saved));
    }
  }, []);

  const saveProject = (project: Project) => {
    const updated = [project, ...projects.filter(p => p.id !== project.id)];
    setProjects(updated);
    localStorage.setItem('lumina_projects', JSON.stringify(updated));
  };

  return (
    <HashRouter>
      <div className="flex h-screen bg-slate-950 text-slate-100 overflow-hidden">
        <Sidebar 
          isOpen={isSidebarOpen} 
          toggle={() => setIsSidebarOpen(!isSidebarOpen)} 
          activeMode={activeMode}
          setActiveMode={setActiveMode}
        />

        <div className="flex-1 flex flex-col min-w-0 h-full relative">
          <Header />
          <main className="flex-1 overflow-auto relative p-4 md:p-6">
            <Routes>
              <Route path="/" element={<Dashboard projects={projects} setActiveMode={setActiveMode} />} />
              <Route path="/video" element={<VideoEditor onSave={saveProject} />} />
              <Route path="/photo" element={<PhotoEditor onSave={saveProject} />} />
              <Route path="/paint" element={<PaintStudio onSave={saveProject} />} />
              <Route path="/ads" element={<AdBuilder onSave={saveProject} />} />
              <Route path="/templates" element={<TemplatesGallery />} />
              <Route path="*" element={<Navigate to="/" replace />} />
            </Routes>
          </main>
        </div>
      </div>
    </HashRouter>
  );
};

export default App;

import { GoogleGenAI, Type } from "@google/genai";

export class GeminiService {
  private static instance: GeminiService;
  private ai: any;

  private constructor() {
    this.ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
  }

  public static getInstance(): GeminiService {
    if (!GeminiService.instance) {
      GeminiService.instance = new GeminiService();
    }
    return GeminiService.instance;
  }

  async generateImage(prompt: string, aspectRatio: "1:1" | "16:9" | "9:16" = "1:1") {
    try {
      const response = await this.ai.models.generateContent({
        model: 'gemini-2.5-flash-image',
        contents: { parts: [{ text: prompt }] },
        config: { imageConfig: { aspectRatio } }
      });

      for (const part of response.candidates[0].content.parts) {
        if (part.inlineData) {
          return `data:image/png;base64,${part.inlineData.data}`;
        }
      }
      return null;
    } catch (error) {
      console.error("Image generation failed", error);
      return null;
    }
  }

  async editImage(base64Image: string, instruction: string) {
    try {
      const response = await this.ai.models.generateContent({
        model: 'gemini-2.5-flash-image',
        contents: {
          parts: [
            { inlineData: { data: base64Image.split(',')[1], mimeType: 'image/png' } },
            { text: instruction }
          ]
        }
      });

      for (const part of response.candidates[0].content.parts) {
        if (part.inlineData) {
          return `data:image/png;base64,${part.inlineData.data}`;
        }
      }
      return null;
    } catch (error) {
      console.error("Image editing failed", error);
      return null;
    }
  }

  async generateCaptions(theme: string, category: string) {
    try {
      const response = await this.ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Generate 5 catchy marketing captions for a ${category} project with theme: ${theme}. Format as JSON array of strings.`,
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.ARRAY,
            items: { type: Type.STRING }
          }
        }
      });
      return JSON.parse(response.text);
    } catch (error) {
      return ["Unlock your creativity", "Professional designs in seconds", "The future of content"];
    }
  }
}

import React from 'react';
import { useNavigate, useLocation } from 'react-router-dom';
import { 
  LayoutDashboard, 
  Video, 
  Image as ImageIcon, 
  Paintbrush, 
  Megaphone, 
  Layers,
  ShoppingBag,
  Settings,
  ChevronLeft,
  ChevronRight
} from 'lucide-react';
import { StudioMode } from '../types';

interface SidebarProps {
  isOpen: boolean;
  toggle: () => void;
  activeMode: StudioMode;
  setActiveMode: (mode: StudioMode) => void;
}

const Sidebar: React.FC<SidebarProps> = ({ isOpen, toggle, activeMode, setActiveMode }) => {
  const navigate = useNavigate();
  const location = useLocation();

  const menuItems = [
    { id: 'dashboard', icon: LayoutDashboard, label: 'Dashboard', path: '/' },
    { id: StudioMode.VIDEO, icon: Video, label: 'Video Editor', path: '/video' },
    { id: StudioMode.PHOTO, icon: ImageIcon, label: 'Photo Studio', path: '/photo' },
    { id: StudioMode.PAINT, icon: Paintbrush, label: 'Character Paint', path: '/paint' },
    { id: StudioMode.AD_BUILDER, icon: Megaphone, label: 'Ad Builder', path: '/ads' },
    { id: 'templates', icon: Layers, label: 'Templates', path: '/templates' },
    { id: 'shop', icon: ShoppingBag, label: 'Marketplace', path: '/shop' },
  ];

  const handleNav = (item: any) => {
    if (item.id in StudioMode) {
      setActiveMode(item.id as StudioMode);
    }
    navigate(item.path);
  };

  return (
    <aside className={`${isOpen ? 'w-64' : 'w-20'} bg-slate-900 border-r border-slate-800 transition-all duration-300 flex flex-col relative z-50`}>
      <div className="p-6 flex items-center justify-between">
        {isOpen ? (
          <h1 className="text-xl font-bold bg-gradient-to-r from-cyan-400 to-blue-500 bg-clip-text text-transparent truncate">
            LUMINA
          </h1>
        ) : (
          <div className="w-8 h-8 bg-gradient-to-br from-cyan-400 to-blue-500 rounded-lg" />
        )}
      </div>

      <nav className="flex-1 px-3 space-y-2">
        {menuItems.map((item) => (
          <button
            key={item.id}
            onClick={() => handleNav(item)}
            className={`w-full flex items-center p-3 rounded-xl transition-all ${
              location.pathname === item.path 
                ? 'bg-blue-600/20 text-blue-400' 
                : 'text-slate-400 hover:bg-slate-800 hover:text-slate-100'
            }`}
          >
            <item.icon className="w-6 h-6 shrink-0" />
            {isOpen && <span className="ml-4 font-medium">{item.label}</span>}
          </button>
        ))}
      </nav>

      <div className="p-4 border-t border-slate-800">
        <button
          onClick={toggle}
          className="w-full flex items-center p-3 text-slate-400 hover:bg-slate-800 rounded-xl transition-all"
        >
          {isOpen ? <ChevronLeft className="w-6 h-6" /> : <ChevronRight className="w-6 h-6" />}
          {isOpen && <span className="ml-4 font-medium">Collapse</span>}
        </button>
      </div>
    </aside>
  );
};

export default Sidebar;

