interface PhotoEditorProps {
  onSave: (project: Project) => void;
}

const PhotoEditor: React.FC<PhotoEditorProps> = ({ onSave }) => {
  const [image, setImage] = useState<string>("https://picsum.photos/seed/photo1/1200/800");
  const [isProcessing, setIsProcessing] = useState(false);
  const [instruction, setInstruction] = useState("");

  const handleAIEdit = async () => {
    if (!instruction) return;
    setIsProcessing(true);
    const gemini = GeminiService.getInstance();
    const result = await gemini.editImage(image, instruction);
    if (result) setImage(result);
    setIsProcessing(false);
    setInstruction("");
  };

  const handleSave = () => {
    onSave({
      id: Date.now().toString(),
      name: "Edited Photo",
      type: StudioMode.PHOTO,
      thumbnail: image,
      updatedAt: Date.now(),
      data: { image }
    });
  };

  const filters = [
    { name: 'Vivid', class: 'sepia-0 brightness-110' },
    { name: 'Noir', class: 'grayscale' },
    { name: 'Retro', class: 'sepia brightness-90' },
    { name: 'Cool', class: 'hue-rotate-180 saturate-150' },
  ];

  return (
    <div className="h-full flex flex-col space-y-4 animate-in fade-in duration-500">
