            Upload
          </button>
          <button onClick={handleSave} className="flex items-center px-4 py-2 bg-blue-600 hover:bg-blue-500 rounded-xl text-sm">
            <Save className="w-4 h-4 mr-2" />
            Save
          </button>
        </div>
      </div>

      <div className="flex-1 flex space-x-6 min-h-0">
        <div className="flex-1 bg-slate-900 rounded-3xl border border-slate-800 p-6 flex flex-col">
          <div className="flex-1 bg-black/50 rounded-2xl flex items-center justify-center relative overflow-hidden">
            <img 
              src={image} 
              alt="Edit Workspace" 
              className={`max-h-full max-w-full object-contain transition-all duration-700 ${isProcessing ? 'blur-sm opacity-50' : ''}`}
            />
