                  <span className="text-slate-500">120</span>
                </div>
                <input type="range" className="w-full accent-blue-500" />
              </div>
            </div>
          </div>

          <div className="pt-4 border-t border-slate-800">
             <button className="w-full flex items-center justify-center p-3 bg-slate-800 hover:bg-slate-700 rounded-xl text-xs font-medium transition-all">
                <RotateCcw className="w-4 h-4 mr-2" />
                Reset Changes
             </button>
