interface PaintStudioProps {
  onSave: (project: Project) => void;
}

const PaintStudio: React.FC<PaintStudioProps> = ({ onSave }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [tool, setTool] = useState<'brush' | 'eraser' | 'shape'>('brush');
  const [color, setColor] = useState('#3b82f6');
  const [isDrawing, setIsDrawing] = useState(false);
  const [isGenerating, setIsGenerating] = useState(false);
  const [prompt, setPrompt] = useState("");

  useEffect(() => {
    const canvas = canvasRef.current;
    if (canvas) {
      const ctx = canvas.getContext('2d');
      if (ctx) {
        ctx.lineJoin = 'round';
        ctx.lineCap = 'round';
        ctx.lineWidth = 5;
      }
    }
  }, []);

  const startDrawing = (e: React.MouseEvent) => {
    setIsDrawing(true);
    draw(e);
  };

  const draw = (e: React.MouseEvent) => {
    if (!isDrawing) return;
    const canvas = canvasRef.current;
    const ctx = canvas?.getContext('2d');
    if (!canvas || !ctx) return;

    const rect = canvas.getBoundingClientRect();
    const x = e.clientX - rect.left;
    const y = e.clientY - rect.top;

    ctx.strokeStyle = tool === 'eraser' ? '#0f172a' : color;
    ctx.lineTo(x, y);
    ctx.stroke();
    ctx.beginPath();
    ctx.moveTo(x, y);
  };

  const endDrawing = () => {
    setIsDrawing(false);
    const canvas = canvasRef.current;
    canvas?.getContext('2d')?.beginPath();
  };

  const handleCharacterGenerate = async () => {
    if (!prompt) return;
    setIsGenerating(true);
    const gemini = GeminiService.getInstance();
    const result = await gemini.generateImage(`Animation character design for: ${prompt}. Concept art sheet, high resolution, expressive.`, "1:1");
    if (result) {
      const canvas = canvasRef.current;
      const ctx = canvas?.getContext('2d');
      const img = new Image();
      img.onload = () => {
        ctx?.clearRect(0, 0, canvas?.width || 800, canvas?.height || 600);
        ctx?.drawImage(img, 0, 0, canvas?.width || 800, canvas?.height || 600);
      };
      img.src = result;
    }
    setIsGenerating(false);
  };

  const handleSave = () => {
    const canvas = canvasRef.current;
    if (canvas) {
      onSave({
        id: Date.now().toString(),
        name: "My Animation Character",
        type: StudioMode.PAINT,
        thumbnail: canvas.toDataURL(),
        updatedAt: Date.now(),
        data: {}
      });
    }
  };

  return (
    <div className="h-full flex flex-col space-y-4 animate-in fade-in duration-500">
      <div className="flex items-center justify-between mb-2">
        <h2 className="text-xl font-bold flex items-center">
          <Paintbrush className="w-5 h-5 mr-2 text-emerald-500" />
          Animation Paint Studio
        </h2>
        <div className="flex space-x-2">
           <button className="flex items-center px-4 py-2 bg-slate-800 hover:bg-slate-700 rounded-xl text-sm"><Undo className="w-4 h-4 mr-2" /> Undo</button>
           <button onClick={handleSave} className="flex items-center px-4 py-2 bg-blue-600 hover:bg-blue-500 rounded-xl text-sm"><Save className="w-4 h-4 mr-2" /> Save</button>
        </div>
      </div>

      <div className="flex-1 flex space-x-6 min-h-0">
         <div className="w-16 bg-slate-900 border border-slate-800 rounded-3xl p-3 flex flex-col items-center space-y-4">
            <button onClick={() => setTool('brush')} className={`p-3 rounded-2xl transition-all ${tool === 'brush' ? 'bg-blue-600 text-white' : 'text-slate-400 hover:bg-slate-800'}`}>
              <Paintbrush className="w-6 h-6" />
            </button>
            <button onClick={() => setTool('eraser')} className={`p-3 rounded-2xl transition-all ${tool === 'eraser' ? 'bg-blue-600 text-white' : 'text-slate-400 hover:bg-slate-800'}`}>
              <Eraser className="w-6 h-6" />
            </button>
            <button className="p-3 rounded-2xl transition-all text-slate-400 hover:bg-slate-800">
              <Square className="w-6 h-6" />
            </button>
            <button className="p-3 rounded-2xl transition-all text-slate-400 hover:bg-slate-800">
              <Circle className="w-6 h-6" />
            </button>
            <button className="p-3 rounded-2xl transition-all text-slate-400 hover:bg-slate-800">
              <Type className="w-6 h-6" />
            </button>

            <div className="pt-4 border-t border-slate-800 flex flex-col items-center space-y-3">
              {['#3b82f6', '#10b981', '#f59e0b', '#ef4444', '#8b5cf6', '#ffffff'].map(c => (
                <button 
                  key={c}
                  onClick={() => setColor(c)}
                  className={`w-6 h-6 rounded-full border-2 ${color === c ? 'border-white scale-110 shadow-lg shadow-white/20' : 'border-transparent'}`}
                  style={{ backgroundColor: c }}
                />
              ))}
            </div>
         </div>

         <div className="flex-1 bg-slate-900 rounded-3xl border border-slate-800 p-8 flex flex-col">
            <div className="flex-1 bg-[#0f172a] rounded-2xl shadow-inner border border-white/5 overflow-hidden relative group">
               <canvas 
                ref={canvasRef}
                width={800}
                height={600}
                onMouseDown={startDrawing}
                onMouseMove={draw}
                onMouseUp={endDrawing}
                onMouseLeave={endDrawing}
                className="w-full h-full cursor-crosshair"
               />
               <div className="absolute top-4 right-4 flex space-x-2 opacity-0 group-hover:opacity-100 transition-all">
                  <button className="p-2 bg-slate-900/80 backdrop-blur rounded-lg text-slate-300 hover:text-white border border-white/10"><Download className="w-4 h-4" /></button>
                  <button className="p-2 bg-slate-900/80 backdrop-blur rounded-lg text-slate-300 hover:text-white border border-white/10"><Video className="w-4 h-4" /></button>
               </div>
            </div>

            <div className="mt-6 flex space-x-4">
              <div className="flex-1 relative">
                <input 
                  value={prompt}
                  onChange={(e) => setPrompt(e.target.value)}
                  placeholder="Design an AI character: 'A cute robot exploring space'..." 
                  className="w-full bg-slate-800 border border-slate-700 rounded-2xl py-3.5 pl-5 pr-12 focus:outline-none focus:ring-2 focus:ring-emerald-500/50"
                />
                <button 
                  onClick={handleCharacterGenerate}
                  disabled={isGenerating || !prompt}
                  className="absolute right-2.5 top-1/2 -translate-y-1/2 p-2 bg-emerald-600 rounded-xl text-white disabled:opacity-50 shadow-lg shadow-emerald-600/20"
                >
                  {isGenerating ? <Sparkles className="w-5 h-5 animate-spin" /> : <Wand2 className="w-5 h-5" />}
                </button>
              </div>
            </div>
         </div>
      </div>
    </div>
  );
};

