import { GoogleGenAI, Type } from "@google/genai";

export class GeminiService {
  private static instance: GeminiService;
  private ai: any;

  private constructor() {
    // FIX: Always use { apiKey: process.env.API_KEY } for initialization as per Google GenAI SDK guidelines
    this.ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  }

  public static getInstance(): GeminiService {
    if (!GeminiService.instance) {
      GeminiService.instance = new GeminiService();
    }
    return GeminiService.instance;
  }

  async generateImage(prompt: string, aspectRatio: "1:1" | "16:9" | "9:16" = "1:1") {
    try {
      // FIX: Use gemini-2.5-flash-image for general image generation tasks
      const response = await this.ai.models.generateContent({
        model: 'gemini-2.5-flash-image',
        contents: { parts: [{ text: prompt }] },
        config: { imageConfig: { aspectRatio } }
      });

      // FIX: Iterate through all parts to find the image part as it may not be the first one
      for (const part of response.candidates[0].content.parts) {
        if (part.inlineData) {
          return `data:image/png;base64,${part.inlineData.data}`;
        }
      }
      return null;
    } catch (error) {
      console.error("Image generation failed", error);
      return null;
    }
  }

  async editImage(base64Image: string, instruction: string) {
    try {
      // FIX: Use gemini-2.5-flash-image for image editing tasks
      const response = await this.ai.models.generateContent({
        model: 'gemini-2.5-flash-image',
        contents: {
          parts: [
            { inlineData: { data: base64Image.split(',')[1], mimeType: 'image/png' } },
            { text: instruction }
          ]
        }
      });

      // FIX: Iterate through all parts to find the image part
      for (const part of response.candidates[0].content.parts) {
        if (part.inlineData) {
          return `data:image/png;base64,${part.inlineData.data}`;
        }
      }
      return null;
    } catch (error) {
      console.error("Image editing failed", error);
      return null;
    }
  }

  async generateCaptions(theme: string, category: string) {
    try {
      // FIX: Use gemini-3-flash-preview for basic text tasks like caption generation
      const response = await this.ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Generate 5 catchy marketing captions for a ${category} project with theme: ${theme}. Format as JSON array of strings.`,
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.ARRAY,
            items: { type: Type.STRING }
          }
        }
      });
      // FIX: The text output is accessed via the .text property, not a method
      return JSON.parse(response.text);
    } catch (error) {
      return ["Unlock your creativity", "Professional designs in seconds", "The future of content"];
    }
  }
}

