interface VideoEditorProps {
  onSave: (project: Project) => void;
}

const VideoEditor: React.FC<VideoEditorProps> = ({ onSave }) => {
  const [isPlaying, setIsPlaying] = useState(false);
  const [currentTime, setCurrentTime] = useState(0);
  const [selectedLayerIds, setSelectedLayerIds] = useState<Set<string>>(new Set());
  const [layers, setLayers] = useState<TimelineLayer[]>([
    { id: '1', name: 'Main Visual', type: 'video', start: 0, duration: 100, content: 'https://picsum.photos/seed/vid1/800/450' },
    { id: '2', name: 'BGM Track', type: 'audio', start: 0, duration: 80, content: 'bg-music' },
    { id: '3', name: 'Intro Text', type: 'text', start: 5, duration: 30, content: 'Summer Vlog 2024' },
  ]);
  const [isGenerating, setIsGenerating] = useState(false);
  const audioInputRef = useRef<HTMLInputElement>(null);

  const totalDuration = 100;

  const handlePlayToggle = () => setIsPlaying(!isPlaying);

  const toggleLayerSelection = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    const newSelection = new Set(selectedLayerIds);
    if (newSelection.has(id)) {
      newSelection.delete(id);
    } else {
      newSelection.add(id);
    }
    setSelectedLayerIds(newSelection);
  };

  const handleSave = () => {
    onSave({
      id: Date.now().toString(),
      name: "New Video Composition",
