    const file = e.target.files?.[0];
    if (file) {
      const newLayer: TimelineLayer = {
        id: Date.now().toString(),
        name: file.name,
        type: file.type.startsWith('audio') ? 'audio' : 'video',
        start: currentTime,
        duration: 40, // Default duration simulation
        content: URL.createObjectURL(file)
      };
      setLayers([...layers, newLayer]);
    }
  };

  const handleMergeAudio = () => {
    const selectedAudio = layers.filter(l => selectedLayerIds.has(l.id) && l.type === 'audio');
    if (selectedAudio.length < 2) return;

    const earliestStart = Math.min(...selectedAudio.map(a => a.start));
    const latestEnd = Math.max(...selectedAudio.map(a => a.start + a.duration));

    const mergedLayer: TimelineLayer = {
      id: `merged-${Date.now()}`,
      name: `Merged Audio (${selectedAudio.length} tracks)`,
      type: 'audio',
      start: earliestStart,
      duration: latestEnd - earliestStart,
      content: 'composite-audio-stream'
    };

    // Remove old tracks and add the new merged one
    setLayers([
      ...layers.filter(l => !selectedLayerIds.has(l.id)),
      mergedLayer
    ]);
    setSelectedLayerIds(new Set());
  };

  const deleteSelected = () => {
    setLayers(layers.filter(l => !selectedLayerIds.has(l.id)));
    setSelectedLayerIds(new Set());
  };

  const handleAIGenerate = async () => {
    setIsGenerating(true);
    const gemini = GeminiService.getInstance();
    const result = await gemini.generateImage("Cinematic mountain landscape 4k hyperrealistic", "16:9");
    if (result) {
      setLayers([...layers, {
        id: Date.now().toString(),
        name: 'AI Gen Clip',
        type: 'video',
        start: currentTime,
        duration: 30,
        content: result
      }]);
    }
    setIsGenerating(false);
  };

  return (
    <div className="h-full flex flex-col space-y-4 animate-in fade-in duration-500 overflow-hidden">
