        type="file" 
        ref={audioInputRef} 
        onChange={handleFileUpload} 
        accept="audio/*,video/*" 
        className="hidden" 
      />

      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 mb-2">
        <h2 className="text-xl font-bold flex items-center">
          <Video className="w-5 h-5 mr-2 text-rose-500" />
          Pro Video Studio
        </h2>
        <div className="flex flex-wrap items-center gap-2">
          {selectedLayerIds.size > 0 && (
            <div className="flex items-center bg-slate-800 rounded-lg p-1 border border-slate-700 mr-2">
              <button 
                onClick={deleteSelected}
                className="p-1.5 hover:bg-red-500/20 text-red-400 rounded-md transition-all"
                title="Delete Selected"
              >
                <Trash2 className="w-4 h-4" />
              </button>
              {Array.from(selectedLayerIds).every(id => layers.find(l => l.id === id)?.type === 'audio') && selectedLayerIds.size >= 2 && (
                <button 
                  onClick={handleMergeAudio}
                  className="p-1.5 hover:bg-emerald-500/20 text-emerald-400 rounded-md transition-all ml-1"
                  title="Merge Audio Tracks"
                >
                  <Combine className="w-4 h-4" />
                </button>
              )}
            </div>
          )}
          <button onClick={handleAIGenerate} disabled={isGenerating} className="flex items-center px-3 py-1.5 bg-indigo-600 hover:bg-indigo-500 rounded-lg text-sm disabled:opacity-50">
            <Wand2 className="w-4 h-4 mr-2" />
            {isGenerating ? 'Dreaming...' : 'AI Enhance'}
          </button>
          <button onClick={handleSave} className="flex items-center px-3 py-1.5 bg-slate-800 hover:bg-slate-700 rounded-lg text-sm">
            <Save className="w-4 h-4 mr-2" />
            Save
          </button>
          <button className="flex items-center px-3 py-1.5 bg-blue-600 hover:bg-blue-500 rounded-lg text-sm font-semibold">
            <Download className="w-4 h-4 mr-2" />
            Export
          </button>
        </div>
      </div>

      <div className="flex-1 grid grid-cols-1 md:grid-cols-12 gap-4 min-h-0">
        <div className="md:col-span-9 flex flex-col min-h-0 bg-slate-900 rounded-3xl border border-slate-800 p-4">
          <div className="flex-1 bg-black rounded-2xl flex items-center justify-center relative overflow-hidden group">
            <img 
              src={layers.find(l => l.type === 'video')?.content || 'https://picsum.photos/seed/empty/800/450'} 
              alt="Preview" 
              className="max-h-full max-w-full object-contain"
            />
            {isPlaying && (
              <div className="absolute inset-0 bg-blue-500/5 animate-pulse pointer-events-none" />
            )}
            <div className="absolute bottom-6 left-1/2 -translate-x-1/2 flex items-center space-x-8 bg-slate-900/90 backdrop-blur-xl px-8 py-4 rounded-full border border-white/10 opacity-0 group-hover:opacity-100 transition-all shadow-2xl">
              <button className="text-slate-400 hover:text-white transition-colors"><SkipBack className="w-6 h-6" /></button>
              <button 
                onClick={handlePlayToggle}
                className="w-12 h-12 bg-white rounded-full flex items-center justify-center text-slate-950 hover:scale-110 active:scale-95 transition-all"
              >
                {isPlaying ? <Pause className="w-6 h-6 fill-current" /> : <Play className="w-6 h-6 fill-current ml-1" />}
              </button>
              <button className="text-slate-400 hover:text-white transition-colors"><SkipForward className="w-6 h-6" /></button>
            </div>
          </div>
        </div>

        <div className="md:col-span-3 bg-slate-900 rounded-3xl border border-slate-800 p-6 space-y-6 overflow-y-auto">
          <h3 className="text-xs font-bold text-slate-500 uppercase tracking-widest">Editor Tools</h3>
          <div className="grid grid-cols-2 gap-3">
