              className="p-4 bg-slate-800 hover:bg-slate-700 rounded-2xl flex flex-col items-center justify-center transition-all group border border-slate-700 hover:border-blue-500/50"
            >
              <Upload className="w-6 h-6 mb-2 text-blue-400 group-hover:scale-110" />
              <span className="text-[10px] font-bold uppercase tracking-tighter">Import</span>
            </button>
            <button className="p-4 bg-slate-800 hover:bg-slate-700 rounded-2xl flex flex-col items-center justify-center transition-all group border border-slate-700">
              <Scissors className="w-6 h-6 mb-2 text-rose-400 group-hover:scale-110" />
              <span className="text-[10px] font-bold uppercase tracking-tighter">Split</span>
            </button>
            <button className="p-4 bg-slate-800 hover:bg-slate-700 rounded-2xl flex flex-col items-center justify-center transition-all group border border-slate-700">
              <TypeIcon className="w-6 h-6 mb-2 text-indigo-400 group-hover:scale-110" />
              <span className="text-[10px] font-bold uppercase tracking-tighter">Text</span>
            </button>
            <button className="p-4 bg-slate-800 hover:bg-slate-700 rounded-2xl flex flex-col items-center justify-center transition-all group border border-slate-700">
              <Music className="w-6 h-6 mb-2 text-emerald-400 group-hover:scale-110" />
              <span className="text-[10px] font-bold uppercase tracking-tighter">SFX</span>
            </button>
          </div>

          <div className="pt-4 border-t border-slate-800">
            <h4 className="text-[10px] font-bold text-slate-600 uppercase mb-3">Layer Info</h4>
            <div className="bg-slate-950/50 rounded-xl p-3 border border-slate-800">
              {selectedLayerIds.size === 1 ? (
                <div className="space-y-1">
                  <p className="text-xs font-medium text-blue-400 truncate">
                    {layers.find(l => l.id === Array.from(selectedLayerIds)[0])?.name}
                  </p>
                  <p className="text-[10px] text-slate-500">Duration: {layers.find(l => l.id === Array.from(selectedLayerIds)[0])?.duration}s</p>
                </div>
              ) : (
                <p className="text-[10px] text-slate-600 italic">Select a layer to view details</p>
              )}
            </div>
          </div>
        </div>
      </div>

      <div className="h-72 bg-slate-900 rounded-3xl border border-slate-800 flex flex-col overflow-hidden shadow-2xl">
        <div className="px-6 py-3 border-b border-slate-800 flex items-center justify-between bg-slate-900/50">
