             </div>
          </div>
          <div className="text-xs font-mono text-blue-400 bg-blue-400/10 px-3 py-1 rounded-full border border-blue-400/20">
            00:{(currentTime/10).toFixed(0).padStart(2,'0')}:00 / 00:10:00
          </div>
