        <div className="flex-1 overflow-x-auto p-6 scrollbar-hide">
          <div className="h-full w-[2500px] space-y-3 relative">
             {/* Timeline markers */}
             <div className="flex space-x-40 border-b border-slate-800/50 mb-6 h-6 select-none">
