interface VideoEditorProps {
  onSave: (project: Project) => void;
}

const VideoEditor: React.FC<VideoEditorProps> = ({ onSave }) => {
  const [isPlaying, setIsPlaying] = useState(false);
  const [currentTime, setCurrentTime] = useState(0);
  const [selectedLayerIds, setSelectedLayerIds] = useState<Set<string>>(new Set());
  const [layers, setLayers] = useState<TimelineLayer[]>([
    { id: '1', name: 'Main Visual', type: 'video', start: 0, duration: 100, content: 'https://picsum.photos/seed/vid1/800/450' },
    { id: '2', name: 'BGM Track', type: 'audio', start: 0, duration: 80, content: 'bg-music' },
    { id: '3', name: 'Intro Text', type: 'text', start: 5, duration: 30, content: 'Summer Vlog 2024' },
  ]);
  const [isGenerating, setIsGenerating] = useState(false);
  const [showVfxPanel, setShowVfxPanel] = useState(false);
  const audioInputRef = useRef<HTMLInputElement>(null);

  const totalDuration = 100;

  useEffect(() => {
    let interval: number;
    if (isPlaying) {
      interval = window.setInterval(() => {
        setCurrentTime(prev => {
          if (prev >= totalDuration) {
            setIsPlaying(false);
            return 0;
          }
          return prev + 1;
        });
      }, 100);
    }
    return () => clearInterval(interval);
  }, [isPlaying]);

  const handlePlayToggle = () => setIsPlaying(!isPlaying);

  const toggleLayerSelection = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    const newSelection = new Set(selectedLayerIds);
    if (newSelection.has(id)) {
      newSelection.delete(id);
    } else {
      newSelection.add(id);
    }
    setSelectedLayerIds(newSelection);
  };

  const handleSave = () => {
    onSave({
      id: Date.now().toString(),
      name: "New Video Composition",
      type: StudioMode.VIDEO,
      thumbnail: layers.find(l => l.type === 'video')?.content || layers[0].content,
      updatedAt: Date.now(),
      data: { layers }
    });
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const newLayer: TimelineLayer = {
        id: Date.now().toString(),
        name: file.name,
        type: file.type.startsWith('audio') ? 'audio' : 'video',
        start: currentTime,
        duration: 40,
        content: URL.createObjectURL(file)
      };
      setLayers([...layers, newLayer]);
    }
  };

  const applyVfx = (vfxType: string) => {
    const newLayer: TimelineLayer = {
      id: `vfx-${Date.now()}`,
      name: `${vfxType.charAt(0).toUpperCase() + vfxType.slice(1)} Effect`,
      type: 'vfx',
      vfxType: vfxType,
      start: currentTime,
      duration: 30,
      content: ''
    };
    setLayers([...layers, newLayer]);
    setShowVfxPanel(false);
  };

  const handleMergeAudio = () => {
    const selectedAudio = layers.filter(l => selectedLayerIds.has(l.id) && l.type === 'audio');
    if (selectedAudio.length < 2) return;

    const earliestStart = Math.min(...selectedAudio.map(a => a.start));
    const latestEnd = Math.max(...selectedAudio.map(a => a.start + a.duration));

    const mergedLayer: TimelineLayer = {
      id: `merged-${Date.now()}`,
      name: `Merged Audio (${selectedAudio.length} tracks)`,
      type: 'audio',
      start: earliestStart,
      duration: latestEnd - earliestStart,
      content: 'composite-audio-stream'
    };

    setLayers([
      ...layers.filter(l => !selectedLayerIds.has(l.id)),
      mergedLayer
    ]);
    setSelectedLayerIds(new Set());
  };

  const deleteSelected = () => {
    setLayers(layers.filter(l => !selectedLayerIds.has(l.id)));
    setSelectedLayerIds(new Set());
  };

  const activeVfx = layers
    .filter(l => l.type === 'vfx' && currentTime >= l.start && currentTime <= (l.start + l.duration))
    .map(l => l.vfxType);

  return (
    <div className="h-full flex flex-col space-y-4 animate-in fade-in duration-500 overflow-hidden relative">
      <input 
        type="file" 
        ref={audioInputRef} 
        onChange={handleFileUpload} 
        accept="audio/*,video/*" 
        className="hidden" 
      />

      {showVfxPanel && (
        <div className="absolute inset-0 z-[60] bg-slate-950/60 backdrop-blur-sm flex items-center justify-center p-4">
          <div className="bg-slate-900 border border-slate-800 rounded-3xl w-full max-w-lg p-8 shadow-2xl animate-in zoom-in-95 duration-200">
            <div className="flex justify-between items-center mb-6">
              <h3 className="text-xl font-bold flex items-center">
                <Zap className="w-5 h-5 mr-2 text-amber-400" />
                VFX Library
              </h3>
              <button onClick={() => setShowVfxPanel(false)} className="p-2 hover:bg-slate-800 rounded-full">
                <X className="w-5 h-5" />
              </button>
            </div>
            <div className="grid grid-cols-2 gap-4">
              {[
                { id: 'glitch', icon: '🌩️', label: 'Digital Glitch', desc: 'Fragmented pixel artifacts' },
                { id: 'bloom', icon: '✨', label: 'Neon Bloom', desc: 'Radiant glow on highlights' },
                { id: 'particles', icon: '❄️', label: 'Ember Dust', desc: 'Floating cinematic particles' },
                { id: 'cinematic', icon: '🎬', label: 'AI Grade', desc: 'Gemini-optimized color' },
              ].map(vfx => (
                <button 
                  key={vfx.id}
                  onClick={() => applyVfx(vfx.id)}
                  className="p-6 bg-slate-800/50 hover:bg-slate-800 border border-slate-700 hover:border-amber-500/50 rounded-2xl text-left transition-all group"
                >
                  <span className="text-3xl mb-3 block group-hover:scale-110 transition-transform">{vfx.icon}</span>
                  <p className="font-bold text-slate-100">{vfx.label}</p>
                  <p className="text-xs text-slate-500 mt-1">{vfx.desc}</p>
                </button>
              ))}
            </div>
          </div>
        </div>
      )}

      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 mb-2">
        <h2 className="text-xl font-bold flex items-center">
          <Video className="w-5 h-5 mr-2 text-rose-500" />
