          <button onClick={() => setShowVfxPanel(true)} className="flex items-center px-4 py-2 bg-amber-500 hover:bg-amber-400 text-slate-950 rounded-xl text-sm font-bold shadow-lg shadow-amber-500/20 transition-all hover:scale-105">
