import { GoogleGenAI, Type, Modality } from "@google/genai";

export class GeminiService {
  private static instance: GeminiService;
  private ai: any;

  private constructor() {
    this.ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  }

  public static getInstance(): GeminiService {
    if (!GeminiService.instance) {
      GeminiService.instance = new GeminiService();
    }
    return GeminiService.instance;
  }

  async generateSpeech(text: string, voice: string = 'Kore') {
    try {
      const response = await this.ai.models.generateContent({
        model: "gemini-2.5-flash-preview-tts",
        contents: [{ parts: [{ text }] }],
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: {
            voiceConfig: {
              prebuiltVoiceConfig: { voiceName: voice },
            },
          },
        },
      });

      const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
      if (base64Audio) {
        return `data:audio/pcm;base64,${base64Audio}`;
      }
      return null;
    } catch (error) {
      console.error("Speech generation failed", error);
      return null;
    }
  }

  async generateImage(prompt: string, aspectRatio: "1:1" | "16:9" | "9:16" = "1:1") {
    try {
      const response = await this.ai.models.generateContent({
        model: 'gemini-2.5-flash-image',
        contents: { parts: [{ text: prompt }] },
        config: { imageConfig: { aspectRatio } }
      });

      for (const part of response.candidates[0].content.parts) {
        if (part.inlineData) {
          return `data:image/png;base64,${part.inlineData.data}`;
        }
      }
      return null;
    } catch (error) {
      console.error("Image generation failed", error);
      return null;
    }
  }

  async editImage(base64Image: string, instruction: string) {
    try {
      const response = await this.ai.models.generateContent({
        model: 'gemini-2.5-flash-image',
        contents: {
          parts: [
            { inlineData: { data: base64Image.split(',')[1], mimeType: 'image/png' } },
            { text: instruction }
          ]
        }
      });

      for (const part of response.candidates[0].content.parts) {
        if (part.inlineData) {
          return `data:image/png;base64,${part.inlineData.data}`;
        }
      }
      return null;
    } catch (error) {
      console.error("Image editing failed", error);
      return null;
    }
  }

  async generateCaptions(theme: string, category: string) {
    try {
      const response = await this.ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Generate 5 catchy marketing captions for a ${category} project with theme: ${theme}. Format as JSON array of strings.`,
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.ARRAY,
            items: { type: Type.STRING }
          }
        }
      });
      return JSON.parse(response.text);
    } catch (error) {
      return ["Unlock your creativity", "Professional designs in seconds", "The future of content"];
    }
  }
}

import React, { useState, useEffect } from 'react';
import { HashRouter, Routes, Route, Navigate } from 'react-router-dom';
import Sidebar from './components/Sidebar';
import Header from './components/Header';
import Dashboard from './components/Dashboard';
import VideoEditor from './components/VideoEditor';
import PhotoEditor from './components/PhotoEditor';
import PaintStudio from './components/PaintStudio';
import AdBuilder from './components/AdBuilder';
import TemplatesGallery from './components/TemplatesGallery';
import AudiobookStudio from './components/AudiobookStudio';
import AdminPanel from './components/AdminPanel';
import UserProfilePage from './components/UserProfilePage';
import CloudStorage from './components/CloudStorage';
import { StudioMode, Project, UserProfile } from './types';

const App: React.FC = () => {
  const [activeMode, setActiveMode] = useState<StudioMode>(StudioMode.VIDEO);
  const [projects, setProjects] = useState<Project[]>([]);
  const [isSidebarOpen, setIsSidebarOpen] = useState(true);
  const [user, setUser] = useState<UserProfile>({
    name: 'Alex Rivera',
    role: 'Lead Creative',
    avatar: 'https://picsum.photos/seed/user/100/100',
    email: 'alex.rivera@lumina.studio',
    plan: 'Pro'
  });

  useEffect(() => {
    const saved = localStorage.getItem('lumina_projects');
    if (saved) {
      setProjects(JSON.parse(saved));
    }
  }, []);

  const saveProject = (project: Project) => {
    const updated = [project, ...projects.filter(p => p.id !== project.id)];
    setProjects(updated);
    localStorage.setItem('lumina_projects', JSON.stringify(updated));
  };

  return (
    <HashRouter>
      <div className="flex h-screen bg-slate-950 text-slate-100 overflow-hidden">
        <Sidebar 
          isOpen={isSidebarOpen} 
          toggle={() => setIsSidebarOpen(!isSidebarOpen)} 
          activeMode={activeMode}
          setActiveMode={setActiveMode}
        />

        <div className="flex-1 flex flex-col min-w-0 h-full relative">
          <Header user={user} />
          <main className="flex-1 overflow-auto relative p-4 md:p-6">
            <Routes>
              <Route path="/" element={<Dashboard projects={projects} setActiveMode={setActiveMode} />} />
              <Route path="/video" element={<VideoEditor onSave={saveProject} />} />
              <Route path="/photo" element={<PhotoEditor onSave={saveProject} />} />
              <Route path="/paint" element={<PaintStudio onSave={saveProject} />} />
              <Route path="/ads" element={<AdBuilder onSave={saveProject} />} />
              <Route path="/audiobook" element={<AudiobookStudio onSave={saveProject} />} />
              <Route path="/templates" element={<TemplatesGallery />} />
              <Route path="/admin" element={<AdminPanel />} />
              <Route path="/profile" element={<UserProfilePage user={user} setUser={setUser} />} />
              <Route path="/storage" element={<CloudStorage projects={projects} />} />
              <Route path="*" element={<Navigate to="/" replace />} />
            </Routes>
          </main>
        </div>
      </div>
    </HashRouter>
  );
};

export default App;

