import React, { useState } from 'react';
import { BookOpen, Wand2, Play, Save, Download, Music, Mic2, Pause, Volume2, Share2 } from 'lucide-react';
import { GeminiService } from '../services/geminiService';
import { Project, StudioMode } from '../types';

interface AudiobookStudioProps {
  onSave: (project: Project) => void;
}

const AudiobookStudio: React.FC<AudiobookStudioProps> = ({ onSave }) => {
  const [text, setText] = useState('');
  const [voice, setVoice] = useState('Zephyr');
  const [isGenerating, setIsGenerating] = useState(false);
  const [audioUrl, setAudioUrl] = useState<string | null>(null);
  const [isPlaying, setIsPlaying] = useState(false);

  const voices = [
    { name: 'Zephyr', gender: 'Male', tone: 'Helpful' },
    { name: 'Puck', gender: 'Male', tone: 'Cheerful' },
    { name: 'Kore', gender: 'Female', tone: 'Professional' },
    { name: 'Charon', gender: 'Male', tone: 'Deep' },
    { name: 'Fenrir', gender: 'Male', tone: 'Storyteller' }
  ];

  const handleGenerate = async () => {
    if (!text) return;
    setIsGenerating(true);
    const gemini = GeminiService.getInstance();
    const result = await gemini.generateSpeech(text, voice);
    if (result) {
      setAudioUrl(result);
    }
    setIsGenerating(false);
  };

  const handleSave = () => {
    onSave({
      id: Date.now().toString(),
      name: "Audiobook: " + text.slice(0, 20) + "...",
      type: StudioMode.AUDIOBOOK,
      thumbnail: 'https://images.unsplash.com/photo-1485276587751-282e145450c7?auto=format&fit=crop&q=80&w=300&h=200',
      updatedAt: Date.now(),
      status: 'draft',
      data: { text, voice }
    });
  };

  return (
    <div className="h-full flex flex-col space-y-6 animate-in fade-in duration-700 max-w-6xl mx-auto">
      <div className="flex flex-col md:flex-row md:items-end justify-between gap-4">
        <div>
          <h2 className="text-2xl font-bold flex items-center">
            <BookOpen className="w-6 h-6 mr-3 text-emerald-500" />
            Audiobook Studio
          </h2>
          <p className="text-slate-400 mt-1">Transform text into professional narration with Gemini AI.</p>
        </div>
        <div className="flex items-center space-x-3">
          <button className="p-2.5 bg-slate-800 hover:bg-slate-700 rounded-xl text-slate-400"><Share2 className="w-5 h-5" /></button>
          <button onClick={handleSave} className="flex items-center px-6 py-2.5 bg-blue-600 hover:bg-blue-500 text-white rounded-xl font-bold shadow-lg shadow-blue-600/20">
            <Save className="w-4 h-4 mr-2" /> Save Project
          </button>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-8 flex-1">
        <div className="lg:col-span-8 flex flex-col space-y-6">
          <div className="bg-slate-900 border border-slate-800 rounded-3xl p-6 flex-1 flex flex-col">
            <div className="flex items-center justify-between mb-4">
              <span className="text-[10px] font-bold text-slate-500 uppercase tracking-widest">Script Content</span>
              <span className="text-[10px] font-mono text-slate-600">{text.length} characters</span>
            </div>
            <textarea 
              value={text}
              onChange={(e) => setText(e.target.value)}
              placeholder="Paste your story or script here... Gemini will bring it to life with professional voice acting."
              className="flex-1 bg-transparent border-none resize-none focus:outline-none text-slate-200 text-lg leading-relaxed placeholder:text-slate-700 font-serif"
            />
          </div>

          {audioUrl && (
            <div className="bg-gradient-to-r from-emerald-600/20 to-blue-600/20 border border-emerald-500/20 rounded-3xl p-6 flex items-center justify-between">
              <div className="flex items-center space-x-6 flex-1">
                <button 
                  onClick={() => setIsPlaying(!isPlaying)}
                  className="w-14 h-14 bg-emerald-500 text-slate-950 rounded-full flex items-center justify-center hover:scale-105 transition-all shadow-xl shadow-emerald-500/30"
                >
                  {isPlaying ? <Pause className="w-7 h-7 fill-current" /> : <Play className="w-7 h-7 fill-current ml-1" />}
                </button>
                <div className="flex-1">
                  <div className="h-1 w-full bg-slate-800 rounded-full overflow-hidden relative">
                    <div className="absolute inset-y-0 left-0 bg-emerald-500 w-1/3" />
                  </div>
                  <div className="flex justify-between mt-2">
                    <span className="text-[10px] font-mono text-slate-500 uppercase">00:42 / 02:15</span>
                    <span className="text-[10px] font-mono text-emerald-400 uppercase tracking-widest">Mastering Active</span>
                  </div>
                </div>
              </div>
              <button className="ml-8 p-3 bg-slate-900 border border-slate-800 rounded-2xl hover:bg-slate-800 text-slate-300">
                <Download className="w-5 h-5" />
              </button>
            </div>
          )}
        </div>

        <div className="lg:col-span-4 space-y-6">
          <div className="bg-slate-900 border border-slate-800 rounded-3xl p-6">
            <h3 className="text-xs font-bold text-slate-500 uppercase tracking-widest mb-6">Voice Selection</h3>
            <div className="space-y-2">
              {voices.map(v => (
                <button 
                  key={v.name}
                  onClick={() => setVoice(v.name)}
                  className={`w-full flex items-center justify-between p-3.5 rounded-2xl transition-all border ${
                    voice === v.name ? 'bg-blue-600/10 border-blue-500/50' : 'bg-slate-800/50 border-transparent hover:border-slate-700'
                  }`}
                >
                  <div className="flex items-center">
                    <div className={`p-2 rounded-lg mr-3 ${voice === v.name ? 'bg-blue-500 text-white' : 'bg-slate-800 text-slate-500'}`}>
                      <Mic2 className="w-4 h-4" />
                    </div>
                    <div className="text-left">
                      <p className="text-sm font-bold">{v.name}</p>
                      <p className="text-[10px] text-slate-500">{v.tone} Tone</p>
                    </div>
                  </div>
                  <Volume2 className={`w-4 h-4 ${voice === v.name ? 'text-blue-400' : 'text-slate-700'}`} />
                </button>
              ))}
            </div>
          </div>

          <div className="bg-slate-900 border border-slate-800 rounded-3xl p-6">
            <h3 className="text-xs font-bold text-slate-500 uppercase tracking-widest mb-6">Environment</h3>
            <div className="grid grid-cols-2 gap-3">
              <button className="p-4 bg-slate-800/50 rounded-2xl flex flex-col items-center border border-slate-700 hover:border-blue-500 transition-all">
                <Music className="w-5 h-5 mb-2 text-rose-400" />
                <span className="text-[10px] font-bold">Ambient BGM</span>
              </button>
              <button className="p-4 bg-slate-800/50 rounded-2xl flex flex-col items-center border border-slate-700 hover:border-blue-500 transition-all">
                <Wand2 className="w-5 h-5 mb-2 text-amber-400" />
                <span className="text-[10px] font-bold">Auto-Master</span>
              </button>
            </div>
          </div>

          <button 
            onClick={handleGenerate}
            disabled={isGenerating || !text}
            className="w-full py-5 bg-emerald-500 text-slate-950 font-black uppercase tracking-widest rounded-3xl shadow-2xl shadow-emerald-500/20 hover:scale-[1.02] active:scale-95 transition-all disabled:opacity-50 flex items-center justify-center"
          >
            {isGenerating ? (
              <span className="flex items-center">
                <Wand2 className="w-5 h-5 animate-spin mr-3" /> Processing script...
              </span>
            ) : "Generate Audio Master"}
          </button>
        </div>
      </div>
    </div>
  );
};

export default AudiobookStudio;

import React, { useState, useRef } from 'react';
import { BookOpen, Wand2, Play, Save, Download, Music, Mic2, Pause, Volume2, Share2, Plus, Trash2, Upload, CheckCircle } from 'lucide-react';
import { GeminiService } from '../services/geminiService';
import { Project, StudioMode } from '../types';

interface AudiobookStudioProps {
  onSave: (project: Project) => void;
}

interface Chapter {
  id: string;
  title: string;
  content: string;
  audioUrl: string | null;
  isAiGenerated: boolean;
}

const AudiobookStudio: React.FC<AudiobookStudioProps> = ({ onSave }) => {
  const [chapters, setChapters] = useState<Chapter[]>([
    { id: '1', title: 'Chapter 1: The Beginning', content: '', audioUrl: null, isAiGenerated: true }
  ]);
  const [activeChapterIndex, setActiveChapterIndex] = useState(0);
  const [voice, setVoice] = useState('Zephyr');
  const [isGenerating, setIsGenerating] = useState(false);
  const [isPlaying, setIsPlaying] = useState(false);
  const [showSavedToast, setShowSavedToast] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const voices = [
    { name: 'Zephyr', gender: 'Male', tone: 'Helpful' },
    { name: 'Puck', gender: 'Male', tone: 'Cheerful' },
    { name: 'Kore', gender: 'Female', tone: 'Professional' },
    { name: 'Charon', gender: 'Male', tone: 'Deep' },
    { name: 'Fenrir', gender: 'Male', tone: 'Storyteller' }
  ];

  const activeChapter = chapters[activeChapterIndex];

  const handleGenerate = async () => {
    if (!activeChapter.content) return;
    setIsGenerating(true);
    const gemini = GeminiService.getInstance();
    const result = await gemini.generateSpeech(activeChapter.content, voice);
    if (result) {
      const updatedChapters = [...chapters];
      updatedChapters[activeChapterIndex].audioUrl = result;
      updatedChapters[activeChapterIndex].isAiGenerated = true;
      setChapters(updatedChapters);
    }
    setIsGenerating(false);
  };

  const handleManualUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const url = URL.createObjectURL(file);
      const updatedChapters = [...chapters];
      updatedChapters[activeChapterIndex].audioUrl = url;
      updatedChapters[activeChapterIndex].isAiGenerated = false;
      setChapters(updatedChapters);
    }
  };

  const addChapter = () => {
    const newChapter: Chapter = {
      id: Date.now().toString(),
      title: `Chapter ${chapters.length + 1}: Untitled`,
      content: '',
      audioUrl: null,
      isAiGenerated: true
    };
    setChapters([...chapters, newChapter]);
    setActiveChapterIndex(chapters.length);
  };

  const updateChapterTitle = (title: string) => {
    const updated = [...chapters];
    updated[activeChapterIndex].title = title;
    setChapters(updated);
  };

  const updateChapterContent = (content: string) => {
    const updated = [...chapters];
    updated[activeChapterIndex].content = content;
    setChapters(updated);
  };

  const deleteChapter = (index: number) => {
    if (chapters.length === 1) return;
    const updated = chapters.filter((_, i) => i !== index);
    setChapters(updated);
    setActiveChapterIndex(Math.max(0, activeChapterIndex - 1));
  };

  const handleSave = () => {
    onSave({
      id: Date.now().toString(),
      name: "Audiobook: " + chapters[0].title,
      type: StudioMode.AUDIOBOOK,
      thumbnail: 'https://images.unsplash.com/photo-1485276587751-282e145450c7?auto=format&fit=crop&q=80&w=300&h=200',
      updatedAt: Date.now(),
      status: 'draft',
      data: { chapters, voice }
    });
    setShowSavedToast(true);
    setTimeout(() => setShowSavedToast(false), 3000);
  };

  const handleExport = () => {
    // Simulate export
    const link = document.createElement('a');
    link.href = '#';
    link.setAttribute('download', 'audiobook_project.zip');
    document.body.appendChild(link);
    alert('Exporting project as high-quality studio bundle...');
    document.body.removeChild(link);
  };

  return (
    <div className="h-full flex flex-col space-y-6 animate-in fade-in duration-700 max-w-7xl mx-auto pb-10">
      <input type="file" ref={fileInputRef} onChange={handleManualUpload} accept="audio/*" className="hidden" />

      {showSavedToast && (
        <div className="fixed top-20 right-10 bg-emerald-500 text-white px-6 py-3 rounded-2xl shadow-2xl z-[100] flex items-center animate-in slide-in-from-right duration-300">
          <CheckCircle className="w-5 h-5 mr-3" />
          <span className="font-bold uppercase tracking-widest text-xs">Project Saved to Cloud</span>
        </div>
      )}

      <div className="flex flex-col md:flex-row md:items-end justify-between gap-4">
        <div>
          <h2 className="text-2xl font-black tracking-tight flex items-center">
            <BookOpen className="w-7 h-7 mr-3 text-emerald-500" />
            LUMINA AUDIOBOOK PRO
          </h2>
          <p className="text-slate-400 mt-1 font-medium">Combine AI narration with manual audio production.</p>
        </div>
        <div className="flex items-center space-x-3">
          <button onClick={handleExport} className="flex items-center px-4 py-2 bg-slate-800 hover:bg-slate-700 rounded-xl text-slate-100 text-xs font-bold uppercase tracking-widest transition-all">
            <Download className="w-4 h-4 mr-2" /> Export Bundle
          </button>
          <button onClick={handleSave} className="flex items-center px-6 py-2.5 bg-blue-600 hover:bg-blue-500 text-white rounded-xl font-bold shadow-lg shadow-blue-600/20 uppercase text-xs tracking-widest">
            <Save className="w-4 h-4 mr-2" /> Save Project
          </button>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-6 flex-1 min-h-0">
        <div className="lg:col-span-3 flex flex-col space-y-4">
          <div className="bg-slate-900 border border-slate-800 rounded-3xl p-5 flex flex-col flex-1 overflow-hidden">
            <div className="flex items-center justify-between mb-4">
              <h3 className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Chapters</h3>
              <button onClick={addChapter} className="p-1.5 bg-blue-600 rounded-lg text-white hover:bg-blue-500 transition-all">
                <Plus className="w-4 h-4" />
              </button>
            </div>
            <div className="flex-1 overflow-y-auto space-y-2 pr-2">
              {chapters.map((ch, idx) => (
                <div 
                  key={ch.id} 
                  onClick={() => setActiveChapterIndex(idx)}
                  className={`group flex items-center justify-between p-3 rounded-2xl cursor-pointer border transition-all ${
                    activeChapterIndex === idx ? 'bg-blue-600/20 border-blue-500/50' : 'bg-slate-800/40 border-transparent hover:border-slate-700'
                  }`}
                >
                  <div className="flex items-center space-x-3 min-w-0">
                    <div className={`w-2 h-2 rounded-full ${ch.audioUrl ? 'bg-emerald-500' : 'bg-slate-600'}`} />
                    <p className={`text-xs font-bold truncate ${activeChapterIndex === idx ? 'text-blue-400' : 'text-slate-400'}`}>
                      {ch.title}
                    </p>
                  </div>
                  <button 
                    onClick={(e) => { e.stopPropagation(); deleteChapter(idx); }}
                    className="opacity-0 group-hover:opacity-100 p-1 hover:text-rose-500 transition-all"
                  >
                    <Trash2 className="w-3.5 h-3.5" />
                  </button>
                </div>
              ))}
            </div>
          </div>
        </div>

        <div className="lg:col-span-6 flex flex-col space-y-6 min-h-0">
          <div className="bg-slate-900 border border-slate-800 rounded-3xl p-6 flex-1 flex flex-col shadow-xl">
            <input 
              value={activeChapter.title}
              onChange={(e) => updateChapterTitle(e.target.value)}
              className="bg-transparent border-b border-slate-800 pb-3 mb-6 text-xl font-black focus:outline-none focus:border-blue-500 transition-all text-slate-100"
              placeholder="Chapter Title..."
            />
            <textarea 
              value={activeChapter.content}
              onChange={(e) => updateChapterContent(e.target.value)}
              placeholder="Start writing the narration script here..."
              className="flex-1 bg-transparent border-none resize-none focus:outline-none text-slate-300 text-lg leading-relaxed placeholder:text-slate-700 font-serif"
            />
          </div>

          <div className="bg-slate-900 border border-slate-800 rounded-3xl p-6 shadow-2xl">
            <div className="flex items-center justify-between mb-6">
               <h3 className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Production Console</h3>
               <div className="flex space-x-2">
                 <button 
                  onClick={() => fileInputRef.current?.click()}
                  className="flex items-center px-4 py-2 bg-slate-800 hover:bg-slate-700 rounded-xl text-[10px] font-black uppercase tracking-widest border border-slate-700 transition-all"
                 >
                   <Upload className="w-3.5 h-3.5 mr-2 text-blue-400" /> Manual Upload
                 </button>
               </div>
            </div>

            {activeChapter.audioUrl ? (
              <div className="bg-slate-950/50 border border-emerald-500/20 rounded-2xl p-5 flex items-center justify-between animate-in slide-in-from-bottom-2">
                <div className="flex items-center space-x-4 flex-1">
                  <button 
                    onClick={() => setIsPlaying(!isPlaying)}
                    className="w-12 h-12 bg-emerald-500 text-slate-950 rounded-xl flex items-center justify-center hover:scale-105 transition-all shadow-lg"
                  >
                    {isPlaying ? <Pause className="w-6 h-6 fill-current" /> : <Play className="w-6 h-6 fill-current ml-1" />}
                  </button>
                  <div className="flex-1">
                    <p className="text-[10px] font-black text-emerald-400 uppercase tracking-widest mb-2 flex items-center">
                      {activeChapter.isAiGenerated ? <Wand2 className="w-3 h-3 mr-1" /> : <Mic2 className="w-3 h-3 mr-1" />}
                      {activeChapter.isAiGenerated ? 'AI Generated Master' : 'Manual Audio Clip'}
                    </p>
                    <div className="h-1.5 w-full bg-slate-800 rounded-full overflow-hidden">
                      <div className="bg-emerald-500 h-full w-1/4" />
                    </div>
                  </div>
                </div>
                <button 
                  onClick={() => {
                    const updated = [...chapters];
                    updated[activeChapterIndex].audioUrl = null;
                    setChapters(updated);
                  }}
                  className="ml-6 p-2 text-slate-600 hover:text-rose-500 transition-colors"
                >
                  <Trash2 className="w-5 h-5" />
                </button>
              </div>
            ) : (
              <div className="py-8 flex flex-col items-center justify-center border-2 border-dashed border-slate-800 rounded-2xl bg-slate-950/20">
                <Music className="w-10 h-10 text-slate-700 mb-4" />
                <p className="text-slate-500 font-bold text-sm">No audio generated for this chapter</p>
                <p className="text-[10px] text-slate-600 mt-1 uppercase tracking-widest">Select an AI voice or upload manually</p>
              </div>
            )}
          </div>
        </div>

        <div className="lg:col-span-3 space-y-6">
          <div className="bg-slate-900 border border-slate-800 rounded-3xl p-6">
            <h3 className="text-[10px] font-black text-slate-500 uppercase tracking-widest mb-6">Voice Persona</h3>
            <div className="space-y-2 max-h-64 overflow-y-auto pr-2 scrollbar-hide">
              {voices.map(v => (
                <button 
                  key={v.name}
                  onClick={() => setVoice(v.name)}
                  className={`w-full flex items-center justify-between p-3 rounded-2xl transition-all border ${
                    voice === v.name ? 'bg-blue-600/10 border-blue-500/50' : 'bg-slate-800/30 border-transparent hover:border-slate-700'
                  }`}
                >
                  <div className="flex items-center min-w-0">
                    <div className={`p-2 rounded-lg mr-3 ${voice === v.name ? 'bg-blue-500 text-white' : 'bg-slate-800 text-slate-500'}`}>
                      <Volume2 className="w-3.5 h-3.5" />
                    </div>
                    <div className="text-left min-w-0">
                      <p className="text-xs font-black truncate">{v.name}</p>
                      <p className="text-[9px] text-slate-600 uppercase tracking-tighter">{v.gender} • {v.tone}</p>
                    </div>
                  </div>
                </button>
              ))}
            </div>
          </div>

          <div className="bg-slate-900 border border-slate-800 rounded-3xl p-6">
            <h3 className="text-[10px] font-black text-slate-500 uppercase tracking-widest mb-6">Enhancements</h3>
            <div className="space-y-3">
              <button className="w-full flex items-center p-3 bg-slate-800/40 border border-slate-700 rounded-xl hover:border-blue-500 transition-all group">
                <Music className="w-4 h-4 mr-3 text-rose-400" />
                <span className="text-xs font-bold text-slate-400 group-hover:text-slate-200">Ambient Soundtrack</span>
              </button>
              <button className="w-full flex items-center p-3 bg-slate-800/40 border border-slate-700 rounded-xl hover:border-blue-500 transition-all group">
                <Wand2 className="w-4 h-4 mr-3 text-amber-400" />
                <span className="text-xs font-bold text-slate-400 group-hover:text-slate-200">Noise Removal</span>
              </button>
            </div>
          </div>

          <button 
            onClick={handleGenerate}
            disabled={isGenerating || !activeChapter.content}
            className="w-full py-5 bg-gradient-to-r from-emerald-500 to-emerald-600 text-slate-950 font-black uppercase tracking-widest rounded-3xl shadow-2xl shadow-emerald-500/30 hover:scale-[1.02] active:scale-95 transition-all disabled:opacity-50 flex items-center justify-center text-xs"
          >
            {isGenerating ? (
              <span className="flex items-center">
                <Wand2 className="w-5 h-5 animate-spin mr-3" /> Processing...
              </span>
            ) : (
              <span className="flex items-center">
                <Sparkles className="w-5 h-5 mr-3" /> Generate Narration
              </span>
            )}
          </button>
        </div>
      </div>
    </div>
  );
