interface PaintStudioProps {
  onSave: (project: Project) => void;
}

const PaintStudio: React.FC<PaintStudioProps> = ({ onSave }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [tool, setTool] = useState<'brush' | 'eraser' | 'shape'>('brush');
  const [color, setColor] = useState('#3b82f6');
  const [isDrawing, setIsDrawing] = useState(false);
  const [isGenerating, setIsGenerating] = useState(false);
  const [prompt, setPrompt] = useState("");
  const [showSavedToast, setShowSavedToast] = useState(false);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (canvas) {
      const ctx = canvas.getContext('2d');
      if (ctx) {
        ctx.lineJoin = 'round';
        ctx.lineCap = 'round';
        ctx.lineWidth = 5;
        // Initial background
        ctx.fillStyle = '#0f172a';
        ctx.fillRect(0, 0, canvas.width, canvas.height);
      }
    }
  }, []);

  const startDrawing = (e: React.MouseEvent) => {
    setIsDrawing(true);
    draw(e);
  };

  const draw = (e: React.MouseEvent) => {
    if (!isDrawing) return;
    const canvas = canvasRef.current;
    const ctx = canvas?.getContext('2d');
    if (!canvas || !ctx) return;

    const rect = canvas.getBoundingClientRect();
    const scaleX = canvas.width / rect.width;
    const scaleY = canvas.height / rect.height;
    const x = (e.clientX - rect.left) * scaleX;
    const y = (e.clientY - rect.top) * scaleY;

    ctx.strokeStyle = tool === 'eraser' ? '#0f172a' : color;
    ctx.lineTo(x, y);
    ctx.stroke();
    ctx.beginPath();
    ctx.moveTo(x, y);
  };

  const endDrawing = () => {
    setIsDrawing(false);
    const canvas = canvasRef.current;
    canvas?.getContext('2d')?.beginPath();
  };

  const handleCharacterGenerate = async () => {
    if (!prompt) return;
    setIsGenerating(true);
    const gemini = GeminiService.getInstance();
    const result = await gemini.generateImage(`Animation character design for: ${prompt}. Concept art sheet, high resolution, expressive.`, "1:1");
    if (result) {
      const canvas = canvasRef.current;
      const ctx = canvas?.getContext('2d');
      const img = new Image();
      img.crossOrigin = "anonymous";
      img.onload = () => {
        ctx?.clearRect(0, 0, canvas?.width || 800, canvas?.height || 600);
        ctx?.drawImage(img, 0, 0, canvas?.width || 800, canvas?.height || 600);
      };
      img.src = result;
    }
    setIsGenerating(false);
  };

  const handleSave = () => {
    const canvas = canvasRef.current;
    if (canvas) {
      onSave({
        id: Date.now().toString(),
        name: "Character: " + (prompt || "Art Session"),
        type: StudioMode.PAINT,
        thumbnail: canvas.toDataURL(),
        updatedAt: Date.now(),
        status: 'draft',
        data: {}
      });
      setShowSavedToast(true);
      setTimeout(() => setShowSavedToast(false), 3000);
    }
  };

  const handleExport = () => {
    const canvas = canvasRef.current;
    if (canvas) {
      const link = document.createElement('a');
      link.href = canvas.toDataURL('image/png');
      link.setAttribute('download', 'lumina_character.png');
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
    }
  };

  return (
    <div className="h-full flex flex-col space-y-4 animate-in fade-in duration-500 max-w-7xl mx-auto">
      {showSavedToast && (
        <div className="fixed top-20 right-10 bg-emerald-500 text-white px-6 py-3 rounded-2xl shadow-2xl z-[100] flex items-center animate-in slide-in-from-right duration-300">
          <CheckCircle className="w-5 h-5 mr-3" />
          <span className="font-bold uppercase tracking-widest text-xs">Artwork Saved</span>
        </div>
      )}

      <div className="flex items-center justify-between mb-2">
        <div>
          <h2 className="text-2xl font-black uppercase tracking-tight flex items-center">
            <Paintbrush className="w-6 h-6 mr-3 text-emerald-500" />
            Character Paint Studio
          </h2>
        </div>
        <div className="flex space-x-2">
           <button onClick={() => {
             const ctx = canvasRef.current?.getContext('2d');
             if (ctx) {
               ctx.fillStyle = '#0f172a';
               ctx.fillRect(0, 0, canvasRef.current!.width, canvasRef.current!.height);
             }
           }} className="flex items-center px-4 py-2 bg-slate-800 hover:bg-slate-700 rounded-xl text-xs font-bold uppercase tracking-widest transition-all">
             <Undo className="w-4 h-4 mr-2" /> Reset
           </button>
           <button onClick={handleExport} className="flex items-center px-4 py-2 bg-slate-800 hover:bg-slate-700 rounded-xl text-xs font-bold uppercase tracking-widest transition-all">
             <Download className="w-4 h-4 mr-2" /> Export
           </button>
           <button onClick={handleSave} className="flex items-center px-6 py-2.5 bg-blue-600 hover:bg-blue-500 rounded-xl text-xs font-black uppercase tracking-widest shadow-xl shadow-blue-600/20 transition-all">
             <Save className="w-4 h-4 mr-2" /> Save
           </button>
        </div>
      </div>

      <div className="flex-1 flex flex-col lg:flex-row space-y-4 lg:space-y-0 lg:space-x-6 min-h-0">
         <div className="w-full lg:w-20 bg-slate-900 border border-slate-800 rounded-[2rem] p-4 flex flex-row lg:flex-col items-center justify-center space-x-4 lg:space-x-0 lg:space-y-6 shadow-xl">
            <button onClick={() => setTool('brush')} className={`p-4 rounded-2xl transition-all shadow-lg ${tool === 'brush' ? 'bg-blue-600 text-white scale-110' : 'bg-slate-800 text-slate-400 hover:bg-slate-700'}`}>
              <Paintbrush className="w-6 h-6" />
            </button>
            <button onClick={() => setTool('eraser')} className={`p-4 rounded-2xl transition-all shadow-lg ${tool === 'eraser' ? 'bg-blue-600 text-white scale-110' : 'bg-slate-800 text-slate-400 hover:bg-slate-700'}`}>
              <Eraser className="w-6 h-6" />
            </button>
            <button className="p-4 bg-slate-800 rounded-2xl transition-all text-slate-400 hover:bg-slate-700 shadow-lg">
              <Square className="w-6 h-6" />
            </button>
            <button className="p-4 bg-slate-800 rounded-2xl transition-all text-slate-400 hover:bg-slate-700 shadow-lg">
              <Circle className="w-6 h-6" />
            </button>

            <div className="hidden lg:block pt-6 border-t border-slate-800 w-full flex flex-col items-center space-y-4">
              {['#3b82f6', '#10b981', '#f59e0b', '#ef4444', '#8b5cf6', '#ffffff'].map(c => (
                <button 
                  key={c}
                  onClick={() => setColor(c)}
                  className={`w-8 h-8 rounded-full border-4 shadow-xl transition-all hover:scale-125 ${color === c ? 'border-white scale-110 ring-4 ring-white/10' : 'border-transparent'}`}
                  style={{ backgroundColor: c }}
                />
              ))}
            </div>
         </div>

         <div className="flex-1 bg-slate-900 rounded-[3rem] border border-slate-800 p-10 flex flex-col shadow-2xl relative overflow-hidden">
            <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-blue-500 via-emerald-500 to-purple-500 opacity-50" />

            <div className="flex-1 bg-[#0a0f1d] rounded-[2rem] shadow-inner border border-white/5 overflow-hidden relative group cursor-crosshair">
               <canvas 
                ref={canvasRef}
                width={1600}
                height={1200}
                onMouseDown={startDrawing}
                onMouseMove={draw}
                onMouseUp={endDrawing}
                onMouseLeave={endDrawing}
                className="w-full h-full object-contain"
               />
               <div className="absolute top-6 right-6 flex space-x-3 opacity-0 group-hover:opacity-100 transition-all">
                  <button className="p-3 bg-slate-900/80 backdrop-blur-xl rounded-2xl text-slate-300 hover:text-white border border-white/10 shadow-2xl hover:scale-105 active:scale-95"><Video className="w-5 h-5" /></button>
               </div>
            </div>

            <div className="mt-8 flex space-x-4">
              <div className="flex-1 relative">
                <input 
                  value={prompt}
                  onChange={(e) => setPrompt(e.target.value)}
                  placeholder="Dream your character: 'A futuristic neon samurai cat with dual katanas'..." 
                  className="w-full bg-slate-800 border border-slate-700 rounded-3xl py-4.5 pl-6 pr-16 focus:outline-none focus:ring-4 focus:ring-emerald-500/20 text-slate-100 font-medium transition-all"
                />
                <button 
                  onClick={handleCharacterGenerate}
                  disabled={isGenerating || !prompt}
                  className="absolute right-2.5 top-1/2 -translate-y-1/2 p-3.5 bg-emerald-600 rounded-2xl text-white disabled:opacity-50 shadow-xl shadow-emerald-600/30 hover:scale-105 active:scale-95 transition-all"
                >
                  {isGenerating ? <SparklesIcon className="w-5 h-5 animate-spin" /> : <Wand2 className="w-5 h-5" />}
                </button>
              </div>
            </div>
         </div>
      </div>
    </div>
  );
};

