    { id: '1', name: 'Main Visual', type: 'video', start: 0, duration: 100, content: 'https://picsum.photos/seed/vid1/800/450' },
    { id: '2', name: 'BGM Track', type: 'audio', start: 0, duration: 80, content: 'bg-music' },
    { id: '3', name: 'Intro Text', type: 'text', start: 5, duration: 30, content: 'Summer Vlog 2024' },
  ]);
  const [isGenerating, setIsGenerating] = useState(false);
  const [showVfxPanel, setShowVfxPanel] = useState(false);
  const [aspectRatio, setAspectRatio] = useState<AspectRatio>('16:9');
  const [showSaveToast, setShowSaveToast] = useState(false);
  const audioInputRef = useRef<HTMLInputElement>(null);

  const totalDuration = 100;

  useEffect(() => {
    let interval: number;
    if (isPlaying) {
      interval = window.setInterval(() => {
        setCurrentTime(prev => {
          if (prev >= totalDuration) {
            setIsPlaying(false);
            return 0;
          }
          return prev + 1;
        });
      }, 100);
    }
    return () => clearInterval(interval);
  }, [isPlaying]);

  const handlePlayToggle = () => setIsPlaying(!isPlaying);

  const toggleLayerSelection = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    const newSelection = new Set(selectedLayerIds);
    if (newSelection.has(id)) {
      newSelection.delete(id);
    } else {
      newSelection.add(id);
    }
    setSelectedLayerIds(newSelection);
  };

  const handleSave = () => {
    onSave({
      id: Date.now().toString(),
      name: `Composition (${aspectRatio}) ${new Date().toLocaleTimeString()}`,
      type: StudioMode.VIDEO,
      thumbnail: layers.find(l => l.type === 'video')?.content || layers[0].content,
      updatedAt: Date.now(),
      status: 'draft',
      data: { layers, aspectRatio }
    });
    setShowSaveToast(true);
    setTimeout(() => setShowSaveToast(false), 3000);
  };

  const handleExport = () => {
    alert(`Exporting high-quality MP4 (${aspectRatio}) to cloud...`);
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const newLayer: TimelineLayer = {
        id: Date.now().toString(),
        name: file.name,
        type: file.type.startsWith('audio') ? 'audio' : 'video',
        start: currentTime,
        duration: 40,
        content: URL.createObjectURL(file)
      };
      setLayers([...layers, newLayer]);
    }
  };

  const applyVfx = (vfxType: string) => {
    const newLayer: TimelineLayer = {
      id: `vfx-${Date.now()}`,
      name: `${vfxType.charAt(0).toUpperCase() + vfxType.slice(1)} Effect`,
      type: 'vfx',
      vfxType: vfxType,
      start: currentTime,
      duration: 30,
      content: ''
    };
    setLayers([...layers, newLayer]);
    setShowVfxPanel(false);
  };

  const handleMergeAudio = () => {
    const selectedAudio = layers.filter(l => selectedLayerIds.has(l.id) && l.type === 'audio');
    if (selectedAudio.length < 2) return;

    const earliestStart = Math.min(...selectedAudio.map(a => a.start));
    const latestEnd = Math.max(...selectedAudio.map(a => a.start + a.duration));

    const mergedLayer: TimelineLayer = {
      id: `merged-${Date.now()}`,
      name: `Merged Audio (${selectedAudio.length} tracks)`,
      type: 'audio',
      start: earliestStart,
      duration: latestEnd - earliestStart,
      content: 'composite-audio-stream'
    };

    setLayers([
      ...layers.filter(l => !selectedLayerIds.has(l.id)),
      mergedLayer
    ]);
    setSelectedLayerIds(new Set());
  };

  const deleteSelected = () => {
    setLayers(layers.filter(l => !selectedLayerIds.has(l.id)));
    setSelectedLayerIds(new Set());
  };

  const activeVfx = layers
    .filter(l => l.type === 'vfx' && currentTime >= l.start && currentTime <= (l.start + l.duration))
    .map(l => l.vfxType);

  const getPreviewClasses = () => {
    switch(aspectRatio) {
      case '9:16': return 'aspect-[9/16] h-full max-w-full mx-auto';
      case '16:9': return 'aspect-video w-full max-h-full mx-auto';
      case '1:1': return 'aspect-square h-full max-w-full mx-auto';
      case '21:9': return 'aspect-[21/9] w-full max-h-full mx-auto';
      default: return 'aspect-video w-full';
    }
  };

  return (
    <div className="h-full flex flex-col space-y-4 animate-in fade-in duration-500 overflow-hidden relative">
      <input type="file" ref={audioInputRef} onChange={handleFileUpload} accept="audio/*,video/*" className="hidden" />

      {showSaveToast && (
        <div className="fixed top-20 right-10 bg-emerald-600 text-white px-8 py-4 rounded-2xl shadow-2xl z-[100] flex items-center animate-in slide-in-from-right duration-300">
          <CheckCircle className="w-5 h-5 mr-3" />
          <span className="font-bold uppercase tracking-widest text-xs">Project Synced to Cloud</span>
        </div>
      )}

      {showVfxPanel && (
        <div className="absolute inset-0 z-[60] bg-slate-950/70 backdrop-blur-md flex items-center justify-center p-4">
          <div className="bg-slate-900 border border-slate-800 rounded-[2.5rem] w-full max-w-xl p-10 shadow-2xl animate-in zoom-in-95 duration-200">
            <div className="flex justify-between items-center mb-10">
              <h3 className="text-2xl font-black flex items-center">
                <Zap className="w-6 h-6 mr-3 text-amber-400" />
                VFX Master Library
              </h3>
              <button onClick={() => setShowVfxPanel(false)} className="p-3 bg-slate-800 hover:bg-slate-700 rounded-2xl transition-all">
                <X className="w-6 h-6" />
              </button>
            </div>
            <div className="grid grid-cols-2 gap-6">
              {[
                { id: 'glitch', icon: '🌩️', label: 'Digital Glitch', desc: 'Fragmented pixel artifacts' },
                { id: 'bloom', icon: '✨', label: 'Neon Bloom', desc: 'Radiant glow on highlights' },
                { id: 'particles', icon: '❄️', label: 'Ember Dust', desc: 'Floating cinematic particles' },
                { id: 'cinematic', icon: '🎬', label: 'YouTube Grade', desc: 'Pro color correction' },
              ].map(vfx => (
                <button 
                  key={vfx.id}
                  onClick={() => applyVfx(vfx.id)}
                  className="p-8 bg-slate-800/50 hover:bg-slate-800 border border-slate-700 hover:border-amber-500/50 rounded-3xl text-left transition-all group"
                >
                  <span className="text-4xl mb-4 block group-hover:scale-110 transition-transform">{vfx.icon}</span>
                  <p className="font-black text-slate-100 uppercase tracking-widest text-sm">{vfx.label}</p>
                  <p className="text-xs text-slate-500 mt-2 font-medium">{vfx.desc}</p>
                </button>
              ))}
            </div>
          </div>
        </div>
      )}

      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 mb-2">
        <div className="flex items-center space-x-4">
          <h2 className="text-xl font-black flex items-center uppercase tracking-tight">
            <Video className="w-6 h-6 mr-3 text-rose-500" />
            Lumina Video Studio
          </h2>
          <div className="hidden lg:flex items-center bg-slate-900 border border-slate-800 rounded-2xl p-1">
            <button 
              onClick={() => setAspectRatio('16:9')}
              className={`p-2 rounded-xl transition-all ${aspectRatio === '16:9' ? 'bg-blue-600 text-white' : 'text-slate-500 hover:text-white'}`}
              title="YouTube Long (16:9)"
            >
              <Monitor className="w-4 h-4" />
            </button>
            <button 
              onClick={() => setAspectRatio('9:16')}
              className={`p-2 rounded-xl transition-all ${aspectRatio === '9:16' ? 'bg-blue-600 text-white' : 'text-slate-500 hover:text-white'}`}
              title="YouTube Shorts (9:16)"
            >
              <Smartphone className="w-4 h-4" />
            </button>
            <button 
              onClick={() => setAspectRatio('1:1')}
              className={`p-2 rounded-xl transition-all ${aspectRatio === '1:1' ? 'bg-blue-600 text-white' : 'text-slate-500 hover:text-white'}`}
              title="Social Square (1:1)"
            >
              <div className="w-4 h-4 border-2 border-current rounded-sm" />
            </button>
          </div>
        </div>
        <div className="flex flex-wrap items-center gap-3">
          <button onClick={() => setShowVfxPanel(true)} className="flex items-center px-5 py-2.5 bg-amber-500 hover:bg-amber-400 text-slate-950 rounded-2xl text-xs font-black uppercase tracking-widest shadow-xl shadow-amber-500/20 transition-all hover:scale-105 active:scale-95">
            <Zap className="w-4 h-4 mr-2" />
            VFX Engine
          </button>
          <button onClick={handleSave} className="flex items-center px-4 py-2.5 bg-slate-800 hover:bg-slate-700 rounded-2xl text-xs font-black uppercase tracking-widest transition-all border border-slate-700">
            <Save className="w-4 h-4 mr-2" />
            Save
          </button>
          <button onClick={handleExport} className="flex items-center px-6 py-2.5 bg-blue-600 hover:bg-blue-500 rounded-2xl text-xs font-black uppercase tracking-widest shadow-xl shadow-blue-600/20 transition-all">
            <Download className="w-4 h-4 mr-2" />
            Export MP4
          </button>
        </div>
      </div>

      <div className="flex-1 grid grid-cols-1 md:grid-cols-12 gap-6 min-h-0">
        <div className="md:col-span-9 flex flex-col min-h-0 bg-slate-900 rounded-[2.5rem] border border-slate-800 p-8 shadow-inner overflow-hidden">
          <div className="flex-1 bg-black rounded-[2rem] flex items-center justify-center relative overflow-hidden group shadow-2xl border border-white/5">
            <div className={`relative ${getPreviewClasses()} flex items-center justify-center transition-all duration-500 overflow-hidden`}>
              <img 
                src={layers.find(l => l.type === 'video')?.content || 'https://picsum.photos/seed/empty/800/450'} 
                alt="Preview" 
                className={`max-h-full max-w-full object-cover transition-all duration-500 shadow-2xl ${activeVfx.includes('bloom') ? 'brightness-125 saturate-150 blur-[0.5px]' : ''} ${activeVfx.includes('cinematic') ? 'sepia-[0.2] contrast-125 saturate-110' : ''}`}
              />

              {/* Real-time VFX Overlays */}
              {activeVfx.includes('glitch') && (
                <div className="absolute inset-0 pointer-events-none mix-blend-screen opacity-70">
                  <div className="absolute inset-0 bg-red-500/10 animate-pulse" />
                  <div className="absolute inset-0 bg-cyan-500/10 animate-pulse delay-75 translate-x-2" />
                  <div className="absolute h-[1px] w-full bg-white/30 top-1/4 animate-bounce" />
                  <div className="absolute h-[1px] w-full bg-white/30 top-3/4 animate-bounce delay-150" />
                </div>
              )}

              {activeVfx.includes('particles') && (
                <div className="absolute inset-0 pointer-events-none overflow-hidden">
                  {[...Array(25)].map((_, i) => (
                    <div 
                      key={i} 
                      className="absolute w-1.5 h-1.5 bg-white rounded-full animate-ping opacity-20 blur-[1px]"
                      style={{ 
                        top: `${Math.random() * 100}%`, 
                        left: `${Math.random() * 100}%`,
                        animationDuration: `${1.5 + Math.random() * 3}s`
                      }}
                    />
                  ))}
                </div>
              )}
            </div>

            <div className="absolute bottom-10 left-1/2 -translate-x-1/2 flex items-center space-x-10 bg-slate-950/80 backdrop-blur-2xl px-12 py-5 rounded-full border border-white/10 opacity-0 group-hover:opacity-100 transition-all shadow-2xl">
              <button className="text-slate-500 hover:text-white transition-all hover:scale-125"><SkipBack className="w-7 h-7" /></button>
              <button 
                onClick={handlePlayToggle}
                className="w-16 h-16 bg-white rounded-full flex items-center justify-center text-slate-950 hover:scale-110 active:scale-95 transition-all shadow-xl shadow-white/10"
              >
                {isPlaying ? <Pause className="w-8 h-8 fill-current" /> : <Play className="w-8 h-8 fill-current ml-1" />}
              </button>
              <button className="text-slate-500 hover:text-white transition-all hover:scale-125"><SkipForward className="w-7 h-7" /></button>
            </div>

            <div className="absolute top-6 left-6 flex items-center space-x-3">
              <div className="px-4 py-1.5 bg-red-600/20 backdrop-blur-md rounded-full border border-red-500/30 flex items-center">
                <Youtube className="w-3.5 h-3.5 mr-2 text-red-500" />
                <span className="text-[10px] font-black uppercase tracking-widest text-red-100">YouTube Workspace</span>
              </div>
            </div>
          </div>
        </div>

        <div className="md:col-span-3 bg-slate-900 rounded-[2.5rem] border border-slate-800 p-8 space-y-8 overflow-y-auto shadow-2xl">
          <h3 className="text-[10px] font-black text-slate-500 uppercase tracking-[0.2em]">Studio Deck</h3>
          <div className="grid grid-cols-2 gap-4">
            <button onClick={() => audioInputRef.current?.click()} className="p-5 bg-slate-800 hover:bg-slate-700 rounded-3xl flex flex-col items-center justify-center border border-slate-700 hover:border-blue-500/50 transition-all group">
              <Upload className="w-7 h-7 mb-3 text-blue-400 group-hover:scale-110 transition-transform" />
              <span className="text-[10px] font-black uppercase">Import</span>
            </button>
            <button onClick={() => setShowVfxPanel(true)} className="p-5 bg-slate-800 hover:bg-slate-700 rounded-3xl flex flex-col items-center justify-center border border-slate-700 hover:border-amber-500/50 transition-all group">
              <Zap className="w-7 h-7 mb-3 text-amber-400 group-hover:scale-110 transition-transform" />
              <span className="text-[10px] font-black uppercase">VFX</span>
            </button>
            <button className="p-5 bg-slate-800 hover:bg-slate-700 rounded-3xl flex flex-col items-center justify-center border border-slate-700 hover:border-indigo-500/50 transition-all group">
              <TypeIcon className="w-7 h-7 mb-3 text-indigo-400 group-hover:scale-110 transition-transform" />
              <span className="text-[10px] font-black uppercase">Titles</span>
            </button>
            <button className="p-5 bg-slate-800 hover:bg-slate-700 rounded-3xl flex flex-col items-center justify-center border border-slate-700 hover:border-emerald-500/50 transition-all group">
              <Music className="w-7 h-7 mb-3 text-emerald-400 group-hover:scale-110 transition-transform" />
              <span className="text-[10px] font-black uppercase">Audio</span>
            </button>
