                  <p className="text-xs font-bold text-blue-400">{aspectRatio === '16:9' ? 'YouTube Standard (16:9)' : aspectRatio === '9:16' ? 'YouTube Shorts (9:16)' : 'Custom'}</p>
               </div>
               <div>
                  <p className="text-[9px] font-black text-slate-600 uppercase mb-1">Active FX</p>
                  <div className="flex flex-wrap gap-1 mt-1">
                    {activeVfx.length > 0 ? activeVfx.map((v, i) => (
                      <span key={i} className="px-2 py-0.5 bg-amber-500/10 text-amber-500 text-[8px] font-black rounded uppercase border border-amber-500/20">{v}</span>
                    )) : <span className="text-[10px] text-slate-600 font-medium italic">Normal Output</span>}
                  </div>
               </div>
            </div>
          </div>
        </div>
      </div>

      <div className="h-64 bg-slate-900 rounded-[2.5rem] border border-slate-800 flex flex-col overflow-hidden shadow-2xl">
        <div className="px-8 py-4 border-b border-slate-800 flex items-center justify-between bg-slate-950/30">
          <div className="flex items-center space-x-10">
             <div className="flex items-center space-x-3">
                <div className="w-2.5 h-2.5 rounded-full bg-red-500 animate-pulse shadow-[0_0_8px_rgba(239,68,68,0.8)]" />
                <span className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em]">Master Timeline</span>
             </div>
             <div className="flex items-center space-x-6 text-slate-500">
                <button onClick={deleteSelected} className="hover:text-rose-500 transition-colors"><Trash2 className="w-5 h-5"/></button>
                <button onClick={handleMergeAudio} className="hover:text-blue-400 transition-colors"><Combine className="w-5 h-5"/></button>
                <button className="hover:text-white transition-colors"><Scissors className="w-5 h-5"/></button>
             </div>
          </div>
          <div className="text-xs font-mono text-blue-400 bg-blue-400/10 px-4 py-1.5 rounded-full border border-blue-400/20 font-black">
            00:{(currentTime/10).toFixed(0).padStart(2,'0')}:00
          </div>
        </div>

        <div className="flex-1 overflow-x-auto p-8 scrollbar-hide">
          <div className="h-full w-[2500px] space-y-2 relative">
             <div className="flex space-x-40 border-b border-slate-800/50 mb-6 h-6 select-none opacity-40">
                {[...Array(15)].map((_, i) => (
                  <div key={i} className="text-[10px] text-slate-500 font-mono">{i}0s</div>
                ))}
             </div>

             <div className="space-y-1">
               {layers.map((layer) => (
                 <div key={layer.id} className="flex items-center space-x-4 h-10 group">
                    <div className="w-40 flex items-center space-x-3 shrink-0">
                      <div className={`w-8 h-8 rounded-xl flex items-center justify-center ${
                        layer.type === 'video' ? 'bg-rose-500/10 text-rose-500' : 
                        layer.type === 'audio' ? 'bg-emerald-500/10 text-emerald-500' : 
                        layer.type === 'vfx' ? 'bg-amber-500/10 text-amber-500' : 'bg-indigo-500/10 text-indigo-500'
                      }`}>
                        {layer.type === 'video' ? <Video className="w-4 h-4" /> : 
                         layer.type === 'audio' ? <Music className="w-4 h-4" /> : 
                         layer.type === 'vfx' ? <Zap className="w-4 h-4" /> : <TypeIcon className="w-4 h-4" />}
                      </div>
                      <span className="text-[10px] text-slate-400 font-black truncate uppercase tracking-tighter">{layer.name}</span>
                    </div>

                    <div 
                      onClick={(e) => toggleLayerSelection(layer.id, e)}
                      className={`h-full rounded-2xl relative cursor-pointer border transition-all flex items-center px-5 shadow-inner ${
                        selectedLayerIds.has(layer.id) 
                          ? 'border-blue-500 ring-[6px] ring-blue-500/10 shadow-2xl brightness-110 z-10' 
                          : 'border-white/5 hover:border-white/10'
                      } ${
                        layer.type === 'video' ? 'bg-rose-600/20' : 
                        layer.type === 'audio' ? 'bg-emerald-600/20' : 
                        layer.type === 'vfx' ? 'bg-amber-600/20' : 'bg-indigo-600/20'
                      }`}
                      style={{ 
                        width: `${layer.duration * 8}px`,
                        marginLeft: `${layer.start * 8}px` 
                      }}
                    >
                      <div className={`text-[10px] font-black truncate uppercase tracking-widest ${
                        layer.type === 'video' ? 'text-rose-400' : 
                        layer.type === 'audio' ? 'text-emerald-400' : 
                        layer.type === 'vfx' ? 'text-amber-400' : 'text-indigo-400'
                      }`}>
                        {layer.name}
                      </div>
                      {layer.type === 'audio' && (
                        <div className="absolute right-4 flex items-center space-x-1 opacity-40">
                          <Music className="w-3 h-3" />
                        </div>
                      )}
                    </div>
                 </div>
               ))}
             </div>

             <div 
              className="absolute top-0 bottom-0 w-[3px] bg-blue-500 shadow-[0_0_25px_rgba(59,130,246,1)] z-50 pointer-events-none transition-all duration-100"
              style={{ left: `${(currentTime + 21) * 8}px` }}
             >
                <div className="w-5 h-5 bg-blue-500 rounded-full -ml-[8.5px] -mt-2 ring-[6px] ring-blue-500/30 shadow-2xl" />
             </div>
          </div>
        </div>
      </div>
    </div>
  );
};

