type PreviewFormat = 'landscape' | 'portrait' | 'square';

const AdBuilder: React.FC<AdBuilderProps> = ({ onSave }) => {
  const [selectedCategory, setSelectedCategory] = useState('E-Commerce');
  const [theme, setTheme] = useState("");
  const [format, setFormat] = useState<PreviewFormat>('square');
  const [isGenerating, setIsGenerating] = useState(false);
  const [showSaved, setShowSaved] = useState(false);

  const [campaign, setCampaign] = useState({
    headline: "Your Brand, Redefined",
    description: "Experience professional creative excellence with Lumina Studio's AI-powered design tools.",
    ctas: ["Shop Now", "Learn More", "Get Started"],
    image: "https://picsum.photos/seed/ad-hero/800/800"
  });

  const categories = [
    { id: 'E-Commerce', icon: ShoppingBag, color: 'text-rose-400', bg: 'bg-rose-400/10' },
    { id: 'Education', icon: GraduationCap, color: 'text-blue-400', bg: 'bg-blue-400/10' },
    { id: 'Industry', icon: Building2, color: 'text-emerald-400', bg: 'bg-emerald-400/10' },
    { id: 'Restaurant', icon: Palette, color: 'text-amber-400', bg: 'bg-amber-400/10' },
  ];

  const handleGenerate = async () => {
    if (!theme) return;
    setIsGenerating(true);
    const gemini = GeminiService.getInstance();

    try {
      const imgAspect = format === 'landscape' ? '16:9' : format === 'portrait' ? '9:16' : '1:1';
