        gemini.generateAdCampaign(theme, selectedCategory),
        gemini.generateImage(`Premium high-fidelity professional ad visual for ${selectedCategory} brand. Theme: ${theme}`, imgAspect)
      ]);

      setCampaign({
        ...campaignData,
        image: visual || campaign.image
      });
    } catch (e) {
      console.error(e);
    } finally {
      setIsGenerating(false);
    }
  };

  const handleSave = () => {
    onSave({
