import { GoogleGenAI, Type, Modality } from "@google/genai";

export class GeminiService {
  private static instance: GeminiService;

  private constructor() {
    // Guidelines recommend creating a new GoogleGenAI instance right before making an API call
  }

  public static getInstance(): GeminiService {
    if (!GeminiService.instance) {
      GeminiService.instance = new GeminiService();
    }
    return GeminiService.instance;
  }

  async generateSpeech(text: string, voice: string = 'Kore') {
    try {
      // Create a new instance right before the call
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: "gemini-2.5-flash-preview-tts",
        contents: [{ parts: [{ text }] }],
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: {
            voiceConfig: {
              prebuiltVoiceConfig: { voiceName: voice },
            },
          },
        },
      });

      const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
      if (base64Audio) {
        return `data:audio/pcm;base64,${base64Audio}`;
      }
      return null;
    } catch (error) {
      console.error("Speech generation failed", error);
      return null;
    }
  }

  async generateImage(prompt: string, aspectRatio: "1:1" | "16:9" | "9:16" = "1:1") {
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-2.5-flash-image',
        contents: { parts: [{ text: prompt }] },
        config: { imageConfig: { aspectRatio } }
      });

      for (const part of response.candidates[0].content.parts) {
        // Iterate through parts to find the image part as per guidelines
        if (part.inlineData) {
          return `data:image/png;base64,${part.inlineData.data}`;
        }
      }
      return null;
    } catch (error) {
      console.error("Image generation failed", error);
      return null;
    }
  }

  async editImage(base64Image: string, instruction: string) {
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-2.5-flash-image',
        contents: {
          parts: [
            { inlineData: { data: base64Image.split(',')[1], mimeType: 'image/png' } },
            { text: instruction }
          ]
        }
      });

      for (const part of response.candidates[0].content.parts) {
        if (part.inlineData) {
          return `data:image/png;base64,${part.inlineData.data}`;
        }
      }
      return null;
    } catch (error) {
      console.error("Image editing failed", error);
      return null;
    }
  }

  async refineText(text: string, style: 'formal' | 'creative' | 'short') {
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Refine the following text to be more ${style}: "${text}"`,
      });
      // Correct extraction of text from GenerateContentResponse
      return response.text;
    } catch (error) {
      console.error("Text refinement failed", error);
      return text;
    }
  }

  async generateAdCampaign(theme: string, category: string) {
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Act as a marketing expert. Create an ad campaign for a ${category} brand with the theme: "${theme}". 
        Provide a catchy headline, a short body description, and 3 call-to-action buttons.`,
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              headline: { type: Type.STRING },
              description: { type: Type.STRING },
              ctas: { 
                type: Type.ARRAY, 
                items: { type: Type.STRING } 
              }
            },
            required: ["headline", "description", "ctas"]
          }
        }
      });
      return JSON.parse(response.text || '{}');
    } catch (error) {
      console.error("Ad generation failed", error);
      return { 
        headline: "Elevate Your Brand", 
        description: "Professional creative solutions tailored for your success.",
        ctas: ["Shop Now", "Learn More", "Contact Us"]
      };
    }
  }
}

import React, { useState, useRef, useEffect } from 'react';
import { 
  Paintbrush, 
  Eraser, 
  Square, 
  Circle, 
  Minus,
  Wand2, 
  Save, 
  Undo,
  Download,
  Video,
  Sparkles as SparklesIcon,
  CheckCircle,
  MousePointer2,
  Type
} from 'lucide-react';
import { GeminiService } from '../services/geminiService';
import { Project, StudioMode } from '../types';

interface PaintStudioProps {
  onSave: (project: Project) => void;
}

type Tool = 'brush' | 'eraser' | 'line' | 'rect' | 'ellipse';

const PaintStudio: React.FC<PaintStudioProps> = ({ onSave }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [tool, setTool] = useState<Tool>('brush');
  const [color, setColor] = useState('#3b82f6');
  const [strokeWidth, setStrokeWidth] = useState(5);
  const [isFilled, setIsFilled] = useState(false);
  const [isDrawing, setIsDrawing] = useState(false);
  const [isGenerating, setIsGenerating] = useState(false);
  const [prompt, setPrompt] = useState("");
  const [showSavedToast, setShowSavedToast] = useState(false);

  // For shape drawing (rubber banding)
  const startPos = useRef<{ x: number, y: number } | null>(null);
  const snapshot = useRef<ImageData | null>(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (canvas) {
      const ctx = canvas.getContext('2d', { willReadFrequently: true });
      if (ctx) {
        ctx.lineJoin = 'round';
        ctx.lineCap = 'round';
        // Initial background
        ctx.fillStyle = '#0f172a';
        ctx.fillRect(0, 0, canvas.width, canvas.height);
      }
    }
  }, []);

  const getMousePos = (e: React.MouseEvent) => {
    const canvas = canvasRef.current;
    if (!canvas) return { x: 0, y: 0 };
    const rect = canvas.getBoundingClientRect();
    const scaleX = canvas.width / rect.width;
    const scaleY = canvas.height / rect.height;
    return {
      x: (e.clientX - rect.left) * scaleX,
      y: (e.clientY - rect.top) * scaleY
    };
  };

  const startDrawing = (e: React.MouseEvent) => {
    const canvas = canvasRef.current;
    const ctx = canvas?.getContext('2d', { willReadFrequently: true });
    if (!canvas || !ctx) return;

    setIsDrawing(true);
    const pos = getMousePos(e);
    startPos.current = pos;

    // Save state for shape previewing
    snapshot.current = ctx.getImageData(0, 0, canvas.width, canvas.height);

    if (tool === 'brush' || tool === 'eraser') {
      ctx.beginPath();
      ctx.moveTo(pos.x, pos.y);
      ctx.lineWidth = strokeWidth;
      ctx.strokeStyle = tool === 'eraser' ? '#0f172a' : color;
    }
  };

  const draw = (e: React.MouseEvent) => {
    if (!isDrawing || !startPos.current) return;
    const canvas = canvasRef.current;
    const ctx = canvas?.getContext('2d');
    if (!canvas || !ctx) return;

    const currentPos = getMousePos(e);

    if (tool === 'brush' || tool === 'eraser') {
      ctx.lineWidth = strokeWidth;
      ctx.strokeStyle = tool === 'eraser' ? '#0f172a' : color;
      ctx.lineTo(currentPos.x, currentPos.y);
      ctx.stroke();
    } else {
      // For shapes, restore the snapshot before drawing the new preview
      if (snapshot.current) {
        ctx.putImageData(snapshot.current, 0, 0);
      }

      ctx.lineWidth = strokeWidth;
      ctx.strokeStyle = color;
      ctx.fillStyle = color;

      const width = currentPos.x - startPos.current.x;
      const height = currentPos.y - startPos.current.y;

      if (tool === 'line') {
        ctx.beginPath();
        ctx.moveTo(startPos.current.x, startPos.current.y);
        ctx.lineTo(currentPos.x, currentPos.y);
        ctx.stroke();
      } else if (tool === 'rect') {
        if (isFilled) {
          ctx.fillRect(startPos.current.x, startPos.current.y, width, height);
        } else {
          ctx.strokeRect(startPos.current.x, startPos.current.y, width, height);
        }
      } else if (tool === 'ellipse') {
        ctx.beginPath();
        ctx.ellipse(
          startPos.current.x + width / 2,
          startPos.current.y + height / 2,
          Math.abs(width / 2),
          Math.abs(height / 2),
          0, 0, 2 * Math.PI
        );
        if (isFilled) ctx.fill();
        ctx.stroke();
      }
    }
  };

  const endDrawing = () => {
    setIsDrawing(false);
    startPos.current = null;
    snapshot.current = null;
    canvasRef.current?.getContext('2d')?.beginPath();
  };

  const handleCharacterGenerate = async () => {
    if (!prompt) return;
    setIsGenerating(true);
    const gemini = GeminiService.getInstance();
    const result = await gemini.generateImage(`Animation character design for: ${prompt}. Concept art sheet, high resolution, expressive.`, "1:1");
    if (result) {
      const canvas = canvasRef.current;
      const ctx = canvas?.getContext('2d');
      const img = new Image();
      img.crossOrigin = "anonymous";
      img.onload = () => {
        ctx?.clearRect(0, 0, canvas?.width || 800, canvas?.height || 600);
        ctx?.drawImage(img, 0, 0, canvas?.width || 800, canvas?.height || 600);
      };
      img.src = result;
    }
    setIsGenerating(false);
  };

  const handleSave = () => {
    const canvas = canvasRef.current;
    if (canvas) {
      onSave({
        id: Date.now().toString(),
        name: "Character: " + (prompt || "Art Session"),
        type: StudioMode.PAINT,
        thumbnail: canvas.toDataURL(),
        updatedAt: Date.now(),
        status: 'draft',
        data: {}
      });
      setShowSavedToast(true);
      setTimeout(() => setShowSavedToast(false), 3000);
    }
  };

  const handleExport = () => {
    const canvas = canvasRef.current;
    if (canvas) {
      const link = document.createElement('a');
      link.href = canvas.toDataURL('image/png');
      link.setAttribute('download', 'lumina_character.png');
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
    }
  };

  return (
    <div className="h-full flex flex-col space-y-4 animate-in fade-in duration-500 max-w-7xl mx-auto">
      {showSavedToast && (
        <div className="fixed top-20 right-10 bg-emerald-500 text-white px-6 py-3 rounded-2xl shadow-2xl z-[100] flex items-center animate-in slide-in-from-right duration-300">
          <CheckCircle className="w-5 h-5 mr-3" />
          <span className="font-bold uppercase tracking-widest text-xs">Artwork Saved</span>
        </div>
      )}

      <div className="flex items-center justify-between mb-2">
        <div>
          <h2 className="text-2xl font-black uppercase tracking-tight flex items-center">
            <Paintbrush className="w-6 h-6 mr-3 text-emerald-500" />
            Character Paint Studio
          </h2>
        </div>
        <div className="flex space-x-2">
           <button onClick={() => {
             const ctx = canvasRef.current?.getContext('2d');
             if (ctx) {
               ctx.fillStyle = '#0f172a';
               ctx.fillRect(0, 0, canvasRef.current!.width, canvasRef.current!.height);
             }
           }} className="flex items-center px-4 py-2 bg-slate-800 hover:bg-slate-700 rounded-xl text-xs font-bold uppercase tracking-widest transition-all">
             <Undo className="w-4 h-4 mr-2" /> Reset
           </button>
           <button onClick={handleExport} className="flex items-center px-4 py-2 bg-slate-800 hover:bg-slate-700 rounded-xl text-xs font-bold uppercase tracking-widest transition-all">
             <Download className="w-4 h-4 mr-2" /> Export
           </button>
           <button onClick={handleSave} className="flex items-center px-6 py-2.5 bg-blue-600 hover:bg-blue-500 rounded-xl text-xs font-black uppercase tracking-widest shadow-xl shadow-blue-600/20 transition-all">
             <Save className="w-4 h-4 mr-2" /> Save
           </button>
        </div>
      </div>

      <div className="flex-1 flex flex-col lg:flex-row space-y-4 lg:space-y-0 lg:space-x-6 min-h-0">
