      status: 'draft',
      data: { image }
    });
    setShowSavedToast(true);
    setTimeout(() => setShowSavedToast(false), 3000);
  };

  const handleExport = () => {
    const link = document.createElement('a');
    link.href = image;
    link.setAttribute('download', 'lumina_edit.png');
