import React, { useState, useEffect } from 'react';
import { 
  FileSpreadsheet, FileText, FileBarChart, Save, Download, 
  Plus, Search, Folder, Trash2, Layout, Table as TableIcon, 
  Type, Sparkles, Wand2, CheckCircle, Clock, FileEdit 
} from 'lucide-react';
import { UserProfile, StudioMode, Project } from '../types';
import { GeminiService } from '../services/geminiService';

interface OfficeSuiteProps {
  user: UserProfile;
  onSave: (project: Project) => void;
}

interface SavedDoc {
  id: string;
  title: string;
  content: string;
  type: 'docs' | 'sheets' | 'slides';
  updatedAt: number;
}

const OfficeSuite: React.FC<OfficeSuiteProps> = ({ user, onSave }) => {
  const [activeTab, setActiveTab] = useState<'docs' | 'sheets' | 'slides'>('docs');
  const [docContent, setDocContent] = useState("");
  const [docTitle, setDocTitle] = useState("Untitled Document");
  const [isSaving, setIsSaving] = useState(false);
  const [isRefining, setIsRefining] = useState(false);
  const [savedDocs, setSavedDocs] = useState<SavedDoc[]>(() => {
    const saved = localStorage.getItem('lumina_office_docs');
    return saved ? JSON.parse(saved) : [];
  });

  useEffect(() => {
    localStorage.setItem('lumina_office_docs', JSON.stringify(savedDocs));
  }, [savedDocs]);

  const handleSave = () => {
    setIsSaving(true);
    const newDoc: SavedDoc = {
      id: Date.now().toString(),
      title: docTitle,
      content: docContent,
      type: activeTab,
      updatedAt: Date.now()
    };

    setSavedDocs(prev => [newDoc, ...prev.filter(d => d.title !== docTitle)].slice(0, 10));

    onSave({
      id: newDoc.id,
      name: docTitle,
      type: StudioMode.OFFICE,
      thumbnail: 'https://images.unsplash.com/photo-1517842645767-c639042777db?auto=format&fit=crop&q=80&w=300&h=200',
      updatedAt: Date.now(),
      status: 'draft',
      data: { content: docContent, type: activeTab }
    });

    setTimeout(() => setIsSaving(false), 800);
  };

  const handleRefine = async (style: 'formal' | 'creative' | 'short') => {
    if (!docContent) return;
    setIsRefining(true);
    const gemini = GeminiService.getInstance();
    const refined = await gemini.refineText(docContent, style);
    if (refined) setDocContent(refined);
    setIsRefining(false);
  };

  const loadDoc = (doc: SavedDoc) => {
    setDocTitle(doc.title);
    setDocContent(doc.content);
    setActiveTab(doc.type);
  };

  const deleteDoc = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    setSavedDocs(prev => prev.filter(d => d.id !== id));
  };

  return (
    <div className="max-w-7xl mx-auto space-y-8 animate-in fade-in duration-700 pb-12">
      <div className="flex flex-col md:flex-row md:items-end justify-between gap-4">
        <div className="flex items-center space-x-6">
          <div className="p-4 bg-indigo-600/10 rounded-2xl border border-indigo-500/20 text-indigo-400">
            <FileSpreadsheet className="w-8 h-8" />
          </div>
          <div>
            <h2 className="text-3xl font-black tracking-tight uppercase">Office Suite</h2>
            <p className="text-slate-400 mt-1 font-medium">Write, analyze, and manage professional records.</p>
          </div>
        </div>
        <div className="flex space-x-3">
          <button 
            onClick={handleSave} 
            className="px-8 py-3 bg-indigo-600 hover:bg-indigo-500 text-white rounded-2xl text-[10px] font-black uppercase tracking-widest shadow-xl shadow-indigo-600/20 transition-all flex items-center"
          >
            {isSaving ? <Clock className="w-4 h-4 mr-2 animate-spin" /> : <Save className="w-4 h-4 mr-2" />}
            {isSaving ? 'Syncing...' : 'Sync to Cloud'}
          </button>
        </div>
      </div>

      <div className="flex flex-col lg:flex-row gap-8 min-h-[75vh]">
        {/* Left Panel: History & Tools */}
        <div className="lg:w-80 space-y-6">
          <div className="bg-slate-900 border border-slate-800 rounded-[2rem] p-6 shadow-xl">
            <h3 className="text-[10px] font-black text-slate-500 uppercase tracking-widest mb-6 flex items-center">
              <Folder className="w-4 h-4 mr-3 text-indigo-400" />
              Recent Documents
            </h3>
            <div className="space-y-3 max-h-64 overflow-y-auto pr-2 custom-scrollbar">
              {savedDocs.length > 0 ? savedDocs.map(doc => (
                <div 
                  key={doc.id}
                  onClick={() => loadDoc(doc)}
                  className="group flex items-center justify-between p-3 bg-slate-800/40 border border-transparent hover:border-indigo-500/30 rounded-xl cursor-pointer transition-all"
                >
                  <div className="flex items-center space-x-3 truncate">
                    <FileText className="w-4 h-4 text-slate-500 shrink-0" />
                    <span className="text-xs font-bold text-slate-300 truncate">{doc.title}</span>
                  </div>
                  <button onClick={(e) => deleteDoc(e, doc.id)} className="opacity-0 group-hover:opacity-100 p-1 hover:text-rose-500 transition-all">
                    <Trash2 className="w-3.5 h-3.5" />
                  </button>
                </div>
              )) : (
                <p className="text-[10px] text-slate-600 font-bold text-center py-4 uppercase">No saved records</p>
              )}
            </div>
            <button 
              onClick={() => { setDocTitle("New Document"); setDocContent(""); }}
              className="w-full mt-6 py-3 bg-slate-800 hover:bg-slate-700 rounded-xl text-[10px] font-black uppercase tracking-widest text-slate-300 transition-all flex items-center justify-center border border-slate-700"
            >
              <Plus className="w-4 h-4 mr-2" /> Start Fresh
            </button>
          </div>

          <div className="bg-slate-900 border border-slate-800 rounded-[2rem] p-6 shadow-xl">
            <h3 className="text-[10px] font-black text-slate-500 uppercase tracking-widest mb-6 flex items-center">
              <Sparkles className="w-4 h-4 mr-3 text-amber-400" />
              AI Writing Assistant
            </h3>
            <div className="space-y-3">
              <button 
                onClick={() => handleRefine('formal')}
                disabled={isRefining || !docContent}
                className="w-full flex items-center p-3 bg-slate-800/40 border border-slate-700 rounded-xl hover:border-indigo-500 transition-all group disabled:opacity-50"
              >
                <div className="p-2 bg-indigo-500/10 rounded-lg mr-3 group-hover:bg-indigo-500/20 transition-all">
                  <Wand2 className="w-3.5 h-3.5 text-indigo-400" />
                </div>
                <span className="text-[10px] font-black uppercase tracking-widest text-slate-400">Make Formal</span>
              </button>
              <button 
                onClick={() => handleRefine('creative')}
                disabled={isRefining || !docContent}
                className="w-full flex items-center p-3 bg-slate-800/40 border border-slate-700 rounded-xl hover:border-indigo-500 transition-all group disabled:opacity-50"
              >
                <div className="p-2 bg-emerald-500/10 rounded-lg mr-3 group-hover:bg-emerald-500/20 transition-all">
                  <Sparkles className="w-3.5 h-3.5 text-emerald-400" />
                </div>
                <span className="text-[10px] font-black uppercase tracking-widest text-slate-400">Creative Flow</span>
              </button>
              <button 
                onClick={() => handleRefine('short')}
                disabled={isRefining || !docContent}
                className="w-full flex items-center p-3 bg-slate-800/40 border border-slate-700 rounded-xl hover:border-indigo-500 transition-all group disabled:opacity-50"
              >
                <div className="p-2 bg-rose-500/10 rounded-lg mr-3 group-hover:bg-rose-500/20 transition-all">
                  <Type className="w-3.5 h-3.5 text-rose-400" />
                </div>
                <span className="text-[10px] font-black uppercase tracking-widest text-slate-400">Summarize</span>
              </button>
            </div>
          </div>
        </div>

        {/* Main Editor Canvas */}
        <div className="flex-1 flex flex-col space-y-4">
          <div className="flex items-center space-x-2 bg-slate-900 p-1.5 rounded-2xl border border-slate-800 w-fit shadow-inner">
            {[
              { id: 'docs', label: 'Writer', icon: FileText },
              { id: 'sheets', label: 'Data Hub', icon: TableIcon },
              { id: 'slides', label: 'Visual Deck', icon: FileBarChart }
            ].map(tab => (
              <button 
                key={tab.id}
                onClick={() => setActiveTab(tab.id as any)}
                className={`flex items-center px-6 py-2.5 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${
                  activeTab === tab.id 
                  ? 'bg-indigo-600 text-white shadow-xl shadow-indigo-600/20' 
                  : 'text-slate-400 hover:text-white'
                }`}
              >
                <tab.icon className="w-4 h-4 mr-2" />
                {tab.label}
              </button>
            ))}
          </div>

          <div className="bg-white rounded-[2.5rem] border border-slate-200 overflow-hidden shadow-2xl flex-1 flex flex-col text-slate-900 relative">
            {isRefining && (
              <div className="absolute inset-0 bg-white/60 backdrop-blur-sm z-50 flex flex-col items-center justify-center">
                <div className="w-16 h-16 border-4 border-indigo-600 border-t-transparent rounded-full animate-spin mb-4" />
                <p className="text-indigo-600 font-black uppercase tracking-widest text-xs animate-pulse">Assistant is rewriting...</p>
              </div>
