interface SidebarProps {
  isOpen: boolean;
  toggle: () => void;
  activeMode: StudioMode;
  setActiveMode: (mode: StudioMode) => void;
  lang: 'en' | 'bn' | 'hi';
  isAdmin: boolean;
}

const Sidebar: React.FC<SidebarProps> = ({ isOpen, toggle, activeMode, setActiveMode, lang, isAdmin }) => {
  const navigate = useNavigate();
  const location = useLocation();
  const t = translations[lang];

  const menuItems = [
    { id: 'dashboard', icon: LayoutDashboard, label: t.dashboard, path: '/' },
    { id: StudioMode.VIDEO, icon: Video, label: t.video, path: '/video' },
    { id: StudioMode.PHOTO, icon: ImageIcon, label: t.photo, path: '/photo' },
    { id: StudioMode.PAINT, icon: Paintbrush, label: t.paint, path: '/paint' },
    { id: StudioMode.AD_BUILDER, icon: Megaphone, label: t.ads, path: '/ads' },
    { id: StudioMode.AUDIOBOOK, icon: BookOpen, label: t.audiobook, path: '/audiobook' },
    { id: StudioMode.OFFICE, icon: FileSpreadsheet, label: t.office, path: '/office' },
    { id: StudioMode.COMMUNICATION, icon: MessageSquare, label: t.communication, path: '/communication' },
    { id: StudioMode.SHOP, icon: ShoppingBag, label: t.shop, path: '/shop' },
    { id: StudioMode.STORAGE, icon: Cloud, label: t.storage, path: '/storage' },
    { id: 'templates', icon: Layers, label: t.templates, path: '/templates' },
    { id: StudioMode.SUPPORT, icon: LifeBuoy, label: t.support, path: '/support' },
    ...(isAdmin ? [{ id: StudioMode.ADMIN, icon: ShieldAlert, label: t.admin, path: '/admin' }] : []),
  ];

  const handleNav = (item: any) => {
    if (Object.values(StudioMode).includes(item.id as StudioMode)) {
      setActiveMode(item.id as StudioMode);
    }
    navigate(item.path);
  };

  return (
    <aside className={`${isOpen ? 'w-64' : 'w-20'} bg-slate-900 border-r border-slate-800 transition-all duration-300 flex flex-col relative z-50`}>
      <div className="p-6 flex items-center justify-between">
        {isOpen ? (
          <h1 className="text-xl font-bold bg-gradient-to-r from-cyan-400 to-blue-500 bg-clip-text text-transparent truncate tracking-widest uppercase">
            LUMINA
          </h1>
        ) : (
          <div className="w-8 h-8 bg-gradient-to-br from-cyan-400 to-blue-500 rounded-lg shadow-lg shadow-blue-500/20" />
        )}
      </div>

      <nav className="flex-1 px-3 space-y-2 overflow-y-auto scrollbar-hide">
        {menuItems.map((item) => (
          <button
            key={item.id}
            onClick={() => handleNav(item)}
            className={`w-full flex items-center p-3 rounded-xl transition-all group ${
              location.pathname === item.path 
                ? 'bg-blue-600 text-white shadow-lg shadow-blue-600/20' 
                : 'text-slate-400 hover:bg-slate-800 hover:text-slate-100'
            }`}
          >
            <item.icon className={`w-5 h-5 shrink-0 transition-transform group-hover:scale-110`} />
            {isOpen && <span className="ml-4 font-bold text-[10px] uppercase tracking-widest">{item.label}</span>}
          </button>
        ))}
      </nav>

      <div className="p-4 border-t border-slate-800">
        <button
          onClick={toggle}
          className="w-full flex items-center p-3 text-slate-400 hover:bg-slate-800 rounded-xl transition-all group"
        >
          {isOpen ? <ChevronLeft className="w-6 h-6 group-hover:-translate-x-1 transition-transform" /> : <ChevronRight className="w-6 h-6 group-hover:translate-x-1 transition-transform" />}
          {isOpen && <span className="ml-4 font-bold text-[10px] uppercase tracking-widest">Collapse</span>}
        </button>
      </div>
    </aside>
  );
};

export default Sidebar;

