import React, { useState, useEffect } from 'react';
import { 
  User, 
  ShieldCheck, 
  Mail, 
  Lock, 
  Sparkles, 
  UserPlus, 
  LogIn, 
  Key,
  AlertCircle,
  Eye,
  EyeOff,
  CheckCircle2
} from 'lucide-react';
import { UserProfile, SubscriptionTier } from '../types';

interface AuthProps {
  onLogin: (user: UserProfile) => void;
}

// Internal structure for "Database" storage
interface StoredUser extends UserProfile {
  password: string; // In a real app, this would be hashed
}

const Auth: React.FC<AuthProps> = ({ onLogin }) => {
  const [isLogin, setIsLogin] = useState(true);
  const [isAdmin, setIsAdmin] = useState(false);
  const [showPassword, setShowPassword] = useState(false);
  const [error, setError] = useState("");
  const [success, setSuccess] = useState("");

  const [formData, setFormData] = useState({
    name: '',
    email: '',
    password: '',
    adminKey: ''
  });

  // Get users from "Database"
  const getStoredUsers = (): StoredUser[] => {
    const users = localStorage.getItem('lumina_users');
    return users ? JSON.parse(users) : [];
  };

  const handleAuth = (e: React.FormEvent) => {
    e.preventDefault();
    setError("");
    setSuccess("");

    const users = getStoredUsers();

    if (isLogin) {
      // LOGIN LOGIC
      const user = users.find(u => u.email === formData.email && u.password === formData.password);

      if (!user) {
        setError("Invalid email or password. Please try again.");
        return;
      }

      // Check role if they toggled Admin
      if (isAdmin && user.role !== 'Studio Admin') {
        setError("This account does not have Admin privileges.");
        return;
      }

      const { password, ...userProfile } = user;
      localStorage.setItem('lumina_session', JSON.stringify(userProfile));
      onLogin(userProfile);
    } else {
      // SIGN UP LOGIC
      if (!formData.name || !formData.email || !formData.password) {
        setError("Please populate all identity fields.");
        return;
      }

      if (users.some(u => u.email === formData.email)) {
        setError("An identity with this email already exists.");
        return;
      }

      if (isAdmin && formData.adminKey !== 'LUMINA2025') {
        setError("Invalid Studio Admin Master Key.");
        return;
      }

      const newUser: StoredUser = {
