    const users = localStorage.getItem('lumina_users');
    return users ? JSON.parse(users) : [];
  };

  const handleAuth = (e: React.FormEvent) => {
    e.preventDefault();
    setError("");
    setSuccess("");
    setIsSubmitting(true);

    const users = getStoredUsers();

    // Simulated network delay
    setTimeout(() => {
      setIsSubmitting(false);

      if (authView === 'login') {
        // LOGIN LOGIC
        const user = users.find(u => u.email === formData.email && u.password === formData.password);

        if (!user) {
          setError("Invalid email or password. Please try again.");
          return;
        }

        if (isAdmin && user.role !== 'Studio Admin') {
          setError("This account does not have Admin privileges.");
          return;
        }

        const { password, ...userProfile } = user;
        localStorage.setItem('lumina_session', JSON.stringify(userProfile));
        onLogin(userProfile);

      } else if (authView === 'signup') {
        // SIGN UP LOGIC
        if (!formData.name || !formData.email || !formData.password) {
          setError("Please populate all identity fields.");
          return;
        }

        if (users.some(u => u.email === formData.email)) {
          setError("An identity with this email already exists.");
          return;
        }

        if (isAdmin && formData.adminKey !== 'LUMINA2025') {
          setError("Invalid Studio Admin Master Key.");
          return;
        }

        const newUser: StoredUser = {
          name: formData.name,
          role: isAdmin ? 'Studio Admin' : 'Lead Creative',
          avatar: `https://api.dicebear.com/7.x/avataaars/svg?seed=${formData.email}`,
          email: formData.email,
          password: formData.password,
          plan: isAdmin ? 'Enterprise' : 'Individual' as SubscriptionTier,
          credits: isAdmin ? 99999 : 500,
          referralCode: `LUMINA-${Math.random().toString(36).substring(7).toUpperCase()}`,
          referralCount: 0,
          facebookConnected: false,
          githubConnected: false,
          twitterConnected: false,
          language: 'en',
          studentVerificationStatus: 'none',
        };

        users.push(newUser);
        localStorage.setItem('lumina_users', JSON.stringify(users));

        setSuccess("Account synthesized successfully! Please sign in.");
        setAuthView('login');
        setFormData({ ...formData, password: '' });

      } else if (authView === 'forgot') {
        // FORGOT PASSWORD LOGIC
        const userExists = users.some(u => u.email === formData.email);

        if (!userExists) {
          setError("This email is not registered in our creative network.");
          return;
        }

        setSuccess("Recovery protocol initiated. Check your inbox for reset instructions.");
        // In a real app, we'd send an email here.
      }
