  const [searchQuery, setSearchQuery] = useState('');

  const [users, setUsers] = useState<StoredUser[]>([]);
  const [logs, setLogs] = useState<AuditLog[]>([]);
  const [transactions, setTransactions] = useState<Transaction[]>([]);

  // Load data from localStorage
  const loadAdminData = () => {
    setIsRefreshing(true);
    const storedUsers = JSON.parse(localStorage.getItem('lumina_users') || '[]');
    const storedLogs = JSON.parse(localStorage.getItem('lumina_logs') || '[]');
    const storedTransactions = JSON.parse(localStorage.getItem('lumina_transactions') || '[]');

    setUsers(storedUsers);
    setLogs(storedLogs.sort((a: any, b: any) => new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime()));
    setTransactions(storedTransactions.sort((a: any, b: any) => new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime()));

    setTimeout(() => setIsRefreshing(false), 600);
  };

  useEffect(() => {
    loadAdminData();
  }, []);

  const stats = useMemo(() => {
    const totalRev = transactions.reduce((acc, curr) => acc + (curr.status === 'Completed' ? curr.amount : 0), 0);
    return [
      { label: 'Total Revenue', val: `₹${totalRev.toLocaleString()}`, change: '+12%', icon: DollarSign, color: 'text-emerald-400' },
      { label: 'Active Users', val: users.length.toString(), change: '+5%', icon: Users, color: 'text-blue-400' },
      { label: 'Total Logs', val: logs.length.toString(), change: '+22%', icon: History, color: 'text-rose-400' },
      { label: 'Active Sessions', val: Math.floor(users.length * 0.4).toString(), change: '+8%', icon: Activity, color: 'text-amber-400' },
    ];
  }, [users, logs, transactions]);

  const filteredUsers = users.filter(u => 
    u.name.toLowerCase().includes(searchQuery.toLowerCase()) || 
    u.email.toLowerCase().includes(searchQuery.toLowerCase())
  );

  const handleDeleteUser = (email: string) => {
    if (confirm(`Permanent deletion of user ${email}?`)) {
      const updated = users.filter(u => u.email !== email);
      localStorage.setItem('lumina_users', JSON.stringify(updated));
      setUsers(updated);
    }
  };

  return (
    <div className="max-w-7xl mx-auto space-y-8 animate-in fade-in duration-700 pb-12">
      <div className="flex flex-col md:flex-row md:items-end justify-between gap-6">
        <div>
          <h2 className="text-3xl font-black tracking-tight flex items-center uppercase">
            <ShieldAlert className="w-8 h-8 mr-4 text-rose-500" />
            Admin Intelligence
          </h2>
          <p className="text-slate-400 mt-2 font-medium">Monitoring global user behavior and revenue streams.</p>
        </div>
        <div className="flex items-center space-x-3">
          <button 
            onClick={loadAdminData}
            className={`p-3 bg-slate-900 border border-slate-800 rounded-2xl hover:bg-slate-800 transition-all ${isRefreshing ? 'animate-spin' : ''}`}
          >
            <RefreshCw className="w-5 h-5 text-slate-400" />
          </button>
          <div className="flex bg-slate-900 border border-slate-800 p-1.5 rounded-2xl shadow-inner">
            {[
              { id: 'master', label: 'Overview', icon: ShieldCheck },
              { id: 'history', label: 'User History', icon: History },
              { id: 'transactions', label: 'Payments', icon: CreditCard }
            ].map(tab => (
              <button 
                key={tab.id}
                onClick={() => setActiveTab(tab.id as any)}
                className={`px-6 py-2.5 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all flex items-center ${
                  activeTab === tab.id ? 'bg-blue-600 text-white shadow-xl' : 'text-slate-500 hover:text-white'
                }`}
              >
                <tab.icon className="w-3.5 h-3.5 mr-2" /> {tab.label}
              </button>
            ))}
          </div>
        </div>
      </div>

      {activeTab === 'master' && (
        <div className="space-y-8">
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
            {stats.map(s => (
              <div key={s.label} className="bg-slate-900 border border-slate-800 p-8 rounded-[2.5rem] shadow-2xl relative overflow-hidden group">
                <div className={`p-4 rounded-2xl bg-slate-800/50 w-fit mb-6 ${s.color}`}>
                  <s.icon className="w-6 h-6" />
                </div>
                <p className="text-slate-500 text-[10px] font-black uppercase tracking-widest">{s.label}</p>
                <p className="text-3xl font-black mt-1">{s.val}</p>
                <div className="absolute top-8 right-8 text-[9px] font-black px-2 py-1 bg-emerald-500/10 text-emerald-500 rounded-full border border-emerald-500/20">
                  {s.change}
                </div>
              </div>
            ))}
          </div>

          <div className="bg-slate-900 border border-slate-800 rounded-[2.5rem] overflow-hidden shadow-2xl">
            <div className="p-8 border-b border-slate-800 flex items-center justify-between">
              <h3 className="font-black uppercase tracking-tight flex items-center">
                <Users className="w-5 h-5 mr-3 text-blue-400" /> User Directory
              </h3>
              <div className="relative">
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-500" />
                <input 
                  value={searchQuery}
                  onChange={e => setSearchQuery(e.target.value)}
                  placeholder="Filter by name or email..."
                  className="bg-slate-800 border border-slate-700 rounded-xl py-2 pl-10 pr-4 text-xs w-64 focus:ring-2 focus:ring-blue-500"
                />
