                            <p className="text-sm font-black">{u.name}</p>
                            <p className="text-[10px] text-slate-500">{u.email}</p>
                          </div>
                        </div>
                      </td>
                      <td className="px-8 py-6">
                        <span className={`px-3 py-1 rounded-full text-[9px] font-black uppercase tracking-widest border ${
                          u.plan === 'Enterprise' ? 'bg-purple-500/10 text-purple-400 border-purple-500/20' : 'bg-blue-500/10 text-blue-400 border-blue-500/20'
                        }`}>
                          {u.plan}
                        </span>
                      </td>
                      <td className="px-8 py-6">
                        <span className={`text-[10px] font-black uppercase tracking-widest ${u.studentVerificationStatus === 'verified' ? 'text-emerald-400' : 'text-slate-600'}`}>
                          {u.studentVerificationStatus === 'verified' ? 'Student Verified' : 'Standard'}
