                      </td>
                      <td className="px-8 py-6 text-right">
                        <button 
                          onClick={() => handleDeleteUser(u.email)}
                          className="p-2 text-slate-600 hover:text-rose-500 transition-all opacity-0 group-hover:opacity-100"
