import React, { useState, useEffect } from 'react';
import { 
  User, 
  ShieldCheck, 
  Mail, 
  Lock, 
  Sparkles, 
  UserPlus, 
  LogIn, 
  Key,
  AlertCircle,
  Eye,
  EyeOff,
  CheckCircle2,
  ChevronLeft,
  RefreshCw,
  Info
} from 'lucide-react';
import { UserProfile, SubscriptionTier } from '../types';

interface AuthProps {
  onLogin: (user: UserProfile) => void;
}

interface StoredUser extends UserProfile {
  password: string;
}

const Auth: React.FC<AuthProps> = ({ onLogin }) => {
  const [authView, setAuthView] = useState<'login' | 'signup' | 'forgot'>('login');
  const [isAdmin, setIsAdmin] = useState(false);
  const [showPassword, setShowPassword] = useState(false);
  const [error, setError] = useState("");
  const [success, setSuccess] = useState("");
  const [isSubmitting, setIsSubmitting] = useState(false);

  const [formData, setFormData] = useState({
    name: '',
    email: '',
    password: ''
  });

  // Log activity helper
  const logActivity = (email: string, action: string, status: 'Success' | 'Warning' | 'Critical' = 'Success') => {
    const logs = JSON.parse(localStorage.getItem('lumina_logs') || '[]');
    const newLog = {
      id: Math.random().toString(36).substring(2, 9).toUpperCase(),
      timestamp: new Date().toISOString(),
      userEmail: email,
      action: action,
      status: status,
      ip: '127.0.0.1' // Simulated IP
    };
    localStorage.setItem('lumina_logs', JSON.stringify([...logs, newLog].slice(-100)));
  };

  // Initialize Mock Database with default accounts
  useEffect(() => {
    const existingUsers = localStorage.getItem('lumina_users');
    if (!existingUsers) {
      const defaultUsers: StoredUser[] = [
        {
          name: 'Master Admin',
          role: 'Studio Admin',
          avatar: 'https://api.dicebear.com/7.x/avataaars/svg?seed=admin',
          email: 'admin@lumina.com',
          password: 'admin123',
          plan: 'Enterprise',
          credits: 99999,
          referralCode: 'ADMIN-001',
          referralCount: 0,
          facebookConnected: false,
          githubConnected: false,
          twitterConnected: false,
          language: 'en',
          studentVerificationStatus: 'verified',
        },
        {
          name: 'Demo Creative',
          role: 'Lead Creative',
          avatar: 'https://api.dicebear.com/7.x/avataaars/svg?seed=user',
          email: 'user@lumina.com',
          password: 'user123',
          plan: 'Individual',
          credits: 500,
          referralCode: 'DEMO-99',
          referralCount: 0,
          facebookConnected: false,
          githubConnected: false,
          twitterConnected: false,
          language: 'en',
          studentVerificationStatus: 'none',
        }
      ];
      localStorage.setItem('lumina_users', JSON.stringify(defaultUsers));
    }
  }, []);

  const getStoredUsers = (): StoredUser[] => {
    const users = localStorage.getItem('lumina_users');
    return users ? JSON.parse(users) : [];
  };

  const handleAuth = (e: React.FormEvent) => {
    e.preventDefault();
    setError("");
    setSuccess("");
    setIsSubmitting(true);

    const users = getStoredUsers();

    setTimeout(() => {
      setIsSubmitting(false);

      if (authView === 'login') {
        const user = users.find(u => u.email.toLowerCase() === formData.email.toLowerCase() && u.password === formData.password);

        if (!user) {
          logActivity(formData.email, "Failed Login Attempt", "Warning");
          setError("Invalid email or password. Check your credentials.");
          return;
        }

        // Role check
        if (isAdmin && user.role !== 'Studio Admin') {
          logActivity(formData.email, "Admin Access Refused", "Warning");
          setError("This account does not have Admin access. Toggle to 'Creative' mode.");
          return;
        }

        if (!isAdmin && user.role === 'Studio Admin') {
          setError("This is an Admin account. Please toggle to 'Admin' mode to login.");
          return;
        }

        logActivity(formData.email, "Successful Login");
        const { password, ...userProfile } = user;
        localStorage.setItem('lumina_session', JSON.stringify(userProfile));
        onLogin(userProfile);

      } else if (authView === 'signup') {
        if (!formData.name || !formData.email || !formData.password) {
          setError("Fill in all fields to synthesize your identity.");
          return;
        }

        if (users.some(u => u.email.toLowerCase() === formData.email.toLowerCase())) {
          setError("Email already exists in the Lumina network.");
          return;
        }

        const newUser: StoredUser = {
          name: formData.name,
          role: isAdmin ? 'Studio Admin' : 'Lead Creative',
          avatar: `https://api.dicebear.com/7.x/avataaars/svg?seed=${formData.email}`,
          email: formData.email,
          password: formData.password,
          plan: isAdmin ? 'Enterprise' : 'Individual' as SubscriptionTier,
          credits: isAdmin ? 99999 : 500,
          referralCode: `LUMINA-${Math.random().toString(36).substring(7).toUpperCase()}`,
          referralCount: 0,
          facebookConnected: false,
          githubConnected: false,
          twitterConnected: false,
          language: 'en',
          studentVerificationStatus: 'none',
        };

        const updatedUsers = [...users, newUser];
        localStorage.setItem('lumina_users', JSON.stringify(updatedUsers));

        logActivity(formData.email, `New Account Synthesized (${isAdmin ? 'Admin' : 'User'})`);
        setSuccess("Identity initialized! You can now sign in.");
        setAuthView('login');
        setFormData({ name: '', email: '', password: '' });

      } else if (authView === 'forgot') {
        const userExists = users.some(u => u.email.toLowerCase() === formData.email.toLowerCase());
        if (!userExists) {
          setError("Email not found in our creative registry.");
          return;
        }
        logActivity(formData.email, "Password Recovery Initiated");
        setSuccess("Recovery packet dispatched! Check your secure inbox.");
      }
    }, 800);
  };

  return (
    <div className="min-h-screen bg-slate-950 flex items-center justify-center p-6 relative overflow-hidden">
      {/* Background Decor */}
      <div className="absolute top-[-10%] left-[-10%] w-[40%] h-[40%] bg-blue-600/10 blur-[120px] rounded-full" />
      <div className="absolute bottom-[-10%] right-[-10%] w-[40%] h-[40%] bg-purple-600/10 blur-[120px] rounded-full" />

      <div className="w-full max-w-[1000px] grid grid-cols-1 lg:grid-cols-2 bg-slate-900 rounded-[3rem] border border-slate-800 shadow-2xl overflow-hidden animate-in zoom-in-95 duration-500">

        {/* Left Side: Branding */}
        <div className={`hidden lg:flex flex-col justify-between p-12 transition-all duration-700 ${isAdmin ? 'bg-rose-900/20' : 'bg-blue-900/20'} border-r border-slate-800`}>
          <div>
            <div className="flex items-center space-x-3 mb-8">
              <div className={`w-10 h-10 rounded-xl flex items-center justify-center shadow-lg ${isAdmin ? 'bg-rose-600' : 'bg-blue-600'}`}>
                <Sparkles className="w-6 h-6 text-white" />
              </div>
              <h1 className="text-2xl font-black tracking-widest uppercase">Lumina</h1>
            </div>
            <h2 className="text-4xl font-black leading-tight mb-6 animate-in slide-in-from-left duration-700">
              {isAdmin ? 'Govern the Creative Engine.' : 'Synthesize Your Vision.'}
            </h2>
            <p className="text-slate-400 text-lg font-medium leading-relaxed opacity-70">
              {isAdmin 
                ? 'Manage users, audit cloud storage, and oversee global studio infrastructure.' 
                : 'Access 4K video editing, AI character paint, and professional ad building tools.'}
            </p>
          </div>

          <div className="p-6 bg-slate-950/40 rounded-3xl border border-white/5 backdrop-blur-md">
            <div className="flex items-center space-x-3 mb-4">
              <Info className="w-4 h-4 text-blue-400" />
              <span className="text-[10px] font-black uppercase tracking-widest text-slate-400">Default Access</span>
            </div>
            <div className="space-y-2 text-[10px] font-mono text-slate-500">
              <p>Admin: admin@lumina.com / admin123</p>
              <p>User: user@lumina.com / user123</p>
            </div>
          </div>
        </div>

        {/* Right Side: Form */}
        <div className="p-10 md:p-16 flex flex-col justify-center bg-slate-900/40 backdrop-blur-sm">
          {/* Role Toggle */}
          <div className="flex bg-slate-800/50 p-1 rounded-2xl mb-10 w-fit mx-auto lg:mx-0 border border-slate-700 shadow-inner">
            <button 
              onClick={() => { setIsAdmin(false); setError(""); setSuccess(""); }}
              className={`flex items-center px-6 py-2.5 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${!isAdmin ? 'bg-blue-600 text-white shadow-lg shadow-blue-600/20' : 'text-slate-500 hover:text-slate-300'}`}
            >
              <User className="w-3.5 h-3.5 mr-2" /> Creative
            </button>
            <button 
              onClick={() => { setIsAdmin(true); setError(""); setSuccess(""); }}
              className={`flex items-center px-6 py-2.5 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${isAdmin ? 'bg-rose-600 text-white shadow-lg shadow-rose-600/20' : 'text-slate-500 hover:text-slate-300'}`}
            >
              <ShieldCheck className="w-3.5 h-3.5 mr-2" /> Admin
            </button>
          </div>

          <div className="mb-8">
            <h3 className="text-2xl font-black uppercase tracking-tight mb-2">
              {authView === 'login' && (isAdmin ? 'Admin Console' : 'Welcome Back')}
              {authView === 'signup' && (isAdmin ? 'Establish Admin' : 'Create Identity')}
              {authView === 'forgot' && 'Identity Recovery'}
            </h3>
            <p className="text-slate-500 font-medium text-sm">
              {authView === 'login' && 'Sign in to access your workspace.'}
              {authView === 'signup' && 'Enter your details to begin your journey.'}
              {authView === 'forgot' && 'Reset your credentials via secure channel.'}
            </p>
          </div>

          <form onSubmit={handleAuth} className="space-y-5">
            {error && (
              <div className="p-4 bg-rose-500/10 border border-rose-500/20 rounded-2xl flex items-center text-rose-500 text-xs font-bold animate-in shake duration-300">
                <AlertCircle className="w-4 h-4 mr-3 shrink-0" />
                {error}
              </div>
            )}

            {success && (
              <div className="p-4 bg-emerald-500/10 border border-emerald-500/20 rounded-2xl flex items-center text-emerald-500 text-xs font-bold animate-in zoom-in-95 duration-300">
                <CheckCircle2 className="w-4 h-4 mr-3 shrink-0" />
                {success}
              </div>
            )}

            {authView === 'signup' && (
              <div className="space-y-2 group animate-in slide-in-from-top-2">
                <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1 group-focus-within:text-blue-500 transition-colors">Full Name</label>
                <div className="relative">
                  <User className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-600" />
                  <input 
                    type="text"
                    required
                    value={formData.name}
                    onChange={e => setFormData({...formData, name: e.target.value})}
                    placeholder="Enter your name"
                    className="w-full bg-slate-950 border border-slate-800 rounded-2xl py-4 pl-12 pr-4 focus:outline-none focus:ring-2 focus:ring-blue-500/50 transition-all text-slate-200"
                  />
                </div>
              </div>
            )}

            <div className="space-y-2 group">
              <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1 group-focus-within:text-blue-500 transition-colors">Work Email</label>
              <div className="relative">
                <Mail className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-600" />
                <input 
                  type="email"
                  required
                  value={formData.email}
                  onChange={e => setFormData({...formData, email: e.target.value})}
                  placeholder="name@studio.com"
                  className="w-full bg-slate-950 border border-slate-800 rounded-2xl py-4 pl-12 pr-4 focus:outline-none focus:ring-2 focus:ring-blue-500/50 transition-all text-slate-200"
                />
              </div>
            </div>

            {authView !== 'forgot' && (
              <div className="space-y-2 group animate-in slide-in-from-top-2">
                <div className="flex justify-between items-center ml-1">
                  <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest group-focus-within:text-blue-500 transition-colors">Secret Key</label>
                  {authView === 'login' && (
                    <button 
                      type="button" 
                      onClick={() => { setAuthView('forgot'); setError(""); setSuccess(""); }}
                      className="text-[9px] font-black text-slate-600 hover:text-blue-400 uppercase tracking-widest transition-all"
                    >
                      Forgot?
                    </button>
                  )}
                </div>
                <div className="relative">
                  <Lock className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-600" />
                  <input 
                    type={showPassword ? "text" : "password"}
                    required
                    value={formData.password}
                    onChange={e => setFormData({...formData, password: e.target.value})}
                    placeholder="••••••••"
                    className="w-full bg-slate-950 border border-slate-800 rounded-2xl py-4 pl-12 pr-12 focus:outline-none focus:ring-2 focus:ring-blue-500/50 transition-all text-slate-200"
                  />
                  <button 
                    type="button"
                    onClick={() => setShowPassword(!showPassword)}
                    className="absolute right-4 top-1/2 -translate-y-1/2 text-slate-600 hover:text-slate-400 transition-colors"
                  >
                    {showPassword ? <EyeOff className="w-4 h-4" /> : <Eye className="w-4 h-4" />}
                  </button>
                </div>
              </div>
            )}

            <button 
              type="submit"
              disabled={isSubmitting}
              className={`w-full py-5 rounded-2xl font-black uppercase tracking-widest text-[11px] shadow-xl flex items-center justify-center group transition-all transform active:scale-95 disabled:opacity-50 ${
                isAdmin ? 'bg-rose-600 hover:bg-rose-500 shadow-rose-600/20 text-white' : 'bg-blue-600 hover:bg-blue-500 shadow-blue-600/20 text-white'
              }`}
            >
              {isSubmitting ? (
                <RefreshCw className="w-4 h-4 animate-spin" />
              ) : (
                <>
                  {authView === 'login' && <>Access Studio <LogIn className="w-4 h-4 ml-3 group-hover:translate-x-1 transition-transform" /></>}
                  {authView === 'signup' && <>Initialize Account <UserPlus className="w-4 h-4 ml-3 group-hover:translate-x-1 transition-transform" /></>}
                  {authView === 'forgot' && <>Recover Identity <RefreshCw className="w-4 h-4 ml-3 group-hover:rotate-180 transition-transform duration-500" /></>}
                </>
              )}
            </button>
          </form>

          <div className="mt-8 pt-8 border-t border-slate-800 flex flex-col items-center justify-center space-y-4">
            {authView === 'forgot' ? (
              <button 
                onClick={() => { setAuthView('login'); setError(""); setSuccess(""); }}
                className="text-xs font-black uppercase tracking-widest text-slate-500 hover:text-white transition-all flex items-center group"
              >
                <ChevronLeft className="w-4 h-4 mr-2 group-hover:-translate-x-1 transition-transform" />
                Back to Sign In
              </button>
            ) : (
              <button 
                onClick={() => { setAuthView(authView === 'login' ? 'signup' : 'login'); setError(""); setSuccess(""); }}
                className="text-xs font-black uppercase tracking-widest text-slate-500 hover:text-white transition-all flex items-center group"
              >
                {authView === 'login' ? "Don't have an identity? Create one" : "Already registered? Sign in"}
                <ArrowRight className="w-3 h-3 ml-2 group-hover:translate-x-1 transition-transform" />
              </button>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

const ArrowRight = ({className}: {className?: string}) => (
  <svg className={className} width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round"><path d="M5 12h14M12 5l7 7-7 7"/></svg>
);

export default Auth;

import React, { useState, useRef } from 'react';
import { 
  User, 
  Mail, 
  Shield, 
  CreditCard, 
  Share2, 
  LogOut, 
  Camera, 
  Globe, 
  Github, 
  Twitter, 
  Facebook, 
  CheckCircle, 
  Copy, 
  Save, 
  X,
  Trophy,
  Users,
  Zap,
  Sparkles,
  ArrowRight,
  GraduationCap,
  Timer,
  Upload,
  AlertCircle,
  Clock,
  FileSearch,
  Check,
  Trash2
} from 'lucide-react';
import { UserProfile, SubscriptionTier, VerificationStatus } from '../types';
import { translations } from '../App';

interface UserProfilePageProps {
  user: UserProfile;
  setUser: (u: UserProfile) => void;
  onLogout: () => void;
}

const UserProfilePage: React.FC<UserProfilePageProps> = ({ user, setUser, onLogout }) => {
  const [isEditing, setIsEditing] = useState(false);
  const [editForm, setEditForm] = useState(user);
  const [showToast, setShowToast] = useState(false);
  const [toastMsg, setToastMsg] = useState('');
  const [showPlans, setShowPlans] = useState(false);
  const [showVerificationModal, setShowVerificationModal] = useState(false);
  const [icardPreview, setIcardPreview] = useState<string | null>(user.studentIcardUrl || null);
  const [isUploading, setIsUploading] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const t = translations[user.language];

  const plans = [
    { 
      id: 'Individual', 
      price: 20, 
      color: 'bg-slate-600', 
      features: ['Personal Use Only', '10 AI Credits/Day', '720p Exports', 'Standard Support'],
      icon: User
    },
    { 
      id: 'Creator', 
      price: 50, 
      color: 'bg-blue-600', 
      features: ['1080p Exports', '500 AI Credits', 'Basic Templates', 'Cloud Sync'],
      icon: User
    },
    { 
      id: 'Studio', 
      price: 80, 
      color: 'bg-indigo-600', 
      features: ['4K Video Export', '2000 AI Credits', 'Premium Templates', 'Priority Rendering', 'Team Collab'],
      icon: Zap
    },
    { 
      id: 'Enterprise', 
      price: 120, 
      color: 'bg-purple-600', 
      features: ['8K Export Support', 'Unlimited AI Credits', 'Custom AI Fine-tuning', 'Dedicated Manager', 'API Access'],
      icon: Sparkles
    }
  ];

  const logActivity = (action: string, status: 'Success' | 'Warning' | 'Critical' = 'Success') => {
    const logs = JSON.parse(localStorage.getItem('lumina_logs') || '[]');
    const newLog = {
      id: Math.random().toString(36).substring(2, 9).toUpperCase(),
      timestamp: new Date().toISOString(),
      userEmail: user.email,
      action: action,
      status: status,
      ip: '127.0.0.1'
    };
    localStorage.setItem('lumina_logs', JSON.stringify([...logs, newLog].slice(-100)));
  };

  const logTransaction = (plan: SubscriptionTier, price: number) => {
    const transactions = JSON.parse(localStorage.getItem('lumina_transactions') || '[]');
    const newTx = {
      id: `TX-${Math.random().toString(36).substring(2, 9).toUpperCase()}`,
      timestamp: new Date().toISOString(),
      userEmail: user.email,
      plan: plan,
      amount: price,
      status: 'Completed'
    };
    localStorage.setItem('lumina_transactions', JSON.stringify([...transactions, newTx]));
  };

  const handleSaveProfile = () => {
    setUser(editForm);
    setIsEditing(false);
    logActivity("Profile Updated");
    triggerToast('Profile updated successfully!');
  };

  const handleSelectPlan = (planId: SubscriptionTier) => {
    const selectedPlan = plans.find(p => p.id === planId);
    if (!selectedPlan) return;

    const price = user.studentVerificationStatus === 'verified' ? Math.round(selectedPlan.price * 0.9) : selectedPlan.price;

    setUser({ ...user, plan: planId });
    logActivity(`Plan Upgraded to ${planId}`);
    logTransaction(planId, price);

    setShowPlans(false);
    triggerToast(`Subscribed to ${planId} plan!`);
  };

  const triggerToast = (msg: string) => {
    setToastMsg(msg);
    setShowToast(true);
    setTimeout(() => setShowToast(false), 3000);
  };

  const handleIcardUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const url = URL.createObjectURL(file);
      setIcardPreview(url);
    }
  };

  const submitVerification = () => {
    if (!icardPreview) return;
    setIsUploading(true);

    setTimeout(() => {
      setUser({
        ...user,
        studentVerificationStatus: 'pending',
        studentIcardUrl: icardPreview
      });
      setIsUploading(false);
      logActivity("Student ID Submitted");
      triggerToast('I-Card submitted for review!');

      setTimeout(() => {
        setUser({
          ...user,
          studentVerificationStatus: 'verified'
        });
        logActivity("Student Verification Approved", "Success");
        triggerToast('Student ID Verified! 10% Discount Applied.');
      }, 3000);
    }, 1500);
  };

  const resetVerification = () => {
    setUser({ ...user, studentVerificationStatus: 'none', studentIcardUrl: null });
    setIcardPreview(null);
    logActivity("Student Status Reset");
    triggerToast('Verification status reset.');
  };

  const copyReferral = () => {
    navigator.clipboard.writeText(`https://lumina.studio/join?ref=${user.referralCode}`);
    triggerToast('Referral link copied to clipboard!');
  };

  const toggleConnect = (key: 'facebookConnected' | 'githubConnected' | 'twitterConnected') => {
    const isConnecting = !user[key];
    setUser({ ...user, [key]: isConnecting });
    const serviceName = key.replace('Connected', '').charAt(0).toUpperCase() + key.replace('Connected', '').slice(1);
    logActivity(`${serviceName} ${isConnecting ? 'Connected' : 'Disconnected'}`);
    triggerToast(`${serviceName} account ${isConnecting ? 'connected' : 'disconnected'} successfully!`);
  };

  const isVerified = user.studentVerificationStatus === 'verified';

  return (
    <div className="max-w-4xl mx-auto space-y-8 animate-in fade-in duration-700 pb-12 relative">
      {showToast && (
        <div className="fixed top-20 right-10 bg-emerald-600 text-white px-6 py-4 rounded-2xl shadow-2xl z-[100] flex items-center animate-in slide-in-from-right duration-300">
          <CheckCircle className="w-5 h-5 mr-3" />
          <span className="font-bold uppercase tracking-widest text-xs">{toastMsg}</span>
        </div>
      )}

      {/* Student Verification Modal */}
      {showVerificationModal && (
        <div className="fixed inset-0 z-[110] bg-slate-950/80 backdrop-blur-xl flex items-center justify-center p-6 animate-in fade-in duration-300">
          <div className="w-full max-w-xl bg-slate-900 border border-slate-800 rounded-[3rem] p-10 shadow-2xl relative overflow-hidden">
             <button onClick={() => setShowVerificationModal(false)} className="absolute top-8 right-8 p-3 bg-slate-800 hover:bg-slate-700 rounded-2xl transition-all">
               <X className="w-6 h-6" />
             </button>

             <div className="flex flex-col items-center text-center space-y-6">
                <div className="p-5 bg-blue-600/10 rounded-[2rem] border border-blue-500/20 text-blue-400">
                  <GraduationCap className="w-10 h-10" />
                </div>
                <div>
                   <h3 className="text-2xl font-black uppercase tracking-tight">{t.verifyIcard}</h3>
                   <p className="text-slate-500 text-sm mt-2 font-medium">Please upload a clear photo of your student ID card to apply for the regional student discount.</p>
                </div>

                <div className="w-full">
                   <input 
                      type="file" 
                      ref={fileInputRef} 
                      onChange={handleIcardUpload} 
                      className="hidden" 
                      accept="image/*"
                   />

                   <div 
                      onClick={() => !isUploading && fileInputRef.current?.click()}
                      className={`w-full aspect-video rounded-[2rem] border-2 border-dashed transition-all flex flex-col items-center justify-center cursor-pointer overflow-hidden relative group ${
                        icardPreview ? 'border-blue-500/50' : 'border-slate-800 hover:border-slate-700 bg-slate-800/20'
                      }`}
                   >
                      {icardPreview ? (
                        <>
                           <img src={icardPreview} className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-500" alt="Icard Preview" />
                           <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 flex items-center justify-center transition-all">
                              <Upload className="w-8 h-8 text-white" />
                           </div>
                        </>
                      ) : (
                        <>
                           <Camera className="w-10 h-10 text-slate-700 mb-4 group-hover:scale-110 transition-transform" />
                           <p className="text-[10px] font-black uppercase text-slate-500 tracking-widest">{t.uploadIcard}</p>
                        </>
                      )}
                   </div>
                </div>

                <div className="flex w-full space-x-4">
                   <button 
                     onClick={() => setShowVerificationModal(false)}
                     className="flex-1 py-4 bg-slate-800 hover:bg-slate-700 rounded-2xl text-[10px] font-black uppercase tracking-widest transition-all"
                   >
                     Maybe Later
                   </button>
                   <button 
                     onClick={submitVerification}
                     disabled={!icardPreview || isUploading}
                     className="flex-1 py-4 bg-blue-600 hover:bg-blue-500 text-white rounded-2xl text-[10px] font-black uppercase tracking-widest shadow-xl shadow-blue-600/20 transition-all disabled:opacity-50 flex items-center justify-center"
                   >
                     {isUploading ? <Timer className="w-4 h-4 mr-3 animate-spin" /> : <CheckCircle className="w-4 h-4 mr-3" />}
                     {isUploading ? t.verifying : t.submitVerification}
                   </button>
                </div>
             </div>
          </div>
        </div>
      )}

      {/* Subscription Overlay */}
      {showPlans && (
        <div className="fixed inset-0 z-[100] bg-slate-950/80 backdrop-blur-md flex items-center justify-center p-6 animate-in fade-in duration-300">
          <div className="w-full max-w-6xl bg-slate-900 border border-slate-800 rounded-[3rem] p-10 shadow-2xl relative overflow-hidden overflow-y-auto max-h-[90vh]">
            <button 
              onClick={() => setShowPlans(false)}
              className="absolute top-8 right-8 p-3 bg-slate-800 hover:bg-slate-700 rounded-2xl transition-all"
            >
              <X className="w-6 h-6" />
            </button>
            <div className="text-center mb-12">
              <h2 className="text-4xl font-black tracking-tight mb-2">{t.choosePlan}</h2>
              <div className="flex flex-col items-center justify-center space-y-2 mt-2">
                <span className="text-emerald-400 bg-emerald-400/10 px-4 py-1.5 rounded-full text-[10px] font-black uppercase tracking-widest flex items-center border border-emerald-500/20">
                  <Timer className="w-3.5 h-3.5 mr-2" /> {t.demoTrial}
                </span>
                {isVerified && (
                  <span className="text-blue-400 bg-blue-400/10 px-4 py-1.5 rounded-full text-[10px] font-black uppercase tracking-widest flex items-center border border-blue-500/20 animate-bounce">
