            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
              {plans.map((p) => {
                const finalPrice = isVerified ? Math.round(p.price * 0.9) : p.price;
                return (
                  <div 
                    key={p.id}
                    className={`bg-slate-800/40 border-2 rounded-[2.5rem] p-8 transition-all flex flex-col ${
                      user.plan === p.id 
                        ? 'border-blue-500 scale-105 shadow-2xl shadow-blue-500/10' 
                        : 'border-slate-700 hover:border-slate-600'
                    }`}
                  >
                    <div className="flex justify-between items-start mb-6">
                      <div className={`p-4 rounded-2xl ${p.color} text-white shadow-xl`}>
                        <p.icon className="w-6 h-6" />
                      </div>
                      {user.plan === p.id && (
                        <span className="bg-blue-600 text-[10px] font-black uppercase px-3 py-1 rounded-full text-white">{t.active}</span>
                      )}
                    </div>
                    <h3 className="text-2xl font-black mb-1">{p.id}</h3>
                    <div className="flex items-baseline space-x-1 mb-2">
                      <span className="text-3xl font-black">₹{finalPrice}</span>
                      <span className="text-slate-500 font-bold text-xs uppercase tracking-widest">/mo</span>
                    </div>
                    {isVerified && (
                      <p className="text-[9px] font-black text-emerald-400 uppercase mb-6 tracking-tighter line-through decoration-rose-500">Original: ₹{p.price}</p>
                    )}
                    <div className="space-y-4 mb-10 flex-1">
                      {p.features.map(f => (
                        <div key={f} className="flex items-center text-[10px] font-bold text-slate-300">
                          <CheckCircle className="w-3.5 h-3.5 mr-2 text-emerald-400 shrink-0" />
                          {f}
                        </div>
                      ))}
                    </div>
                    <button 
                      onClick={() => handleSelectPlan(p.id as SubscriptionTier)}
                      disabled={user.plan === p.id}
                      className={`w-full py-4 rounded-2xl text-[10px] font-black uppercase tracking-widest transition-all ${
                        user.plan === p.id 
                        ? 'bg-slate-700 text-slate-500 cursor-default' 
                        : 'bg-white text-slate-950 hover:scale-105 shadow-xl'
                      }`}
                    >
                      {user.plan === p.id ? t.currentPlan : t.upgrade}
                    </button>
                  </div>
                );
              })}
            </div>
          </div>
        </div>
      )}

      {/* Hero Header */}
      <div className="relative h-56 rounded-[2.5rem] overflow-hidden bg-gradient-to-br from-blue-600 via-indigo-700 to-purple-800 border border-white/10 shadow-2xl">
        <div className="absolute inset-0 bg-black/10 backdrop-blur-[1px]" />
        <button className="absolute bottom-6 right-6 p-3 bg-black/40 hover:bg-black/60 text-white rounded-2xl backdrop-blur-xl transition-all border border-white/10 hover:scale-110">
          <Camera className="w-5 h-5" />
        </button>
      </div>

      <div className="px-10 -mt-20 relative z-10">
        <div className="flex flex-col md:flex-row md:items-end justify-between gap-6">
          <div className="flex items-end space-x-8">
            <div className="w-40 h-40 rounded-[2.5rem] bg-slate-900 border-[6px] border-slate-950 p-2 shadow-2xl overflow-hidden group relative">
              <img src={user.avatar} className="w-full h-full rounded-[1.8rem] object-cover transition-transform group-hover:scale-110 duration-500" alt="" />
              <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 flex items-center justify-center transition-all">
                <Camera className="w-6 h-6 text-white" />
              </div>
            </div>
            <div className="pb-4">
              {isEditing ? (
                <input 
                  value={editForm.name} 
                  onChange={e => setEditForm({...editForm, name: e.target.value})}
                  className="bg-slate-900 border border-blue-500/50 rounded-xl px-4 py-2 text-2xl font-black focus:outline-none focus:ring-4 focus:ring-blue-500/20"
                />
              ) : (
                <h2 className="text-4xl font-black tracking-tight">{user.name}</h2>
              )}
              <p className="text-blue-400 font-black uppercase tracking-[0.2em] text-xs mt-2">{user.role}</p>
            </div>
          </div>
          <div className="flex items-center space-x-3 pb-4">
            {isEditing ? (
              <>
                <button onClick={() => setIsEditing(false)} className="px-6 py-3 bg-slate-800 hover:bg-slate-700 rounded-2xl text-xs font-black uppercase tracking-widest transition-all flex items-center">
                  <X className="w-4 h-4 mr-2" /> Cancel
                </button>
                <button onClick={handleSaveProfile} className="px-8 py-3 bg-blue-600 hover:bg-blue-500 rounded-2xl text-xs font-black uppercase tracking-widest shadow-xl shadow-blue-600/20 transition-all flex items-center">
                  <Save className="w-4 h-4 mr-2" /> Save Changes
                </button>
              </>
            ) : (
              <button onClick={() => setIsEditing(true)} className="px-8 py-3 bg-slate-800 hover:bg-slate-700 border border-slate-700 rounded-2xl text-xs font-black uppercase tracking-widest shadow-xl transition-all">Edit Studio Profile</button>
            )}
            <button 
              onClick={onLogout}
              className="px-6 py-3 bg-rose-600 hover:bg-rose-500 text-white rounded-2xl text-xs font-black uppercase tracking-widest shadow-xl shadow-rose-600/20 transition-all flex items-center"
            >
              <LogOut className="w-4 h-4 mr-2" /> {t.logout}
            </button>
          </div>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-12 gap-8 px-10">
        <div className="md:col-span-8 space-y-8">
          {/* General Info */}
          <div className="bg-slate-900 border border-slate-800 rounded-[2rem] p-10 shadow-2xl relative overflow-hidden">
            <h3 className="text-sm font-black text-slate-500 uppercase tracking-widest mb-10 flex items-center">
              <User className="w-4 h-4 mr-3 text-blue-400" />
              General Workspace Identity
            </h3>
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-10">
              <div className="space-y-3">
                <label className="text-[10px] font-black text-slate-600 uppercase tracking-widest">Display Identity</label>
                <div className="flex items-center space-x-4 p-4 bg-slate-800/40 rounded-2xl border border-slate-800 group focus-within:border-blue-500/50 transition-all">
                  <User className="w-5 h-5 text-slate-500 group-focus-within:text-blue-400" />
                  <span className="text-sm font-bold text-slate-200">{user.name}</span>
                </div>
              </div>
              <div className="space-y-3">
                <label className="text-[10px] font-black text-slate-600 uppercase tracking-widest">Professional Contact</label>
                <div className="flex items-center space-x-4 p-4 bg-slate-800/40 rounded-2xl border border-slate-800 group focus-within:border-blue-500/50 transition-all">
                  <Mail className="w-5 h-5 text-slate-500 group-focus-within:text-blue-400" />
                  {isEditing ? (
                    <input 
                      value={editForm.email}
                      onChange={e => setEditForm({...editForm, email: e.target.value})}
                      className="bg-transparent text-sm font-bold w-full focus:outline-none"
                    />
                  ) : (
                    <span className="text-sm font-bold text-slate-200">{user.email}</span>
                  )}
                </div>
              </div>
            </div>
          </div>
        </div>

        <div className="md:col-span-4 space-y-8">
          {/* Active Membership Card */}
          <div className="bg-gradient-to-br from-indigo-600 to-blue-700 rounded-[2.5rem] p-8 text-white shadow-2xl relative overflow-hidden group">
            <div className="relative z-10">
              <h4 className="text-[10px] font-black uppercase tracking-[0.2em] mb-4 text-blue-200">{t.subscription}</h4>
              <div className="flex items-baseline space-x-2 mb-8">
                <span className="text-4xl font-black">{user.plan}</span>
                <span className="text-xs font-bold text-blue-200 opacity-60">/ Active</span>
              </div>
              <button 
                onClick={() => setShowPlans(true)}
                className="w-full py-5 bg-white text-blue-600 rounded-[1.5rem] text-[10px] font-black uppercase tracking-widest shadow-2xl transform hover:scale-[1.03] transition-all flex items-center justify-center"
              >
                Change Workspace Plan <ArrowRight className="w-4 h-4 ml-2" />
              </button>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default UserProfilePage;

export enum StudioMode {
  VIDEO = 'video',
  PHOTO = 'photo',
  PAINT = 'paint',
  AD_BUILDER = 'ad_builder',
  AUDIOBOOK = 'audiobook',
  ADMIN = 'admin',
  PROFILE = 'profile',
  STORAGE = 'storage',
  SHOP = 'shop',
  COMMUNICATION = 'communication',
  OFFICE = 'office',
  SUPPORT = 'support'
}

export type SubscriptionTier = 'Individual' | 'Creator' | 'Studio' | 'Enterprise';
export type VerificationStatus = 'none' | 'pending' | 'verified' | 'rejected';

export interface UserProfile {
  name: string;
  role: string;
  avatar: string;
  email: string;
  plan: SubscriptionTier;
  credits: number;
  referralCode: string;
  referralCount: number;
  facebookConnected: boolean;
  githubConnected: boolean;
  twitterConnected: boolean;
  language: 'en' | 'bn' | 'hi';
  studentVerificationStatus: VerificationStatus;
  studentIcardUrl?: string | null;
  isApproved: boolean; // New field for admin approval
}

export interface Project {
  id: string;
  name: string;
  type: StudioMode;
  thumbnail: string;
  updatedAt: number;
  data: any;
  status: 'draft' | 'published' | 'archived';
}

export interface CloudAsset {
  id: string;
  name: string;
  type: 'video' | 'audio' | 'image';
  size: number;
  url: string;
  createdAt: number;
}

export interface TimelineLayer {
  id: string;
  name: string;
  type: 'video' | 'image' | 'audio' | 'text' | 'vfx';
  start: number;
  duration: number;
  content: string;
  vfxType?: string;
}

import React, { useState, useEffect } from 'react';
import { 
  User, 
  ShieldCheck, 
  Mail, 
  Lock, 
  Sparkles, 
  UserPlus, 
  LogIn, 
  Key,
  AlertCircle,
  Eye,
  EyeOff,
  CheckCircle2,
  ChevronLeft,
  RefreshCw,
  Info
} from 'lucide-react';
import { UserProfile, SubscriptionTier } from '../types';

interface AuthProps {
  onLogin: (user: UserProfile) => void;
}

interface StoredUser extends UserProfile {
  password: string;
}

const Auth: React.FC<AuthProps> = ({ onLogin }) => {
  const [authView, setAuthView] = useState<'login' | 'signup' | 'forgot'>('login');
  const [isAdmin, setIsAdmin] = useState(false);
  const [showPassword, setShowPassword] = useState(false);
  const [error, setError] = useState("");
  const [success, setSuccess] = useState("");
  const [isSubmitting, setIsSubmitting] = useState(false);

  const [formData, setFormData] = useState({
    name: '',
    email: '',
    password: ''
  });

  // Log activity helper
  const logActivity = (email: string, action: string, status: 'Success' | 'Warning' | 'Critical' = 'Success') => {
    const logs = JSON.parse(localStorage.getItem('lumina_logs') || '[]');
    const newLog = {
      id: Math.random().toString(36).substring(2, 9).toUpperCase(),
      timestamp: new Date().toISOString(),
      userEmail: email,
      action: action,
      status: status,
      ip: '127.0.0.1' // Simulated IP
    };
    localStorage.setItem('lumina_logs', JSON.stringify([...logs, newLog].slice(-100)));
  };

  // Initialize Mock Database with default accounts
  useEffect(() => {
    const existingUsers = localStorage.getItem('lumina_users');
    if (!existingUsers) {
      const defaultUsers: StoredUser[] = [
        {
          name: 'Master Admin',
          role: 'Studio Admin',
          avatar: 'https://api.dicebear.com/7.x/avataaars/svg?seed=admin',
          email: 'admin@lumina.com',
          password: 'admin123',
          plan: 'Enterprise',
          credits: 99999,
          referralCode: 'ADMIN-001',
          referralCount: 0,
          facebookConnected: false,
          githubConnected: false,
          twitterConnected: false,
          language: 'en',
          studentVerificationStatus: 'verified',
          isApproved: true,
        },
        {
          name: 'Demo Creative',
          role: 'Lead Creative',
          avatar: 'https://api.dicebear.com/7.x/avataaars/svg?seed=user',
          email: 'user@lumina.com',
          password: 'user123',
          plan: 'Individual',
          credits: 500,
          referralCode: 'DEMO-99',
          referralCount: 0,
          facebookConnected: false,
          githubConnected: false,
          twitterConnected: false,
          language: 'en',
          studentVerificationStatus: 'none',
          isApproved: true,
        }
      ];
      localStorage.setItem('lumina_users', JSON.stringify(defaultUsers));
    }
  }, []);

  const getStoredUsers = (): StoredUser[] => {
    const users = localStorage.getItem('lumina_users');
    return users ? JSON.parse(users) : [];
  };

  const handleAuth = (e: React.FormEvent) => {
    e.preventDefault();
    setError("");
    setSuccess("");
    setIsSubmitting(true);

    const users = getStoredUsers();

    setTimeout(() => {
      setIsSubmitting(false);

      if (authView === 'login') {
        const user = users.find(u => u.email.toLowerCase() === formData.email.toLowerCase() && u.password === formData.password);

        if (!user) {
          logActivity(formData.email, "Failed Login Attempt", "Warning");
          setError("Invalid email or password. Check your credentials.");
          return;
        }

        // Role check
        if (isAdmin && user.role !== 'Studio Admin') {
          logActivity(formData.email, "Admin Access Refused", "Warning");
          setError("This account does not have Admin access. Toggle to 'Creative' mode.");
          return;
        }

        if (!isAdmin && user.role === 'Studio Admin') {
          setError("This is an Admin account. Please toggle to 'Admin' mode to login.");
          return;
        }

        logActivity(formData.email, "Successful Login");
        const { password, ...userProfile } = user;
        localStorage.setItem('lumina_session', JSON.stringify(userProfile));
        onLogin(userProfile);

      } else if (authView === 'signup') {
        if (!formData.name || !formData.email || !formData.password) {
          setError("Fill in all fields to synthesize your identity.");
          return;
        }

        if (users.some(u => u.email.toLowerCase() === formData.email.toLowerCase())) {
          setError("Email already exists in the Lumina network.");
          return;
        }

        const newUser: StoredUser = {
          name: formData.name,
          role: isAdmin ? 'Studio Admin' : 'Lead Creative',
          avatar: `https://api.dicebear.com/7.x/avataaars/svg?seed=${formData.email}`,
          email: formData.email,
          password: formData.password,
          plan: isAdmin ? 'Enterprise' : 'Individual' as SubscriptionTier,
          credits: isAdmin ? 99999 : 500,
          referralCode: `LUMINA-${Math.random().toString(36).substring(7).toUpperCase()}`,
          referralCount: 0,
          facebookConnected: false,
          githubConnected: false,
          twitterConnected: false,
          language: 'en',
          studentVerificationStatus: 'none',
          isApproved: isAdmin, // Admins are approved by default
        };

        const updatedUsers = [...users, newUser];
        localStorage.setItem('lumina_users', JSON.stringify(updatedUsers));

        logActivity(formData.email, `New Account Synthesized (${isAdmin ? 'Admin' : 'User'})`);
        setSuccess(isAdmin ? "Admin account initialized! You can now sign in." : "Identity initialized! Access is pending Admin approval.");
        setAuthView('login');
        setFormData({ name: '', email: '', password: '' });

      } else if (authView === 'forgot') {
        const userExists = users.some(u => u.email.toLowerCase() === formData.email.toLowerCase());
        if (!userExists) {
          setError("Email not found in our creative registry.");
          return;
        }
        logActivity(formData.email, "Password Recovery Initiated");
        setSuccess("Recovery packet dispatched! Check your secure inbox.");
      }
    }, 800);
  };

  return (
    <div className="min-h-screen bg-slate-950 flex items-center justify-center p-6 relative overflow-hidden">
      {/* Background Decor */}
      <div className="absolute top-[-10%] left-[-10%] w-[40%] h-[40%] bg-blue-600/10 blur-[120px] rounded-full" />
      <div className="absolute bottom-[-10%] right-[-10%] w-[40%] h-[40%] bg-purple-600/10 blur-[120px] rounded-full" />

      <div className="w-full max-w-[1000px] grid grid-cols-1 lg:grid-cols-2 bg-slate-900 rounded-[3rem] border border-slate-800 shadow-2xl overflow-hidden animate-in zoom-in-95 duration-500">

        {/* Left Side: Branding */}
        <div className={`hidden lg:flex flex-col justify-between p-12 transition-all duration-700 ${isAdmin ? 'bg-rose-900/20' : 'bg-blue-900/20'} border-r border-slate-800`}>
          <div>
            <div className="flex items-center space-x-3 mb-8">
              <div className={`w-10 h-10 rounded-xl flex items-center justify-center shadow-lg ${isAdmin ? 'bg-rose-600' : 'bg-blue-600'}`}>
                <Sparkles className="w-6 h-6 text-white" />
              </div>
              <h1 className="text-2xl font-black tracking-widest uppercase">Lumina</h1>
            </div>
            <h2 className="text-4xl font-black leading-tight mb-6 animate-in slide-in-from-left duration-700">
              {isAdmin ? 'Govern the Creative Engine.' : 'Synthesize Your Vision.'}
            </h2>
            <p className="text-slate-400 text-lg font-medium leading-relaxed opacity-70">
              {isAdmin 
                ? 'Manage users, audit cloud storage, and oversee global studio infrastructure.' 
                : 'Access 4K video editing, AI character paint, and professional ad building tools.'}
            </p>
          </div>

          <div className="p-6 bg-slate-950/40 rounded-3xl border border-white/5 backdrop-blur-md">
            <div className="flex items-center space-x-3 mb-4">
              <Info className="w-4 h-4 text-blue-400" />
              <span className="text-[10px] font-black uppercase tracking-widest text-slate-400">Default Access</span>
            </div>
            <div className="space-y-2 text-[10px] font-mono text-slate-500">
              <p>Admin: admin@lumina.com / admin123</p>
              <p>User: user@lumina.com / user123</p>
            </div>
          </div>
        </div>

        {/* Right Side: Form */}
        <div className="p-10 md:p-16 flex flex-col justify-center bg-slate-900/40 backdrop-blur-sm">
          {/* Role Toggle */}
          <div className="flex bg-slate-800/50 p-1 rounded-2xl mb-10 w-fit mx-auto lg:mx-0 border border-slate-700 shadow-inner">
            <button 
              onClick={() => { setIsAdmin(false); setError(""); setSuccess(""); }}
              className={`flex items-center px-6 py-2.5 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${!isAdmin ? 'bg-blue-600 text-white shadow-lg shadow-blue-600/20' : 'text-slate-500 hover:text-slate-300'}`}
            >
              <User className="w-3.5 h-3.5 mr-2" /> Creative
            </button>
            <button 
              onClick={() => { setIsAdmin(true); setError(""); setSuccess(""); }}
              className={`flex items-center px-6 py-2.5 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${isAdmin ? 'bg-rose-600 text-white shadow-lg shadow-rose-600/20' : 'text-slate-500 hover:text-slate-300'}`}
            >
              <ShieldCheck className="w-3.5 h-3.5 mr-2" /> Admin
            </button>
          </div>

          <div className="mb-8">
            <h3 className="text-2xl font-black uppercase tracking-tight mb-2">
              {authView === 'login' && (isAdmin ? 'Admin Console' : 'Welcome Back')}
              {authView === 'signup' && (isAdmin ? 'Establish Admin' : 'Create Identity')}
              {authView === 'forgot' && 'Identity Recovery'}
            </h3>
            <p className="text-slate-500 font-medium text-sm">
              {authView === 'login' && 'Sign in to access your workspace.'}
              {authView === 'signup' && 'Enter your details to begin your journey.'}
              {authView === 'forgot' && 'Reset your credentials via secure channel.'}
            </p>
          </div>

          <form onSubmit={handleAuth} className="space-y-5">
            {error && (
              <div className="p-4 bg-rose-500/10 border border-rose-500/20 rounded-2xl flex items-center text-rose-500 text-xs font-bold animate-in shake duration-300">
                <AlertCircle className="w-4 h-4 mr-3 shrink-0" />
                {error}
              </div>
            )}

            {success && (
              <div className="p-4 bg-emerald-500/10 border border-emerald-500/20 rounded-2xl flex items-center text-emerald-500 text-xs font-bold animate-in zoom-in-95 duration-300">
                <CheckCircle2 className="w-4 h-4 mr-3 shrink-0" />
                {success}
              </div>
            )}

            {authView === 'signup' && (
              <div className="space-y-2 group animate-in slide-in-from-top-2">
                <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1 group-focus-within:text-blue-500 transition-colors">Full Name</label>
                <div className="relative">
                  <User className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-600" />
                  <input 
                    type="text"
                    required
                    value={formData.name}
                    onChange={e => setFormData({...formData, name: e.target.value})}
                    placeholder="Enter your name"
                    className="w-full bg-slate-950 border border-slate-800 rounded-2xl py-4 pl-12 pr-4 focus:outline-none focus:ring-2 focus:ring-blue-500/50 transition-all text-slate-200"
                  />
                </div>
              </div>
            )}

            <div className="space-y-2 group">
              <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1 group-focus-within:text-blue-500 transition-colors">Work Email</label>
              <div className="relative">
                <Mail className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-600" />
                <input 
                  type="email"
                  required
                  value={formData.email}
                  onChange={e => setFormData({...formData, email: e.target.value})}
                  placeholder="name@studio.com"
                  className="w-full bg-slate-950 border border-slate-800 rounded-2xl py-4 pl-12 pr-4 focus:outline-none focus:ring-2 focus:ring-blue-500/50 transition-all text-slate-200"
                />
              </div>
            </div>

            {authView !== 'forgot' && (
              <div className="space-y-2 group animate-in slide-in-from-top-2">
                <div className="flex justify-between items-center ml-1">
                  <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest group-focus-within:text-blue-500 transition-colors">Secret Key</label>
                  {authView === 'login' && (
                    <button 
                      type="button" 
                      onClick={() => { setAuthView('forgot'); setError(""); setSuccess(""); }}
                      className="text-[9px] font-black text-slate-600 hover:text-blue-400 uppercase tracking-widest transition-all"
                    >
                      Forgot?
                    </button>
                  )}
                </div>
                <div className="relative">
                  <Lock className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-600" />
                  <input 
                    type={showPassword ? "text" : "password"}
                    required
                    value={formData.password}
                    onChange={e => setFormData({...formData, password: e.target.value})}
                    placeholder="••••••••"
                    className="w-full bg-slate-950 border border-slate-800 rounded-2xl py-4 pl-12 pr-12 focus:outline-none focus:ring-2 focus:ring-blue-500/50 transition-all text-slate-200"
                  />
                  <button 
                    type="button"
                    onClick={() => setShowPassword(!showPassword)}
                    className="absolute right-4 top-1/2 -translate-y-1/2 text-slate-600 hover:text-slate-400 transition-colors"
                  >
                    {showPassword ? <EyeOff className="w-4 h-4" /> : <Eye className="w-4 h-4" />}
                  </button>
                </div>
              </div>
            )}

            <button 
              type="submit"
              disabled={isSubmitting}
              className={`w-full py-5 rounded-2xl font-black uppercase tracking-widest text-[11px] shadow-xl flex items-center justify-center group transition-all transform active:scale-95 disabled:opacity-50 ${
                isAdmin ? 'bg-rose-600 hover:bg-rose-500 shadow-rose-600/20 text-white' : 'bg-blue-600 hover:bg-blue-500 shadow-blue-600/20 text-white'
              }`}
            >
              {isSubmitting ? (
                <RefreshCw className="w-4 h-4 animate-spin" />
              ) : (
                <>
                  {authView === 'login' && <>Access Studio <LogIn className="w-4 h-4 ml-3 group-hover:translate-x-1 transition-transform" /></>}
                  {authView === 'signup' && <>Initialize Account <UserPlus className="w-4 h-4 ml-3 group-hover:translate-x-1 transition-transform" /></>}
                  {authView === 'forgot' && <>Recover Identity <RefreshCw className="w-4 h-4 ml-3 group-hover:rotate-180 transition-transform duration-500" /></>}
                </>
              )}
            </button>
          </form>

          <div className="mt-8 pt-8 border-t border-slate-800 flex flex-col items-center justify-center space-y-4">
            {authView === 'forgot' ? (
              <button 
                onClick={() => { setAuthView('login'); setError(""); setSuccess(""); }}
                className="text-xs font-black uppercase tracking-widest text-slate-500 hover:text-white transition-all flex items-center group"
              >
                <ChevronLeft className="w-4 h-4 mr-2 group-hover:-translate-x-1 transition-transform" />
                Back to Sign In
              </button>
            ) : (
              <button 
                onClick={() => { setAuthView(authView === 'login' ? 'signup' : 'login'); setError(""); setSuccess(""); }}
                className="text-xs font-black uppercase tracking-widest text-slate-500 hover:text-white transition-all flex items-center group"
              >
                {authView === 'login' ? "Don't have an identity? Create one" : "Already registered? Sign in"}
                <ArrowRight className="w-3 h-3 ml-2 group-hover:translate-x-1 transition-transform" />
              </button>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

