const App: React.FC = () => {
  const [activeMode, setActiveMode] = useState<StudioMode>(StudioMode.VIDEO);
  const [projects, setProjects] = useState<Project[]>([]);
  const [isSidebarOpen, setIsSidebarOpen] = useState(true);

  // Auth State
  const [user, setUser] = useState<UserProfile | null>(() => {
    const saved = localStorage.getItem('lumina_session');
    return saved ? JSON.parse(saved) : null;
  });

  // Effect to check approval status periodically if pending
  useEffect(() => {
    if (user && !user.isApproved) {
      const interval = setInterval(() => {
        const users = JSON.parse(localStorage.getItem('lumina_users') || '[]');
        const updatedUser = users.find((u: any) => u.email === user.email);
        if (updatedUser && updatedUser.isApproved) {
          const { password, ...userProfile } = updatedUser;
          setUser(userProfile);
          localStorage.setItem('lumina_session', JSON.stringify(userProfile));
        }
      }, 5000); // Check every 5 seconds
      return () => clearInterval(interval);
    }
  }, [user]);

  useEffect(() => {
    if (user) {
      localStorage.setItem('lumina_user', JSON.stringify(user));
      localStorage.setItem('lumina_session', JSON.stringify(user));
    } else {
      localStorage.removeItem('lumina_session');
    }
  }, [user]);

  useEffect(() => {
    if (user) {
      const saved = localStorage.getItem(`lumina_projects_${user.email}`);
      if (saved) {
        setProjects(JSON.parse(saved));
      } else {
        setProjects([]);
      }
    }
  }, [user]);

  const saveProject = (project: Project) => {
    if (!user) return;
    const updated = [project, ...projects.filter(p => p.id !== project.id)];
    setProjects(updated);
    localStorage.setItem(`lumina_projects_${user.email}`, JSON.stringify(updated));
  };

  const handleLogin = (loggedUser: UserProfile) => {
    setUser(loggedUser);
  };

  const handleLogout = () => {
    setUser(null);
    setProjects([]);
  };

  if (!user) {
    return <Auth onLogin={handleLogin} />;
  }

  // If user is logged in but not approved, show a "Pending" gate
  if (!user.isApproved) {
    return (
      <div className="min-h-screen bg-slate-950 flex flex-col items-center justify-center p-6 text-center relative overflow-hidden">
        <div className="absolute top-[-20%] left-[-10%] w-[60%] h-[60%] bg-blue-600/10 blur-[150px] rounded-full" />
        <div className="w-full max-w-md bg-slate-900 border border-slate-800 p-12 rounded-[3rem] shadow-2xl relative z-10 animate-in zoom-in-95 duration-500">
          <div className="w-20 h-20 bg-blue-600/10 rounded-3xl flex items-center justify-center mx-auto mb-8 border border-blue-500/20">
            <Clock className="w-10 h-10 text-blue-500 animate-pulse" />
          </div>
          <h2 className="text-3xl font-black uppercase tracking-tight mb-4">Access Pending</h2>
          <p className="text-slate-400 font-medium mb-8 leading-relaxed">
            Your Lumina Identity has been synthesized. An Admin must authorize your node before you can access the creative engine.
          </p>
          <div className="p-5 bg-slate-950/50 rounded-2xl border border-slate-800 mb-8">
            <p className="text-[10px] font-black uppercase tracking-widest text-slate-500 mb-1">Authenticated As</p>
            <p className="text-sm font-bold text-slate-200">{user.email}</p>
          </div>
          <button 
            onClick={handleLogout}
            className="w-full py-4 bg-slate-800 hover:bg-slate-700 text-white rounded-2xl text-xs font-black uppercase tracking-widest transition-all flex items-center justify-center border border-slate-700"
          >
            <LogOut className="w-4 h-4 mr-3" /> Log Out
          </button>
        </div>
      </div>
    );
  }

  const isAdmin = user.role === 'Studio Admin';

  return (
    <HashRouter>
      <div className="flex h-screen bg-slate-950 text-slate-100 overflow-hidden">
        <Sidebar 
          isOpen={isSidebarOpen} 
          toggle={() => setIsSidebarOpen(!isSidebarOpen)} 
          activeMode={activeMode}
          setActiveMode={setActiveMode}
          lang={user.language}
          isAdmin={isAdmin}
        />

        <div className="flex-1 flex flex-col min-w-0 h-full relative">
          <Header user={user} onLogout={handleLogout} setLanguage={(l) => setUser({...user, language: l})} />
          <main className="flex-1 overflow-auto relative p-4 md:p-6">
            <Routes>
              <Route path="/" element={<Dashboard projects={projects} setActiveMode={setActiveMode} user={user} />} />
              <Route path="/video" element={<VideoEditor onSave={saveProject} />} />
              <Route path="/photo" element={<PhotoEditor onSave={saveProject} />} />
              <Route path="/paint" element={<PaintStudio onSave={saveProject} />} />
              <Route path="/ads" element={<AdBuilder onSave={saveProject} />} />
              <Route path="/audiobook" element={<AudiobookStudio onSave={saveProject} />} />
              <Route path="/templates" element={<TemplatesGallery />} />
              <Route path="/admin" element={isAdmin ? <AdminPanel /> : <Navigate to="/" />} />
              <Route path="/profile" element={<UserProfilePage user={user} setUser={setUser} onLogout={handleLogout} />} />
              <Route path="/storage" element={<CloudStorage projects={projects} />} />
              <Route path="/shop" element={<Shop user={user} />} />
              <Route path="/communication" element={<CommunicationStudio user={user} />} />
              <Route path="/office" element={<OfficeSuite user={user} onSave={saveProject} />} />
              <Route path="/support" element={<SupportCenter user={user} />} />
              <Route path="*" element={<Navigate to="/" replace />} />
            </Routes>
          </main>
        </div>
      </div>
    </HashRouter>
  );
};

