          <div className="p-4 space-y-3">
            {logs.length > 0 ? logs.map((log) => (
              <div key={log.id} className="flex items-center justify-between p-4 bg-slate-950/40 rounded-2xl border border-slate-800 hover:border-slate-700 transition-all">
                <div className="flex items-center space-x-6">
                  <div className={`w-2 h-2 rounded-full ${log.status === 'Success' ? 'bg-emerald-500 shadow-[0_0_8px_#10b981]' : log.status === 'Critical' ? 'bg-rose-500 shadow-[0_0_8px_#f43f5e]' : 'bg-amber-500 shadow-[0_0_8px_#f59e0b]'}`} />
                  <div>
                    <p className="text-xs font-black uppercase tracking-widest text-slate-200">{log.action}</p>
                    <p className="text-[10px] text-slate-500 mt-0.5">{log.userEmail} • {log.ip}</p>
                  </div>
                </div>
                <div className="text-right">
                  <p className="text-[10px] font-mono text-slate-500">{new Date(log.timestamp).toLocaleTimeString()}</p>
                  <p className="text-[9px] font-black text-slate-700 uppercase">{new Date(log.timestamp).toLocaleDateString()}</p>
                </div>
              </div>
            )) : (
              <div className="py-20 text-center">
                <Activity className="w-12 h-12 text-slate-800 mx-auto mb-4" />
                <p className="text-slate-600 font-bold uppercase tracking-widest text-xs">No history recorded yet</p>
              </div>
            )}
          </div>
        </div>
      )}

      {activeTab === 'transactions' && (
        <div className="space-y-6 animate-in slide-in-from-bottom-4">
          <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">
            <div className="lg:col-span-12 bg-slate-900 border border-slate-800 rounded-[2.5rem] overflow-hidden shadow-2xl">
              <div className="p-8 border-b border-slate-800">
                <h3 className="font-black uppercase tracking-tight flex items-center">
                  <CreditCard className="w-5 h-5 mr-3 text-emerald-400" /> Subscription Purchases
