                </thead>
                <tbody className="divide-y divide-slate-800/50">
                  {filteredUsers.map(u => (
                    <tr key={u.email} className="group hover:bg-slate-800/30 transition-all">
                      <td className="px-8 py-6">
                        <div className="flex items-center space-x-4">
                          <img src={u.avatar} className="w-10 h-10 rounded-xl border border-white/5" alt="" />
                          <div className="truncate max-w-[150px]">
                            <p className="text-sm font-black truncate">{u.name}</p>
                            <p className="text-[10px] text-slate-500 truncate">{u.email}</p>
                          </div>
                        </div>
                      </td>
                      <td className="px-8 py-6 text-center">
                        <span className={`px-3 py-1 rounded-full text-[9px] font-black uppercase tracking-widest border ${
                          u.plan === 'Enterprise' ? 'bg-purple-500/10 text-purple-400 border-purple-500/20' : 'bg-blue-500/10 text-blue-400 border-blue-500/20'
                        }`}>
                          {u.plan}
                        </span>
                      </td>
                      <td className="px-8 py-6 text-center">
                        <div className="flex flex-col items-center">
                          <span className="text-xs font-black text-amber-400">{u.credits}</span>
                          <button 
                            onClick={() => setShowCreditModal({email: u.email, current: u.credits})}
                            className="text-[8px] font-black uppercase text-blue-400 hover:text-white mt-1 flex items-center"
