                            <ArrowUpCircle className="w-2.5 h-2.5 mr-1" /> Add
                          </button>
                        </div>
                      </td>
                      <td className="px-8 py-6 text-center">
                        <span className={`px-3 py-1 rounded-lg text-[9px] font-black uppercase tracking-widest border ${
                          u.isApproved ? 'bg-emerald-500/10 text-emerald-400 border-emerald-500/20' : 'bg-rose-500/10 text-rose-400 border-rose-500/20'
                        }`}>
                          {u.isApproved ? 'Approved' : 'Pending'}
                        </span>
                      </td>
                      <td className="px-8 py-6 text-right">
                        <div className="flex items-center justify-end space-x-2">
                          <button 
                            onClick={() => {/* handled by parent app logic usually */}}
                            className={`p-2 rounded-xl transition-all ${u.isApproved ? 'text-rose-500 hover:bg-rose-500/10' : 'text-emerald-500 hover:bg-emerald-500/10'}`}
                          >
                            {u.isApproved ? <UserMinus className="w-4 h-4" /> : <UserCheck className="w-4 h-4" />}
                          </button>
                        </div>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        </div>
      )}

      {activeTab === 'history' && (
        <div className="bg-slate-900 border border-slate-800 rounded-[2.5rem] overflow-hidden shadow-2xl animate-in slide-in-from-bottom-4">
          <div className="p-8 border-b border-slate-800 flex items-center justify-between">
            <h3 className="font-black uppercase tracking-tight flex items-center">
              <History className="w-5 h-5 mr-3 text-rose-400" /> Intelligence Feed
            </h3>
            <span className="text-[10px] font-black uppercase text-slate-500 bg-slate-800 px-3 py-1 rounded-full">Real-time Node Audit</span>
          </div>
          <div className="p-4 space-y-3 max-h-[600px] overflow-y-auto custom-scrollbar">
            {logs.length > 0 ? logs.map((log) => (
              <div key={log.id} className="flex items-center justify-between p-4 bg-slate-950/40 rounded-2xl border border-slate-800 hover:border-slate-700 transition-all group">
                <div className="flex items-center space-x-6">
                  <div className={`p-3 rounded-xl bg-slate-900 border border-slate-800 group-hover:scale-110 transition-transform`}>
