                          </span>
                        </td>
                        <td className="px-8 py-6 font-black text-emerald-400 text-sm">₹{tx.amount}</td>
                        <td className="px-8 py-6 text-right text-[10px] text-slate-500 font-mono">
                          {new Date(tx.timestamp).toLocaleString()}
                        </td>
                      </tr>
                    ))}
                    {transactions.length === 0 && (
                      <tr>
                        <td colSpan={5} className="px-8 py-20 text-center text-slate-600 font-black uppercase text-[10px] tracking-widest">Revenue streams inactive</td>
                      </tr>
                    )}
                  </tbody>
                </table>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

