  return (
    <div className="h-full flex flex-col space-y-4 animate-in fade-in duration-500 overflow-hidden relative">
      <input type="file" ref={audioInputRef} onChange={handleFileUpload} accept="audio/*,video/*" className="hidden" />

      {showSaveToast && (
        <div className="fixed top-20 right-10 bg-emerald-600 text-white px-8 py-4 rounded-2xl shadow-2xl z-[100] flex items-center animate-in slide-in-from-right duration-300">
          <CheckCircle className="w-5 h-5 mr-3" />
          <span className="font-bold uppercase tracking-widest text-xs">Project Synced to Cloud</span>
        </div>
      )}

      {showVfxPanel && (
        <div className="absolute inset-0 z-[60] bg-slate-950/70 backdrop-blur-md flex items-center justify-center p-4">
          <div className="bg-slate-900 border border-slate-800 rounded-[2.5rem] w-full max-w-xl p-10 shadow-2xl animate-in zoom-in-95 duration-200">
            <div className="flex justify-between items-center mb-10">
              <h3 className="text-2xl font-black flex items-center">
                <Zap className="w-6 h-6 mr-3 text-amber-400" />
                VFX Master Library
              </h3>
              <button onClick={() => setShowVfxPanel(false)} className="p-3 bg-slate-800 hover:bg-slate-700 rounded-2xl transition-all">
                <X className="w-6 h-6" />
              </button>
            </div>
            <div className="grid grid-cols-2 gap-6">
              {[
                { id: 'glitch', icon: '🌩️', label: 'Digital Glitch', desc: 'Fragmented pixel artifacts' },
                { id: 'bloom', icon: '✨', label: 'Neon Bloom', desc: 'Radiant glow on highlights' },
                { id: 'particles', icon: '❄️', label: 'Ember Dust', desc: 'Floating cinematic particles' },
                { id: 'cinematic', icon: '🎬', label: 'YouTube Grade', desc: 'Pro color correction' },
              ].map(vfx => (
                <button 
                  key={vfx.id}
                  onClick={() => applyVfx(vfx.id)}
                  className="p-8 bg-slate-800/50 hover:bg-slate-800 border border-slate-700 hover:border-amber-500/50 rounded-3xl text-left transition-all group"
                >
                  <span className="text-4xl mb-4 block group-hover:scale-110 transition-transform">{vfx.icon}</span>
                  <p className="font-black text-slate-100 uppercase tracking-widest text-sm">{vfx.label}</p>
                  <p className="text-xs text-slate-500 mt-2 font-medium">{vfx.desc}</p>
                </button>
              ))}
            </div>
          </div>
        </div>
      )}

      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 mb-2">
        <div className="flex items-center space-x-4">
          <h2 className="text-xl font-black flex items-center uppercase tracking-tight">
            <Video className="w-6 h-6 mr-3 text-rose-500" />
