    };
    localStorage.setItem('lumina_logs', JSON.stringify([newLog, ...logs].slice(0, 500)));
  };

  const handleAIEdit = async () => {
    if (!instruction) return;
    setIsProcessing(true);
    const gemini = GeminiService.getInstance();
    const result = await gemini.editImage(image, instruction);
    if (result) {
      setImage(result);
      logUsage(`AI Photo Edit: ${instruction.substring(0, 20)}...`);
    }
    setIsProcessing(false);
    setInstruction("");
  };

  const handleSave = () => {
    onSave({
      id: Date.now().toString(),
      name: "Edited Photo " + new Date().toLocaleTimeString(),
      type: StudioMode.PHOTO,
      thumbnail: image,
      updatedAt: Date.now(),
      status: 'draft',
      data: { image }
    });
    logUsage('Saved Photo Studio Session');
    setShowSavedToast(true);
    setTimeout(() => setShowSavedToast(false), 3000);
