          <CheckCircle className="w-5 h-5 mr-3" />
          <span className="font-bold uppercase tracking-widest text-xs">Photo Saved</span>
        </div>
      )}

      <div className="flex items-center justify-between mb-2">
        <div>
          <h2 className="text-2xl font-black flex items-center uppercase tracking-tight">
            <ImageIcon className="w-6 h-6 mr-3 text-cyan-500" />
            Photo Studio Pro
          </h2>
        </div>
        <div className="flex space-x-2">
          <button className="flex items-center px-4 py-2 bg-slate-800 hover:bg-slate-700 rounded-xl text-xs font-bold uppercase tracking-widest transition-all">
            <Upload className="w-4 h-4 mr-2" /> Upload
          </button>
          <button onClick={handleExport} className="flex items-center px-4 py-2 bg-slate-800 hover:bg-slate-700 rounded-xl text-xs font-bold uppercase tracking-widest transition-all">
            <Download className="w-4 h-4 mr-2" /> Export
          </button>
          <button onClick={handleSave} className="flex items-center px-6 py-2.5 bg-blue-600 hover:bg-blue-500 rounded-xl text-xs font-black uppercase tracking-widest shadow-xl shadow-blue-600/20 transition-all">
            <Save className="w-4 h-4 mr-2" /> Save
          </button>
        </div>
      </div>

      <div className="flex-1 flex flex-col lg:flex-row space-y-6 lg:space-y-0 lg:space-x-6 min-h-0">
        <div className="flex-1 bg-slate-900 rounded-[2.5rem] border border-slate-800 p-8 flex flex-col shadow-inner">
          <div className="flex-1 bg-black/40 rounded-[2rem] flex items-center justify-center relative overflow-hidden border border-white/5">
            <img 
