  const [logs, setLogs] = useState<AuditLog[]>([]);
  const [transactions, setTransactions] = useState<Transaction[]>([]);

  const loadAdminData = () => {
    setIsRefreshing(true);
    const storedUsers = JSON.parse(localStorage.getItem('lumina_users') || '[]');
    const storedLogs = JSON.parse(localStorage.getItem('lumina_logs') || '[]');
    const storedTransactions = JSON.parse(localStorage.getItem('lumina_transactions') || '[]');

    setUsers(storedUsers);
    setLogs(storedLogs.sort((a: any, b: any) => new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime()));
    setTransactions(storedTransactions.sort((a: any, b: any) => new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime()));

    setTimeout(() => setIsRefreshing(false), 600);
  };

  useEffect(() => {
    loadAdminData();
  }, []);

  const stats = useMemo(() => {
    const totalRev = transactions.reduce((acc, curr) => acc + (curr.status === 'Completed' ? curr.amount : 0), 0);
    return [
      { label: 'Total Revenue', val: `₹${totalRev.toLocaleString()}`, change: '+12%', icon: DollarSign, color: 'text-emerald-400' },
      { label: 'Registered Nodes', val: users.length.toString(), change: '+5%', icon: Users, color: 'text-blue-400' },
      { label: 'System Logs', val: logs.length.toString(), change: '+22%', icon: History, color: 'text-rose-400' },
      { label: 'Product Events', val: logs.filter(l => l.product).length.toString(), change: '+18%', icon: Activity, color: 'text-amber-400' },
    ];
  }, [users, logs, transactions]);

  const filteredUsers = users.filter(u => 
    u.name.toLowerCase().includes(searchQuery.toLowerCase()) || 
    u.email.toLowerCase().includes(searchQuery.toLowerCase())
  );

  const handleAddCredits = () => {
    if (!showCreditModal) return;
    const updated = users.map(u => {
      if (u.email === showCreditModal.email) {
        return { ...u, credits: (u.credits || 0) + creditAmount };
      }
      return u;
    });
    localStorage.setItem('lumina_users', JSON.stringify(updated));
    setUsers(updated);

    const storedLogs = JSON.parse(localStorage.getItem('lumina_logs') || '[]');
    const newLog = {
      id: Math.random().toString(36).substring(2, 9).toUpperCase(),
      timestamp: new Date().toISOString(),
      userEmail: showCreditModal.email,
      action: `Admin Injected ${creditAmount} Credits`,
      status: 'Success',
      ip: 'ADMIN-NODE'
    };
    localStorage.setItem('lumina_logs', JSON.stringify([...storedLogs, newLog].slice(-100)));
    setLogs([newLog, ...storedLogs]);

    setShowCreditModal(null);
  };

  const getProductIcon = (mode?: StudioMode) => {
    switch (mode) {
      case StudioMode.VIDEO: return <Video className="w-4 h-4 text-rose-400" />;
      case StudioMode.PHOTO: return <ImageIcon className="w-4 h-4 text-cyan-400" />;
      case StudioMode.PAINT: return <Paintbrush className="w-4 h-4 text-emerald-400" />;
      case StudioMode.AD_BUILDER: return <Megaphone className="w-4 h-4 text-amber-400" />;
      case StudioMode.AUDIOBOOK: return <BookOpen className="w-4 h-4 text-indigo-400" />;
      case StudioMode.OFFICE: return <FileText className="w-4 h-4 text-blue-400" />;
      default: return <Activity className="w-4 h-4 text-slate-500" />;
    }
  };

  const copyToClipboard = (text: string) => {
    navigator.clipboard.writeText(text);
    setShowCopyToast(true);
    setTimeout(() => setShowCopyToast(false), 2000);
  };

  return (
    <div className="max-w-7xl mx-auto space-y-8 animate-in fade-in duration-700 pb-12">

      {showCopyToast && (
        <div className="fixed top-20 right-10 bg-blue-600 text-white px-6 py-4 rounded-2xl shadow-2xl z-[110] flex items-center animate-in slide-in-from-right duration-300">
          <CheckCircle className="w-5 h-5 mr-3" />
          <span className="font-bold uppercase tracking-widest text-xs">URL Copied to Clipboard</span>
        </div>
      )}

      {/* Credit Modal */}
      {showCreditModal && (
        <div className="fixed inset-0 z-[100] bg-slate-950/80 backdrop-blur-md flex items-center justify-center p-6 animate-in fade-in duration-200">
