      id: 'Individual', 
      price: 20, 
      color: 'bg-slate-600', 
      features: ['Personal Use Only', '10 AI Credits/Day', '720p Exports', 'Standard Support'],
      icon: User
    },
    { 
      id: 'Creator', 
      price: 50, 
      color: 'bg-blue-600', 
      features: ['1080p Exports', '500 AI Credits', 'Basic Templates', 'Cloud Sync'],
      icon: User
    },
    { 
      id: 'Studio', 
