import React, { useState, useRef, useEffect } from 'react';
import { 
  User, Mail, Shield, CreditCard, Share2, LogOut, Camera, 
  Globe, CheckCircle, Copy, Save, X, Zap, Sparkles, ArrowRight, 
  GraduationCap, Timer, Upload, ExternalLink, RefreshCw
} from 'lucide-react';
import { UserProfile, SubscriptionTier } from '../types';
import { translations } from '../App';

interface UserProfilePageProps {
  user: UserProfile;
  setUser: (u: UserProfile) => void;
  onLogout: () => void;
}

const UserProfilePage: React.FC<UserProfilePageProps> = ({ user, setUser, onLogout }) => {
  const [isEditing, setIsEditing] = useState(false);
  const [editForm, setEditForm] = useState(user);
  const [showToast, setShowToast] = useState(false);
  const [toastMsg, setToastMsg] = useState('');
  const [showPlans, setShowPlans] = useState(false);
  const [showCamera, setShowCamera] = useState(false);
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);

  const t = translations[user.language];

  const triggerToast = (msg: string) => {
    setToastMsg(msg);
    setShowToast(true);
    setTimeout(() => setShowToast(false), 3000);
  };

  const startCamera = async () => {
    setShowCamera(true);
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ video: true });
      if (videoRef.current) {
        videoRef.current.srcObject = stream;
      }
    } catch (err) {
      console.error("Camera access denied", err);
      triggerToast("Camera Access Denied");
      setShowCamera(false);
    }
  };

  const stopCamera = () => {
    if (videoRef.current && videoRef.current.srcObject) {
      const stream = videoRef.current.srcObject as MediaStream;
      stream.getTracks().forEach(track => track.stop());
    }
    setShowCamera(false);
  };

  const takePhoto = () => {
    if (videoRef.current && canvasRef.current) {
      const context = canvasRef.current.getContext('2d');
      if (context) {
        canvasRef.current.width = videoRef.current.videoWidth;
        canvasRef.current.height = videoRef.current.videoHeight;
        context.drawImage(videoRef.current, 0, 0);
        const photoData = canvasRef.current.toDataURL('image/png');
        setUser({ ...user, avatar: photoData });
        triggerToast("Profile Photo Updated!");
        stopCamera();
      }
    }
  };

  const handleSaveProfile = () => {
    setUser(editForm);
    setIsEditing(false);
    triggerToast('Profile updated successfully!');
  };

  const publicLink = `${window.location.origin}/#/portfolio/${user.email.split('@')[0]}`;

  return (
    <div className="max-w-4xl mx-auto space-y-8 animate-in fade-in duration-700 pb-12 relative">
      {showToast && (
        <div className="fixed top-20 right-10 bg-emerald-600 text-white px-6 py-4 rounded-2xl shadow-2xl z-[100] flex items-center animate-in slide-in-from-right duration-300">
          <CheckCircle className="w-5 h-5 mr-3" />
          <span className="font-bold uppercase tracking-widest text-xs">{toastMsg}</span>
        </div>
      )}

      {showCamera && (
        <div className="fixed inset-0 z-[120] bg-slate-950/90 backdrop-blur-xl flex items-center justify-center p-6">
          <div className="bg-slate-900 border border-slate-800 rounded-[3rem] p-10 shadow-2xl w-full max-w-2xl flex flex-col items-center">
            <h3 className="text-xl font-black uppercase mb-6">Capture Studio Identity</h3>
            <div className="relative w-full aspect-video bg-black rounded-3xl overflow-hidden border border-white/10 mb-8">
              <video ref={videoRef} autoPlay playsInline className="w-full h-full object-cover mirror" />
              <canvas ref={canvasRef} className="hidden" />
            </div>
            <div className="flex space-x-4">
              <button onClick={stopCamera} className="px-8 py-4 bg-slate-800 rounded-2xl text-xs font-black uppercase">Cancel</button>
              <button onClick={takePhoto} className="px-10 py-4 bg-blue-600 rounded-2xl text-xs font-black uppercase shadow-xl shadow-blue-600/20">Capture Photo</button>
            </div>
          </div>
        </div>
      )}

      <div className="relative h-56 rounded-[2.5rem] overflow-hidden bg-gradient-to-br from-blue-600 via-indigo-700 to-purple-800 border border-white/10 shadow-2xl">
        <div className="absolute inset-0 bg-black/10 backdrop-blur-[1px]" />
      </div>

      <div className="px-10 -mt-20 relative z-10">
        <div className="flex flex-col md:flex-row md:items-end justify-between gap-6">
          <div className="flex items-end space-x-8">
            <div className="w-40 h-40 rounded-[2.5rem] bg-slate-900 border-[6px] border-slate-950 p-2 shadow-2xl overflow-hidden group relative cursor-pointer" onClick={startCamera}>
              <img src={user.avatar} className="w-full h-full rounded-[1.8rem] object-cover transition-transform group-hover:scale-110 duration-500" alt="" />
              <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 flex items-center justify-center transition-all">
                <Camera className="w-6 h-6 text-white" />
              </div>
            </div>
            <div className="pb-4">
              {isEditing ? (
                <input 
                  value={editForm.name} 
                  onChange={e => setEditForm({...editForm, name: e.target.value})}
                  className="bg-slate-900 border border-blue-500/50 rounded-xl px-4 py-2 text-2xl font-black text-white"
                />
              ) : (
                <h2 className="text-4xl font-black tracking-tight">{user.name}</h2>
              )}
              <p className="text-blue-400 font-black uppercase tracking-[0.2em] text-xs mt-2">{user.role}</p>
            </div>
          </div>
          <div className="flex items-center space-x-3 pb-4">
            <button onClick={() => setIsEditing(!isEditing)} className="px-8 py-3 bg-slate-800 hover:bg-slate-700 border border-slate-700 rounded-2xl text-xs font-black uppercase tracking-widest transition-all">
              {isEditing ? 'Cancel' : 'Edit Profile'}
            </button>
            {isEditing && (
              <button onClick={handleSaveProfile} className="px-8 py-3 bg-blue-600 rounded-2xl text-xs font-black uppercase">Save</button>
            )}
            <button onClick={onLogout} className="px-6 py-3 bg-rose-600 rounded-2xl text-xs font-black uppercase">{t.logout}</button>
          </div>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-12 gap-8 px-10">
        <div className="md:col-span-8 space-y-8">
          <div className="bg-slate-900 border border-slate-800 rounded-[2rem] p-10 shadow-2xl">
            <h3 className="text-sm font-black text-slate-500 uppercase tracking-widest mb-10 flex items-center">
              <User className="w-4 h-4 mr-3 text-blue-400" /> General Identity
            </h3>
            <div className="space-y-6">
              <div className="grid grid-cols-1 sm:grid-cols-2 gap-10">
                <div className="space-y-3">
                  <label className="text-[10px] font-black text-slate-600 uppercase">Email</label>
                  <div className="p-4 bg-slate-950 rounded-2xl border border-slate-800 text-sm font-bold text-slate-300">{user.email}</div>
                </div>
                <div className="space-y-3">
                  <label className="text-[10px] font-black text-slate-600 uppercase">Studio Plan</label>
                  <div className="p-4 bg-slate-950 rounded-2xl border border-slate-800 text-sm font-black text-blue-400 uppercase tracking-widest">{user.plan}</div>
                </div>
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

