import { Project, StudioMode, TimelineLayer } from '../types';

interface VideoEditorProps {
  onSave: (project: Project) => void;
}

type AspectRatio = '16:9' | '9:16' | '1:1';

const VideoEditor: React.FC<VideoEditorProps> = ({ onSave }) => {
  const [isPlaying, setIsPlaying] = useState(false);
  const [currentTime, setCurrentTime] = useState(0);
  const [selectedLayerIds, setSelectedLayerIds] = useState<Set<string>>(new Set());
  const [layers, setLayers] = useState<TimelineLayer[]>([
    { id: '1', name: 'Main Visual', type: 'video', start: 0, duration: 100, content: 'https://picsum.photos/seed/pro-vid/1280/720' },
    { id: '2', name: 'Ambient Audio', type: 'audio', start: 0, duration: 80, content: 'bg-music' },
  ]);
  const [aspectRatio, setAspectRatio] = useState<AspectRatio>('16:9');
  const [showVfxPanel, setShowVfxPanel] = useState(false);
  const [activeVfx, setActiveVfx] = useState<string[]>([]);
  const [proTools, setProTools] = useState({ brightness: 100, contrast: 100, saturation: 100 });
  const [isNarrating, setIsNarrating] = useState(false);
  const uploadInputRef = useRef<HTMLInputElement>(null);
  const [showSaveToast, setShowSaveToast] = useState(false);

  const logUsage = (action: string) => {
    const session = JSON.parse(localStorage.getItem('lumina_session') || '{}');
    const logs = JSON.parse(localStorage.getItem('lumina_logs') || '[]');
    const newLog = {
      id: Math.random().toString(36).substring(2, 9).toUpperCase(),
      timestamp: new Date().toISOString(),
      userEmail: session.email || 'guest@lumina.com',
      action,
      status: 'Success',
      ip: '127.0.0.1',
      product: StudioMode.VIDEO
    };
    localStorage.setItem('lumina_logs', JSON.stringify([newLog, ...logs].slice(0, 100)));
  };

  const handleSave = () => {
    onSave({
      id: Date.now().toString(),
      name: `Pro Cut (${aspectRatio}) ${new Date().toLocaleTimeString()}`,
      type: StudioMode.VIDEO,
      thumbnail: layers[0].content,
      updatedAt: Date.now(),
      status: 'draft',
      data: { layers, aspectRatio, proTools, activeVfx }
    });
    logUsage('Saved Professional Video Project');
    setShowSaveToast(true);
    setTimeout(() => setShowSaveToast(false), 3000);
  };

  const toggleVfx = (vfx: string) => {
    setActiveVfx(prev => prev.includes(vfx) ? prev.filter(v => v !== vfx) : [...prev, vfx]);
    logUsage(`Toggled VFX: ${vfx}`);
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const newLayer: TimelineLayer = {
        id: Date.now().toString(),
        name: file.name,
        type: file.type.startsWith('image') ? 'image' : (file.type.startsWith('audio') ? 'audio' : 'video'),
        start: 0,
        duration: 50,
        content: URL.createObjectURL(file)
      };
      setLayers([newLayer, ...layers]);
      logUsage(`Imported Asset: ${file.name}`);
    }
  };

  const convertToAudiobook = async () => {
    setIsNarrating(true);
    const gemini = GeminiService.getInstance();
    const sceneContext = layers.map(l => l.name).join(", ");
    const script = await gemini.refineText(`Create a cinematic narration script for a video with these elements: ${sceneContext}`, 'creative');
    const speech = await gemini.generateSpeech(script);
    if (speech) {
      const audiobookLayer: TimelineLayer = {
        id: `narration-${Date.now()}`,
        name: 'AI Narrative Track',
        type: 'audio',
        start: 0,
        duration: 100,
        content: speech
      };
      setLayers([...layers, audiobookLayer]);
      logUsage('Generated AI Narrative Audiobook Track');
    }
    setIsNarrating(false);
  };

  return (
    <div className="h-full flex flex-col space-y-4 animate-in fade-in duration-500 overflow-hidden relative">
      <input type="file" ref={uploadInputRef} onChange={handleFileUpload} className="hidden" accept="video/*,audio/*,image/*" />

      {showSaveToast && (
        <div className="fixed top-20 right-10 bg-emerald-600 text-white px-8 py-4 rounded-2xl shadow-2xl z-[100] flex items-center animate-in slide-in-from-right duration-300">
          <CheckCircle className="w-5 h-5 mr-3" />
          <span className="font-bold uppercase tracking-widest text-xs">Project Exported to Cloud</span>
        </div>
      )}

      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 mb-2">
        <div className="flex items-center space-x-4">
          <h2 className="text-xl font-black uppercase tracking-tight flex items-center">
            <Video className="w-6 h-6 mr-3 text-rose-500" /> Lumina Video Engine
          </h2>
          <div className="flex bg-slate-900 border border-slate-800 rounded-xl p-1">
            {['16:9', '9:16', '1:1'].map(ratio => (
              <button 
                key={ratio}
                onClick={() => setAspectRatio(ratio as AspectRatio)}
                className={`px-3 py-1 rounded-lg text-[10px] font-black transition-all ${aspectRatio === ratio ? 'bg-blue-600 text-white' : 'text-slate-500 hover:text-white'}`}
              >
                {ratio === '16:9' ? 'LONG' : ratio === '9:16' ? 'SHORT' : 'SQUARE'}
              </button>
            ))}
          </div>
        </div>
        <div className="flex items-center space-x-3">
          <button onClick={convertToAudiobook} disabled={isNarrating} className="flex items-center px-4 py-2.5 bg-indigo-600 hover:bg-indigo-500 rounded-2xl text-[10px] font-black uppercase tracking-widest transition-all">
            {isNarrating ? <RefreshCw className="w-4 h-4 mr-2 animate-spin" /> : <BookOpen className="w-4 h-4 mr-2" />}
            Narrative Tool
          </button>
          <button onClick={handleSave} className="flex items-center px-6 py-2.5 bg-blue-600 hover:bg-blue-500 rounded-2xl text-[10px] font-black uppercase tracking-widest shadow-xl">
            <Download className="w-4 h-4 mr-2" /> Final Export
          </button>
        </div>
      </div>

      <div className="flex-1 grid grid-cols-1 md:grid-cols-12 gap-6 min-h-0">
        {/* Workspace Canvas */}
        <div className="md:col-span-8 flex flex-col min-h-0 bg-slate-900 rounded-[2.5rem] border border-slate-800 p-8 shadow-inner overflow-hidden">
          <div className="flex-1 bg-black rounded-[2rem] flex items-center justify-center relative overflow-hidden shadow-2xl border border-white/5 group">
            <div className={`relative transition-all duration-500 flex items-center justify-center ${aspectRatio === '9:16' ? 'h-full aspect-[9/16]' : 'w-full aspect-video'}`}>
               <img 
                src={layers.find(l => l.type === 'video' || l.type === 'image')?.content} 
                style={{ 
                  filter: `brightness(${proTools.brightness}%) contrast(${proTools.contrast}%) saturate(${proTools.saturation}%) 
                           ${activeVfx.includes('bloom') ? 'blur(1px) brightness(1.2)' : ''} 
                           ${activeVfx.includes('noir') ? 'grayscale(1)' : ''} 
                           ${activeVfx.includes('cinematic') ? 'sepia(0.2) contrast(1.1)' : ''}` 
                }}
                className={`max-h-full max-w-full object-cover transition-all duration-300 ${activeVfx.includes('glitch') ? 'animate-pulse' : ''}`}
               />

               {activeVfx.includes('glitch') && (
                 <div className="absolute inset-0 bg-red-500/10 mix-blend-screen animate-ping pointer-events-none" />
               )}
            </div>

            <div className="absolute bottom-8 flex items-center space-x-8 bg-slate-950/80 backdrop-blur-2xl px-10 py-4 rounded-full border border-white/10 opacity-0 group-hover:opacity-100 transition-all">
               <SkipBack className="w-5 h-5 text-slate-500" />
               <button onClick={() => setIsPlaying(!isPlaying)} className="w-12 h-12 bg-white rounded-full flex items-center justify-center text-slate-950">
                  {isPlaying ? <Pause /> : <Play className="ml-1" />}
               </button>
               <SkipForward className="w-5 h-5 text-slate-500" />
            </div>
          </div>
        </div>

        {/* Pro Sidebar */}
        <div className="md:col-span-4 bg-slate-900 rounded-[2.5rem] border border-slate-800 p-8 space-y-8 overflow-y-auto shadow-2xl custom-scrollbar">
          <div>
            <h3 className="text-[10px] font-black text-slate-500 uppercase tracking-widest mb-6 flex items-center"><Sliders className="w-3.5 h-3.5 mr-2" /> Color Grading</h3>
            <div className="space-y-6">
              {[
                { id: 'brightness', label: 'Exposure' },
                { id: 'contrast', label: 'Contrast' },
                { id: 'saturation', label: 'Vibrance' }
              ].map(tool => (
                <div key={tool.id} className="space-y-2">
                  <div className="flex justify-between text-[9px] font-bold text-slate-400 uppercase">
                    <span>{tool.label}</span>
                    <span>{(proTools as any)[tool.id]}%</span>
                  </div>
                  <input 
                    type="range" min="0" max="200" 
                    value={(proTools as any)[tool.id]}
                    onChange={(e) => setProTools({...proTools, [tool.id]: parseInt(e.target.value)})}
                    className="w-full accent-blue-600 h-1 bg-slate-800 rounded-full appearance-none cursor-pointer"
                  />
                </div>
              ))}
            </div>
          </div>

          <div>
            <h3 className="text-[10px] font-black text-slate-500 uppercase tracking-widest mb-6 flex items-center"><Zap className="w-3.5 h-3.5 mr-2" /> Master VFX</h3>
            <div className="grid grid-cols-2 gap-4">
              {[
                { id: 'glitch', label: 'Glitch' },
                { id: 'bloom', label: 'Bloom' },
                { id: 'cinematic', label: 'Cinematic' },
                { id: 'noir', label: 'B&W Noir' }
              ].map(v => (
                <button 
                  key={v.id} 
                  onClick={() => toggleVfx(v.id)}
                  className={`p-4 rounded-2xl border text-[10px] font-black uppercase transition-all ${activeVfx.includes(v.id) ? 'bg-blue-600 border-blue-500 text-white' : 'bg-slate-800 border-slate-700 text-slate-400 hover:border-slate-500'}`}
                >
                  {v.label}
                </button>
              ))}
            </div>
          </div>

          <button onClick={() => uploadInputRef.current?.click()} className="w-full py-4 bg-slate-800 hover:bg-slate-700 rounded-2xl text-[10px] font-black uppercase border border-slate-700 flex items-center justify-center">
            <Upload className="w-4 h-4 mr-3 text-blue-400" /> Import Media Assets
          </button>
        </div>
      </div>

      {/* Timeline */}
      <div className="h-48 bg-slate-900 rounded-[2.5rem] border border-slate-800 p-6 shadow-2xl flex flex-col overflow-hidden">
        <div className="flex items-center space-x-6 mb-4">
          <div className="flex items-center space-x-2 text-[10px] font-black text-slate-500 uppercase"><Layers className="w-3 h-3" /> Multi-Track Timeline</div>
          <div className="h-4 w-px bg-slate-800" />
          <div className="text-[10px] font-mono text-blue-400">00:{currentTime.toString().padStart(2, '0')}:00</div>
        </div>
        <div className="flex-1 space-y-3 overflow-y-auto pr-2 custom-scrollbar">
           {layers.map(layer => (
             <div key={layer.id} className="flex items-center space-x-4">
                <div className="w-32 truncate text-[10px] font-black text-slate-500 uppercase">{layer.name}</div>
                <div className={`flex-1 h-8 rounded-xl border border-white/5 shadow-inner flex items-center px-4 ${layer.type === 'audio' ? 'bg-indigo-600/20' : 'bg-rose-600/20'}`}>
                  {layer.type === 'audio' && <Volume2 className="w-3 h-3 text-indigo-400" />}
                </div>
             </div>
           ))}
        </div>
      </div>
    </div>
  );
};

export default VideoEditor;

import React, { useState, useRef } from 'react';
import { 
  ImageIcon, Layers, Wand2, Maximize, Contrast, Sun, RotateCcw,
  Upload, Save, Palette, Download, CheckCircle, FileUp
} from 'lucide-react';
import { GeminiService } from '../services/geminiService';
import { Project, StudioMode } from '../types';

interface PhotoEditorProps {
  onSave: (project: Project) => void;
}

const PhotoEditor: React.FC<PhotoEditorProps> = ({ onSave }) => {
  const [image, setImage] = useState<string>("https://picsum.photos/seed/studio-pro/1200/800");
  const [isProcessing, setIsProcessing] = useState(false);
  const [instruction, setInstruction] = useState("");
  const [showSavedToast, setShowSavedToast] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const logUsage = (action: string) => {
    const session = JSON.parse(localStorage.getItem('lumina_session') || '{}');
    const logs = JSON.parse(localStorage.getItem('lumina_logs') || '[]');
    const newLog = {
      id: Math.random().toString(36).substring(2, 9).toUpperCase(),
      timestamp: new Date().toISOString(),
      userEmail: session.email || 'guest@lumina.com',
      action,
      status: 'Success',
      ip: '127.0.0.1',
      product: StudioMode.PHOTO
    };
    localStorage.setItem('lumina_logs', JSON.stringify([newLog, ...logs].slice(0, 100)));
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const url = URL.createObjectURL(file);
      setImage(url);
      logUsage(`Imported Photo: ${file.name}`);
    }
  };

  const handleAIEdit = async () => {
    if (!instruction) return;
    setIsProcessing(true);
    const gemini = GeminiService.getInstance();
    const result = await gemini.editImage(image, instruction);
    if (result) {
      setImage(result);
      logUsage(`AI Master Edit: ${instruction}`);
    }
    setIsProcessing(false);
    setInstruction("");
  };

  const handleSaveToCloud = () => {
    onSave({
      id: Date.now().toString(),
      name: "Studio Export " + new Date().toLocaleTimeString(),
      type: StudioMode.PHOTO,
      thumbnail: image,
      updatedAt: Date.now(),
      status: 'draft',
      data: { image }
    });
    logUsage('Synced Asset to Cloud Storage');
    setShowSavedToast(true);
    setTimeout(() => setShowSavedToast(false), 3000);
  };

  const handleDownload = () => {
    const link = document.createElement('a');
    link.href = image;
    link.download = `lumina-export-${Date.now()}.png`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    logUsage('Direct Download of Final Asset');
  };

  return (
    <div className="h-full flex flex-col space-y-4 animate-in fade-in duration-500 max-w-7xl mx-auto">
      <input type="file" ref={fileInputRef} onChange={handleFileUpload} className="hidden" accept="image/*" />

      {showSavedToast && (
        <div className="fixed top-20 right-10 bg-emerald-500 text-white px-6 py-3 rounded-2xl shadow-2xl z-[100] flex items-center animate-in slide-in-from-right duration-300">
          <CheckCircle className="w-5 h-5 mr-3" />
          <span className="font-bold uppercase tracking-widest text-xs">Asset Synced!</span>
        </div>
      )}

      <div className="flex items-center justify-between mb-2">
        <div>
          <h2 className="text-2xl font-black flex items-center uppercase tracking-tight">
            <ImageIcon className="w-6 h-6 mr-3 text-cyan-500" /> Photo Studio Pro
          </h2>
        </div>
        <div className="flex space-x-2">
          <button onClick={() => fileInputRef.current?.click()} className="flex items-center px-4 py-2 bg-slate-800 hover:bg-slate-700 rounded-xl text-xs font-bold uppercase tracking-widest transition-all border border-slate-700">
            <FileUp className="w-4 h-4 mr-2 text-cyan-400" /> Import
          </button>
          <button onClick={handleDownload} className="flex items-center px-4 py-2 bg-slate-800 hover:bg-slate-700 rounded-xl text-xs font-bold uppercase tracking-widest transition-all border border-slate-700">
            <Download className="w-4 h-4 mr-2" /> Save File
          </button>
          <button onClick={handleSaveToCloud} className="flex items-center px-6 py-2.5 bg-blue-600 hover:bg-blue-500 rounded-xl text-xs font-black uppercase tracking-widest shadow-xl shadow-blue-600/20 transition-all">
            <CloudIcon className="w-4 h-4 mr-2" /> Sync Cloud
          </button>
        </div>
      </div>

      <div className="flex-1 flex flex-col lg:flex-row space-y-6 lg:space-y-0 lg:space-x-6 min-h-0">
        <div className="flex-1 bg-slate-900 rounded-[2.5rem] border border-slate-800 p-8 flex flex-col shadow-inner">
          <div className="flex-1 bg-black/40 rounded-[2rem] flex items-center justify-center relative overflow-hidden border border-white/5">
            <img 
              src={image} 
              alt="Edit Workspace" 
              className={`max-h-full max-w-full object-contain transition-all duration-700 shadow-2xl ${isProcessing ? 'blur-md scale-95 opacity-50' : 'scale-100'}`}
            />
            {isProcessing && (
              <div className="absolute inset-0 flex flex-col items-center justify-center bg-black/20 backdrop-blur-sm z-10">
                <div className="w-16 h-16 border-4 border-cyan-500 border-t-transparent rounded-full animate-spin mb-6" />
                <p className="text-cyan-400 font-black uppercase tracking-[0.2em] text-xs animate-pulse">Lumina AI Refactoring...</p>
              </div>
            )}
          </div>

          <div className="mt-8 flex space-x-4">
             <div className="flex-1 relative">
                <input 
                  value={instruction}
                  onChange={(e) => setInstruction(e.target.value)}
                  placeholder="Tell AI what to do: 'Enhance lighting', 'Remove background', 'Add a neon effect'..." 
                  className="w-full bg-slate-800 border border-slate-700 rounded-2xl py-4.5 pl-6 pr-16 focus:outline-none focus:ring-4 focus:ring-cyan-500/20 transition-all text-slate-100 font-medium"
