          <div>
            <h3 className="text-[10px] font-black text-slate-500 uppercase tracking-widest mb-6">Adjustment Deck</h3>
            <div className="space-y-6">
              {[
                { icon: Sun, label: 'Exposure', color: 'text-amber-400' },
                { icon: Contrast, label: 'Clarity', color: 'text-blue-400' },
