import React, { useState, useRef, useEffect } from 'react';
import { 
  Paintbrush, Eraser, Square, Circle, Minus, Wand2, Save, Undo,
  Download, Sparkles as SparklesIcon, CheckCircle, Box, Layers
} from 'lucide-react';
import { GeminiService } from '../services/geminiService';
import { Project, StudioMode } from '../types';

interface PaintStudioProps {
  onSave: (project: Project) => void;
}

type Tool = 'brush' | 'eraser' | 'line' | 'rect' | 'ellipse';

const PaintStudio: React.FC<PaintStudioProps> = ({ onSave }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [tool, setTool] = useState<Tool>('brush');
  const [color, setColor] = useState('#3b82f6');
  const [strokeWidth, setStrokeWidth] = useState(5);
  const [isDrawing, setIsDrawing] = useState(false);
  const [isGenerating, setIsGenerating] = useState(false);
  const [prompt, setPrompt] = useState("");
  const [showSavedToast, setShowSavedToast] = useState(false);

  const lastPos = useRef<{ x: number, y: number } | null>(null);

  const logUsage = (action: string) => {
    const session = JSON.parse(localStorage.getItem('lumina_session') || '{}');
    const logs = JSON.parse(localStorage.getItem('lumina_logs') || '[]');
    const newLog = {
      id: Math.random().toString(36).substring(2, 9).toUpperCase(),
      timestamp: new Date().toISOString(),
      userEmail: session.email || 'guest@lumina.com',
      action,
      status: 'Success',
      ip: '127.0.0.1',
      product: StudioMode.PAINT
    };
    localStorage.setItem('lumina_logs', JSON.stringify([newLog, ...logs].slice(0, 100)));
  };

  useEffect(() => {
    const canvas = canvasRef.current;
    if (canvas) {
      const ctx = canvas.getContext('2d');
      if (ctx) {
        ctx.fillStyle = '#0f172a';
        ctx.fillRect(0, 0, canvas.width, canvas.height);
        ctx.lineJoin = 'round';
        ctx.lineCap = 'round';
      }
    }
  }, []);

  const getMousePos = (e: React.MouseEvent) => {
    const canvas = canvasRef.current;
    if (!canvas) return { x: 0, y: 0 };
    const rect = canvas.getBoundingClientRect();
    const scaleX = canvas.width / rect.width;
    const scaleY = canvas.height / rect.height;
    return {
      x: (e.clientX - rect.left) * scaleX,
      y: (e.clientY - rect.top) * scaleY
    };
  };

  const startDrawing = (e: React.MouseEvent) => {
    setIsDrawing(true);
    lastPos.current = getMousePos(e);
  };

  const draw = (e: React.MouseEvent) => {
    if (!isDrawing) return;
    const canvas = canvasRef.current;
    const ctx = canvas?.getContext('2d');
    if (!canvas || !ctx) return;

    const currentPos = getMousePos(e);
    ctx.beginPath();
    ctx.moveTo(lastPos.current!.x, lastPos.current!.y);
    ctx.lineTo(currentPos.x, currentPos.y);
    ctx.strokeStyle = tool === 'eraser' ? '#0f172a' : color;
    ctx.lineWidth = strokeWidth;
    ctx.stroke();
    lastPos.current = currentPos;
  };

  const stopDrawing = () => setIsDrawing(false);

  const handleAIGenerate = async (style: '2d' | '3d') => {
    setIsGenerating(true);
    const gemini = GeminiService.getInstance();
    const canvas = canvasRef.current;
    const sketchBase64 = canvas?.toDataURL('image/png');

    const finalPrompt = style === '3d' 
      ? `High-fidelity 3D Pixar-style render based on this sketch: ${prompt}. Cinematic lighting, 8k resolution, Unreal Engine 5 render.`
      : `Professional 2D concept art based on this sketch: ${prompt}. Expressive line art, digital painting style.`;

    const result = await gemini.generateImage(finalPrompt, "1:1");
    if (result) {
      const img = new Image();
      img.onload = () => {
        canvas?.getContext('2d')?.drawImage(img, 0, 0, canvas.width, canvas.height);
      };
      img.src = result;
      logUsage(`Generated ${style.toUpperCase()} Character Asset`);
    }
    setIsGenerating(false);
  };

  const handleDownload = () => {
    const canvas = canvasRef.current;
    if (canvas) {
      const link = document.createElement('a');
      link.href = canvas.toDataURL('image/png');
      link.download = `character-design-${Date.now()}.png`;
      link.click();
      logUsage('Exported Direct Character File');
    }
  };

  return (
    <div className="h-full flex flex-col space-y-4 animate-in fade-in duration-500 max-w-7xl mx-auto">
      {showSavedToast && (
        <div className="fixed top-20 right-10 bg-emerald-500 text-white px-6 py-3 rounded-2xl shadow-2xl z-[100] flex items-center animate-in slide-in-from-right duration-300">
          <CheckCircle className="w-5 h-5 mr-3" />
          <span className="font-bold uppercase tracking-widest text-xs">Artwork Saved</span>
        </div>
      )}

      <div className="flex items-center justify-between mb-2">
        <h2 className="text-2xl font-black uppercase tracking-tight flex items-center">
          <Paintbrush className="w-6 h-6 mr-3 text-emerald-500" /> Character Master Paint
        </h2>
        <div className="flex space-x-2">
          <button onClick={() => {
            const ctx = canvasRef.current?.getContext('2d');
            if (ctx) { ctx.fillStyle = '#0f172a'; ctx.fillRect(0,0,1600,1200); }
          }} className="px-4 py-2 bg-slate-800 rounded-xl text-xs font-bold uppercase"><Undo className="w-4 h-4 mr-2 inline" /> Reset</button>
          <button onClick={handleDownload} className="px-4 py-2 bg-slate-800 rounded-xl text-xs font-bold uppercase"><Download className="w-4 h-4 mr-2 inline" /> Save File</button>
          <button onClick={() => handleAIGenerate('3d')} className="px-6 py-2.5 bg-indigo-600 rounded-xl text-xs font-black uppercase shadow-xl shadow-indigo-600/20 transition-all">
            <Box className="w-4 h-4 mr-2 inline" /> 3D Synthesize
          </button>
        </div>
      </div>

      <div className="flex-1 flex flex-col lg:flex-row space-y-4 lg:space-y-0 lg:space-x-6 min-h-0">
         <div className="w-full lg:w-20 bg-slate-900 border border-slate-800 rounded-[2rem] p-4 flex flex-row lg:flex-col items-center justify-center space-x-4 lg:space-x-0 lg:space-y-4 shadow-xl">
            {['brush', 'eraser'].map((t: any) => (
              <button key={t} onClick={() => setTool(t)} className={`p-3 rounded-2xl transition-all ${tool === t ? 'bg-blue-600 text-white' : 'bg-slate-800 text-slate-400'}`}>
                {t === 'brush' ? <Paintbrush /> : <Eraser />}
              </button>
            ))}
            <div className="w-full h-px bg-slate-800 my-2 hidden lg:block" />
            {['#3b82f6', '#10b981', '#f59e0b', '#ef4444', '#ffffff'].map(c => (
              <button key={c} onClick={() => setColor(c)} className={`w-8 h-8 rounded-full border-2 ${color === c ? 'border-white scale-110' : 'border-transparent'}`} style={{ backgroundColor: c }} />
            ))}
         </div>

         <div className="flex-1 bg-slate-900 rounded-[3rem] border border-slate-800 p-8 flex flex-col shadow-2xl relative overflow-hidden">
            <div className="flex-1 bg-[#0a0f1d] rounded-[2rem] shadow-inner border border-white/5 overflow-hidden relative cursor-crosshair">
               <canvas 
                ref={canvasRef} width={1600} height={1200}
                onMouseDown={startDrawing} onMouseMove={draw} onMouseUp={stopDrawing} onMouseLeave={stopDrawing}
                className="w-full h-full object-contain"
               />
               {isGenerating && (
                 <div className="absolute inset-0 bg-slate-950/60 backdrop-blur-md flex flex-col items-center justify-center">
                    <div className="w-16 h-16 border-4 border-indigo-500 border-t-transparent rounded-full animate-spin mb-4" />
                    <p className="text-indigo-400 font-black uppercase text-xs animate-pulse">Synthesizing 3D Character...</p>
                 </div>
               )}
            </div>

            <div className="mt-8 flex space-x-4">
              <input 
                value={prompt} onChange={(e) => setPrompt(e.target.value)}
                placeholder="Sketch prompt: 'A robotic warrior monk'..." 
                className="flex-1 bg-slate-800 border border-slate-700 rounded-3xl py-4.5 px-6 focus:ring-4 focus:ring-emerald-500/20 text-slate-100 font-medium"
              />
              <button onClick={() => handleAIGenerate('2d')} className="p-3.5 bg-emerald-600 rounded-2xl text-white shadow-xl shadow-emerald-600/30">
                <Wand2 className="w-6 h-6" />
              </button>
            </div>
         </div>
      </div>
    </div>
