type PreviewFormat = 'landscape' | 'portrait' | 'square';
type AdCategory = 'E-Commerce' | 'Industry' | 'Restaurant';

const AdBuilder: React.FC<AdBuilderProps> = ({ onSave }) => {
  const [selectedCategory, setSelectedCategory] = useState<AdCategory>('E-Commerce');
  const [theme, setTheme] = useState("");
  const [format, setFormat] = useState<PreviewFormat>('square');
  const [isGenerating, setIsGenerating] = useState(false);
  const [isMediaGenerating, setIsMediaGenerating] = useState(false);
  const [showSaved, setShowSaved] = useState(false);

  const [campaign, setCampaign] = useState({
    headline: "Your Brand, Redefined",
    description: "Experience professional creative excellence.",
    ctas: ["Shop Now", "Learn More"],
    image: "https://picsum.photos/seed/ad-hero/800/800",
    audioUrl: null as string | null,
    videoUrl: null as string | null
  });

  const handleGenerateCampaign = async () => {
    if (!theme) return;
    setIsGenerating(true);
    const gemini = GeminiService.getInstance();
    try {
      const imgAspect = format === 'landscape' ? '16:9' : format === 'portrait' ? '9:16' : '1:1';
      const [campaignData, visual] = await Promise.all([
        gemini.generateAdCampaign(theme, selectedCategory),
        gemini.generateImage(`Professional high-end ${selectedCategory} ad visual for: ${theme}`, imgAspect)
      ]);
      setCampaign(prev => ({ ...prev, ...campaignData, image: visual || prev.image }));
    } finally {
      setIsGenerating(false);
    }
  };

  const handleSynthesizeMedia = async (type: 'audio' | 'video') => {
    setIsMediaGenerating(true);
    const gemini = GeminiService.getInstance();
    try {
      if (type === 'audio') {
        const audio = await gemini.generateSpeech(`${campaign.headline}. ${campaign.description}`);
        setCampaign(prev => ({ ...prev, audioUrl: audio }));
      } else {
        // Simulating video generation request via Gemini Veo
        const video = "https://media.giphy.com/media/v1.Y2lkPTc5MGI3NjExNHJqZ3R4Z3R4Z3R4Z3R4Z3R4Z3R4Z3R4Z3R4Z3R4Z3R4Z3R4Z3R4JmVwPXYxX2ludGVybmFsX2dpZl9ieV9pZCZjdD1n/3o7TKMGpxxS0Zz9E0E/giphy.mp4";
