        </div>
        <div className="flex space-x-3">
          <button onClick={handleSaveFile} className="px-6 py-3 bg-slate-800 border border-slate-700 rounded-2xl text-[10px] font-black uppercase text-slate-100"><Download className="w-4 h-4 mr-2" /> Save File</button>
          <button onClick={() => onSave({ id: Date.now().toString(), name: campaign.headline, type: StudioMode.AD_BUILDER, thumbnail: campaign.image, updatedAt: Date.now(), status: 'draft', data: campaign })} className="px-8 py-3 bg-blue-600 rounded-2xl text-[10px] font-black uppercase text-white shadow-xl">Sync Cloud</button>
        </div>
