            <div className="flex items-center space-x-2 bg-slate-950 p-1 rounded-xl mb-6">
              {['docs', 'esign'].map(t => (
                <button 
                  key={t}
                  onClick={() => setActiveTab(t as any)}
                  className={`flex-1 py-2 rounded-lg text-[9px] font-black uppercase tracking-widest transition-all ${activeTab === t ? 'bg-indigo-600 text-white' : 'text-slate-500'}`}
                >
                  {t === 'docs' ? <FileText className="w-3.5 h-3.5 mx-auto" /> : <PenTool className="w-3.5 h-3.5 mx-auto" />}
                </button>
              ))}
            </div>

            <h3 className="text-[10px] font-black text-slate-500 uppercase tracking-widest mb-4 flex items-center">
              <Folder className="w-4 h-4 mr-3 text-indigo-400" /> Recent Work
            </h3>
            <div className="space-y-2 max-h-48 overflow-y-auto custom-scrollbar">
              {savedDocs.map(doc => (
                <button key={doc.id} onClick={() => { setActiveTab(doc.type as any); setDocContent(doc.content); setDocTitle(doc.title); }} className="w-full text-left p-3 bg-slate-800/40 hover:bg-slate-800 rounded-xl text-xs font-bold text-slate-400 hover:text-white truncate">
                  {doc.title}
                </button>
              ))}
            </div>
          </div>

          {activeTab === 'esign' && (
            <div className="bg-slate-900 border border-slate-800 rounded-[2rem] p-6 shadow-xl space-y-6">
               <h3 className="text-[10px] font-black text-slate-500 uppercase tracking-widest flex items-center">
                <ShieldCheck className="w-4 h-4 mr-3 text-emerald-400" /> Digital Identity
              </h3>
              <button onClick={() => sigInputRef.current?.click()} className="w-full py-4 border-2 border-dashed border-slate-700 rounded-2xl flex flex-col items-center justify-center group hover:border-indigo-500 transition-all">
                {signature ? <img src={signature} className="h-12 object-contain" alt="Signature" /> : (
                  <>
                    <PenTool className="w-6 h-6 text-slate-600 mb-2 group-hover:text-indigo-400" />
                    <span className="text-[10px] font-black uppercase text-slate-500">Add Signature</span>
                  </>
                )}
              </button>
              <input type="file" ref={sigInputRef} className="hidden" accept="image/*" onChange={handleSigUpload} />
              <button onClick={() => setIsSigned(true)} disabled={!signature} className="w-full py-4 bg-emerald-600 hover:bg-emerald-500 disabled:opacity-50 text-white rounded-2xl text-[10px] font-black uppercase">Apply e-Sign</button>
              <button onClick={() => { setSignature(null); setIsSigned(false); }} className="w-full py-2 text-slate-500 text-[9px] font-bold uppercase hover:text-white"><RotateCcw className="w-3 h-3 inline mr-1" /> Recheck & Clear</button>
            </div>
          )}
        </div>

        <div className="flex-1 bg-white rounded-[2.5rem] border border-slate-200 shadow-2xl overflow-hidden flex flex-col">
          <div className="h-14 bg-slate-50 border-b border-slate-200 flex items-center px-8 justify-between">
             <div className="flex items-center space-x-4">
               <FileEdit className="w-4 h-4 text-slate-400" />
               <input value={docTitle} onChange={e => setDocTitle(e.target.value)} className="bg-transparent border-none text-slate-800 text-sm font-black uppercase focus:outline-none" />
             </div>
             {activeTab === 'esign' && (
               <div className="flex items-center px-3 py-1 bg-emerald-500/10 text-emerald-600 rounded-full text-[9px] font-black uppercase">
                 <ShieldCheck className="w-3 h-3 mr-1" /> Verified Secure
               </div>
             )}
          </div>

          <div className="flex-1 bg-slate-100 p-12 overflow-y-auto">
             <div className="max-w-[816px] mx-auto bg-white min-h-[1000px] shadow-lg p-20 relative">
                <textarea 
                  value={docContent}
                  onChange={e => setDocContent(e.target.value)}
                  placeholder="Start writing or paste your contract..."
                  className="w-full h-full min-h-[800px] border-none focus:outline-none text-slate-800 text-lg leading-relaxed font-serif bg-transparent"
                />

                {activeTab === 'esign' && isSigned && signature && (
                  <div className="absolute bottom-40 right-40 p-4 border-2 border-emerald-500/30 rounded-xl bg-emerald-50/50 animate-in zoom-in-95">
                    <img src={signature} className="h-16 object-contain" alt="" />
                    <p className="text-[8px] font-black uppercase text-emerald-600 mt-2 text-center">Digitally Signed By {user.name}</p>
