             <button onClick={() => handleDuplicate(selectedLayer.id)} className="flex items-center justify-center py-4 bg-slate-800 rounded-2xl text-[10px] font-black uppercase text-slate-400 border border-slate-700 hover:text-white"><Copy className="w-3.5 h-3.5 mr-2" /> Duplicate</button>
             <button onClick={() => toggleLayerLock(selectedLayer.id)} className="flex items-center justify-center py-4 bg-slate-800 rounded-2xl text-[10px] font-black uppercase text-slate-400 border border-slate-700 hover:text-white">
               {selectedLayer.locked ? <Lock className="w-3.5 h-3.5 mr-2 text-rose-500" /> : <Unlock className="w-3.5 h-3.5 mr-2" />}
               {selectedLayer.locked ? 'Unlock' : 'Lock'}
             </button>
             <button onClick={() => updateLayer(selectedLayer.id, { opacity: 0 })} className="flex items-center justify-center py-4 bg-slate-800 rounded-2xl text-[10px] font-black uppercase text-rose-500 border border-slate-700"><Trash2 className="w-3.5 h-3.5 mr-2" /> Remove BG</button>
             <button onClick={() => uploadInputRef.current?.click()} className="flex items-center justify-center py-4 bg-slate-800 rounded-2xl text-[10px] font-black uppercase text-blue-400 border border-slate-700"><CornerUpRight className="w-3.5 h-3.5 mr-2" /> Replace</button>
          </div>
        </div>
      </div>

      <div className="h-48 bg-slate-900 rounded-[2.5rem] border border-slate-800 p-6 shadow-2xl flex flex-col overflow-hidden">
        <div className="flex items-center justify-between mb-4">
          <div className="flex items-center space-x-6">
            <div className="flex items-center space-x-2 text-[10px] font-black text-slate-500 uppercase"><Layers className="w-3 h-3" /> Professional Timeline</div>
            <div className="text-[10px] font-mono text-blue-400">00:00:{currentTime.toString().padStart(2, '0')}</div>
          </div>
          <div className="flex space-x-2">
            <button onClick={handlePaste} className="p-2 text-slate-500 hover:text-white"><Copy className="w-4 h-4" /></button>
            <button className="p-2 text-slate-500 hover:text-white"><Scissors className="w-4 h-4" /></button>
          </div>
        </div>
        <div className="flex-1 space-y-3 overflow-y-auto pr-2 custom-scrollbar">
           {layers.map(layer => (
             <div 
              key={layer.id} 
              onClick={() => setSelectedLayerIds(new Set([layer.id]))}
