                   {layer.type === 'audio' && <Volume2 className="w-3 h-3 text-indigo-400" />}
                </div>
             </div>
           ))}
        </div>
      </div>
    </div>
  );
};

export default VideoEditor;

import React, { useState, useEffect, useRef } from 'react';
import { 
  FileSpreadsheet, FileText, Save, Printer, RotateCcw, ShieldCheck, 
  PenTool, FileEdit, Folder, Upload, FileType, RefreshCw, Download, 
  CheckCircle, FileImage, FileOutput
} from 'lucide-react';
import { UserProfile, StudioMode, Project } from '../types';

interface OfficeSuiteProps {
  user: UserProfile;
  onSave: (project: Project) => void;
}

interface SavedDoc {
  id: string;
  title: string;
  content: string;
  type: 'docs' | 'esign' | 'converter';
  updatedAt: number;
  signature?: string;
}

const OfficeSuite: React.FC<OfficeSuiteProps> = ({ user, onSave }) => {
  const [activeTab, setActiveTab] = useState<'docs' | 'esign' | 'converter'>('docs');
  const [docContent, setDocContent] = useState("");
  const [docTitle, setDocTitle] = useState("Untitled Document");
  const [isSaving, setIsSaving] = useState(false);
  const [signature, setSignature] = useState<string | null>(null);
  const [isSigned, setIsSigned] = useState(false);

  // Converter State
  const [isConverting, setIsConverting] = useState(false);
  const [convertedFile, setConvertedFile] = useState<string | null>(null);
  const [convertProgress, setConvertProgress] = useState(0);

  const [savedDocs, setSavedDocs] = useState<SavedDoc[]>(() => {
    const saved = localStorage.getItem('lumina_office_docs');
    return saved ? JSON.parse(saved) : [];
  });

  const sigInputRef = useRef<HTMLInputElement>(null);
  const convertInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    localStorage.setItem('lumina_office_docs', JSON.stringify(savedDocs));
  }, [savedDocs]);

  const handleSave = () => {
    setIsSaving(true);
    const newDoc: SavedDoc = {
      id: Date.now().toString(),
      title: docTitle,
      content: docContent,
      type: activeTab,
      updatedAt: Date.now(),
      signature: signature || undefined
    };
    setSavedDocs(prev => [newDoc, ...prev.filter(d => d.title !== docTitle)].slice(0, 10));
    onSave({
      id: newDoc.id,
      name: docTitle,
      type: StudioMode.OFFICE,
      thumbnail: 'https://images.unsplash.com/photo-1517842645767-c639042777db?auto=format&fit=crop&q=80&w=300&h=200',
      updatedAt: Date.now(),
      status: 'draft',
      data: { content: docContent, type: activeTab, isSigned, signature }
    });
    setTimeout(() => setIsSaving(false), 800);
  };

  const handleConversion = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      setIsConverting(true);
      setConvertProgress(0);
      const interval = setInterval(() => {
        setConvertProgress(p => {
          if (p >= 100) {
            clearInterval(interval);
            setConvertedFile("https://picsum.photos/seed/converted/1200/1600");
            setIsConverting(false);
            return 100;
          }
          return p + 5;
        });
      }, 100);
    }
  };

  return (
    <div className="max-w-7xl mx-auto space-y-8 animate-in fade-in duration-700 pb-12">
      <div className="flex flex-col md:flex-row md:items-end justify-between gap-4">
        <div className="flex items-center space-x-6">
          <div className="p-4 bg-indigo-600/10 rounded-2xl border border-indigo-500/20 text-indigo-400">
            <FileSpreadsheet className="w-8 h-8" />
          </div>
          <div>
            <h2 className="text-3xl font-black tracking-tight uppercase">Office Suite Master</h2>
            <p className="text-slate-400 mt-1 font-medium">Professional document processing and conversion.</p>
          </div>
        </div>
        <div className="flex space-x-3">
          <button onClick={() => window.print()} className="px-5 py-3 bg-slate-800 hover:bg-slate-700 rounded-2xl text-[10px] font-black uppercase text-slate-100 border border-slate-700"><Printer className="w-4 h-4 mr-2" /> Print</button>
          <button onClick={handleSave} className="px-8 py-3 bg-indigo-600 hover:bg-indigo-500 text-white rounded-2xl text-[10px] font-black uppercase tracking-widest shadow-xl flex items-center">
            {isSaving ? <RefreshCw className="w-4 h-4 mr-2 animate-spin" /> : <Save className="w-4 h-4 mr-2" />}
            Sync Cloud
          </button>
        </div>
      </div>

      <div className="flex flex-col lg:flex-row gap-8 min-h-[75vh]">
        <div className="lg:w-80 space-y-6">
          <div className="bg-slate-900 border border-slate-800 rounded-[2rem] p-6 shadow-xl">
            <div className="flex items-center space-x-2 bg-slate-950 p-1 rounded-xl mb-6">
              {['docs', 'esign', 'converter'].map(t => (
                <button 
                  key={t}
                  onClick={() => setActiveTab(t as any)}
                  className={`flex-1 py-2 rounded-lg text-[8px] font-black uppercase tracking-widest transition-all ${activeTab === t ? 'bg-indigo-600 text-white' : 'text-slate-500'}`}
                >
                  {t === 'docs' ? <FileText className="w-3.5 h-3.5 mx-auto" /> : t === 'esign' ? <PenTool className="w-3.5 h-3.5 mx-auto" /> : <FileType className="w-3.5 h-3.5 mx-auto" />}
                </button>
              ))}
            </div>

            <h3 className="text-[10px] font-black text-slate-500 uppercase tracking-widest mb-4 flex items-center">
              <Folder className="w-4 h-4 mr-3 text-indigo-400" /> Recent
            </h3>
            <div className="space-y-2 max-h-48 overflow-y-auto custom-scrollbar">
              {savedDocs.filter(d => d.type === activeTab).map(doc => (
                <button key={doc.id} onClick={() => { setDocContent(doc.content); setDocTitle(doc.title); }} className="w-full text-left p-3 bg-slate-800/40 hover:bg-slate-800 rounded-xl text-xs font-bold text-slate-400 hover:text-white truncate">
                  {doc.title}
                </button>
              ))}
            </div>
          </div>

          {activeTab === 'esign' && (
            <div className="bg-slate-900 border border-slate-800 rounded-[2rem] p-6 shadow-xl space-y-4">
              <h3 className="text-[10px] font-black text-slate-500 uppercase tracking-widest flex items-center"><ShieldCheck className="w-4 h-4 mr-3 text-emerald-400" /> Secure Sign</h3>
              <button onClick={() => sigInputRef.current?.click()} className="w-full py-8 border-2 border-dashed border-slate-700 rounded-2xl flex flex-col items-center justify-center hover:border-indigo-500 transition-all">
                {signature ? <img src={signature} className="h-12 object-contain" alt="" /> : <PenTool className="w-6 h-6 text-slate-600" />}
              </button>
              <input type="file" ref={sigInputRef} className="hidden" accept="image/*" onChange={(e) => {
                 const file = e.target.files?.[0];
                 if (file) {
                   const reader = new FileReader();
                   reader.onload = (ev) => setSignature(ev.target?.result as string);
                   reader.readAsDataURL(file);
                 }
              }} />
              <button onClick={() => setIsSigned(true)} disabled={!signature} className="w-full py-4 bg-emerald-600 rounded-2xl text-[10px] font-black uppercase text-white shadow-lg disabled:opacity-50">Apply e-Sign</button>
            </div>
          )}

          {activeTab === 'converter' && (
            <div className="bg-slate-900 border border-slate-800 rounded-[2.5rem] p-8 shadow-xl space-y-6">
              <h3 className="text-[10px] font-black text-slate-500 uppercase tracking-widest flex items-center"><FileType className="w-4 h-4 mr-3 text-blue-400" /> File Converter</h3>
              <div 
                onClick={() => convertInputRef.current?.click()}
                className="w-full h-40 border-2 border-dashed border-slate-800 hover:border-blue-500 rounded-3xl flex flex-col items-center justify-center cursor-pointer transition-all bg-slate-950/20 group"
              >
                <Upload className="w-8 h-8 text-slate-600 mb-3 group-hover:text-blue-500" />
                <p className="text-[10px] font-black text-slate-500 uppercase">Upload PDF / DOCX</p>
              </div>
              <input type="file" ref={convertInputRef} className="hidden" onChange={handleConversion} accept=".pdf,.docx" />

              {isConverting && (
                <div className="space-y-3">
                  <div className="flex justify-between text-[9px] font-black uppercase"><span className="text-blue-400">Processing...</span><span className="text-slate-500">{convertProgress}%</span></div>
                  <div className="h-1.5 bg-slate-800 rounded-full overflow-hidden"><div className="h-full bg-blue-600 transition-all" style={{ width: `${convertProgress}%` }} /></div>
                </div>
              )}

              {convertedFile && (
                <div className="p-4 bg-blue-600/10 border border-blue-500/20 rounded-2xl animate-in zoom-in-95">
                   <div className="flex items-center space-x-3 mb-4">
                      <CheckCircle className="w-4 h-4 text-emerald-400" />
                      <span className="text-[9px] font-black uppercase text-blue-400">PDF Converted to PNG</span>
                   </div>
                   <img src={convertedFile} className="w-full h-32 object-cover rounded-xl mb-4 border border-white/5" alt="" />
                   <button className="w-full py-3 bg-blue-600 text-white rounded-xl text-[10px] font-black uppercase tracking-widest flex items-center justify-center">
                     <Download className="w-3.5 h-3.5 mr-2" /> Download Result
                   </button>
                </div>
              )}
            </div>
          )}
        </div>

        <div className="flex-1 bg-white rounded-[2.5rem] border border-slate-200 shadow-2xl overflow-hidden flex flex-col">
          <div className="h-14 bg-slate-50 border-b border-slate-200 flex items-center px-8 justify-between">
             <div className="flex items-center space-x-4">
               <FileEdit className="w-4 h-4 text-slate-400" />
               <input value={docTitle} onChange={e => setDocTitle(e.target.value)} className="bg-transparent border-none text-slate-800 text-sm font-black uppercase focus:outline-none" />
             </div>
             <div className="flex items-center space-x-3">
               <span className="px-3 py-1 bg-indigo-500/10 text-indigo-600 rounded-full text-[9px] font-black uppercase tracking-widest">v2.4 Pro</span>
             </div>
          </div>

          <div className="flex-1 bg-slate-100 p-12 overflow-y-auto">
             <div className="max-w-[816px] mx-auto bg-white min-h-[1056px] shadow-lg p-20 relative">
                {activeTab === 'converter' && convertedFile ? (
                   <div className="w-full h-full flex items-center justify-center opacity-40"><FileImage className="w-32 h-32 text-slate-300" /></div>
                ) : (
                  <textarea 
                    value={docContent}
                    onChange={e => setDocContent(e.target.value)}
                    placeholder="Enter professional document text..."
                    className="w-full h-full min-h-[800px] border-none focus:outline-none text-slate-800 text-lg leading-relaxed font-serif bg-transparent"
                  />
                )}

                {activeTab === 'esign' && isSigned && signature && (
                  <div className="absolute bottom-40 right-20 p-4 border-2 border-emerald-500/30 rounded-xl bg-emerald-50/50 animate-in zoom-in-95">
                    <img src={signature} className="h-12 object-contain" alt="" />
                    <p className="text-[8px] font-black uppercase text-emerald-600 mt-2 text-center">Digitally Verified: {user.name}</p>
                  </div>
                )}
             </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default OfficeSuite;

import React, { useState, useRef, useEffect } from 'react';
import { 
  Play, Pause, SkipBack, SkipForward, Plus, Music, Type as TypeIcon, 
  Wand2, Download, Video, Trash2, Upload, Sparkles, CheckCircle,
  Sliders, Volume2, Layers, RefreshCw, Lock, Unlock,
  Copy, Square, Move, Maximize, Palette, Crop, CornerUpRight,
  Clipboard, Scissors, RotateCcw, Monitor, Smartphone, Layout
} from 'lucide-react';
import { GeminiService } from '../services/geminiService';
import { Project, StudioMode, TimelineLayer } from '../types';

interface VideoEditorProps {
  onSave: (project: Project) => void;
}

const VideoEditor: React.FC<VideoEditorProps> = ({ onSave }) => {
  const [isPlaying, setIsPlaying] = useState(false);
  const [currentTime, setCurrentTime] = useState(0);
  const [selectedLayerIds, setSelectedLayerIds] = useState<Set<string>>(new Set());
  const [layers, setLayers] = useState<TimelineLayer[]>([
    { id: '1', name: 'Main Visual', type: 'video', start: 0, duration: 100, content: 'https://picsum.photos/seed/pro-vid/1280/720', volume: 100, opacity: 100, scale: 1, borderRadius: 0, locked: false, animation: 'none' },
    { id: '2', name: 'Ambient Track', type: 'audio', start: 0, duration: 80, content: 'bg-music', volume: 80, locked: false },
  ]);
  const [aspectRatio, setAspectRatio] = useState<'16:9' | '9:16' | '1:1'>('16:9');
  const [canvasColor, setCanvasColor] = useState('#0f172a');
  const [isEnhancing, setIsEnhancing] = useState(false);
  const [showSaveToast, setShowSaveToast] = useState(false);
  const [clipboard, setClipboard] = useState<Partial<TimelineLayer> | null>(null);
  const uploadInputRef = useRef<HTMLInputElement>(null);

  // Active layer is the first one in the selection or the first layer overall
  const activeLayer = layers.find(l => selectedLayerIds.has(l.id)) || layers[0];

  const updateLayer = (id: string, updates: Partial<TimelineLayer>) => {
    setLayers(prev => prev.map(l => l.id === id ? { ...l, ...updates } : l));
  };

  const toggleSelection = (e: React.MouseEvent, id: string) => {
    if (e.metaKey || e.ctrlKey) {
      const next = new Set(selectedLayerIds);
      if (next.has(id)) next.delete(id);
      else next.add(id);
      setSelectedLayerIds(next);
    } else {
      setSelectedLayerIds(new Set([id]));
    }
  };

  const handleDuplicate = (id: string) => {
    const layer = layers.find(l => l.id === id);
    if (layer) {
      setLayers([...layers, { ...layer, id: Date.now().toString(), name: `${layer.name} (Duplicate)` }]);
    }
  };

  const handleCopy = () => {
    setClipboard({ 
      volume: activeLayer.volume, 
      opacity: activeLayer.opacity, 
      borderRadius: activeLayer.borderRadius, 
      scale: activeLayer.scale,
      animation: activeLayer.animation
    });
  };

  const handlePaste = () => {
    if (clipboard) {
      selectedLayerIds.forEach(id => updateLayer(id, clipboard));
    }
  };

  const handleEnhanceSpeech = async () => {
    setIsEnhancing(true);
    const gemini = GeminiService.getInstance();
    await gemini.refineText("Enhance the vocal clarity and reduce noise in the narration track.", 'formal');
    updateLayer(activeLayer.id, { name: 'Enhanced Audio Master' });
    setIsEnhancing(false);
  };

  const toggleLayerLock = (id: string) => {
    const layer = layers.find(l => l.id === id);
    if (layer) updateLayer(id, { locked: !layer.locked });
  };

  return (
    <div className="h-full flex flex-col space-y-4 animate-in fade-in duration-500 overflow-hidden relative">
      <input type="file" ref={uploadInputRef} className="hidden" accept="video/*,audio/*,image/*" onChange={(e) => {
        const file = e.target.files?.[0];
        if (file) setLayers([...layers, { id: Date.now().toString(), name: file.name, type: 'video', start: 0, duration: 50, content: URL.createObjectURL(file), volume: 100, locked: false, animation: 'none', scale: 1 }]);
      }} />

      {showSaveToast && (
        <div className="fixed top-20 right-10 bg-emerald-600 text-white px-8 py-4 rounded-2xl shadow-2xl z-[100] animate-in slide-in-from-right">
          <CheckCircle className="w-5 h-5 mr-3" />
          <span className="font-bold uppercase tracking-widest text-xs">Production Synced to Cloud</span>
        </div>
      )}

      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 mb-2">
        <div className="flex items-center space-x-4">
          <h2 className="text-xl font-black uppercase tracking-tight flex items-center">
            <Video className="w-6 h-6 mr-3 text-rose-500" /> Lumina Pro Cut
          </h2>
          <div className="flex bg-slate-900 border border-slate-800 rounded-xl p-1">
             <button onClick={() => setAspectRatio('16:9')} className={`px-3 py-1 text-[9px] font-black rounded-lg ${aspectRatio === '16:9' ? 'bg-blue-600 text-white' : 'text-slate-500'}`}><Monitor className="w-3 h-3" /></button>
             <button onClick={() => setAspectRatio('9:16')} className={`px-3 py-1 text-[9px] font-black rounded-lg ${aspectRatio === '9:16' ? 'bg-blue-600 text-white' : 'text-slate-500'}`}><Smartphone className="w-3 h-3" /></button>
             <button onClick={() => setAspectRatio('1:1')} className={`px-3 py-1 text-[9px] font-black rounded-lg ${aspectRatio === '1:1' ? 'bg-blue-600 text-white' : 'text-slate-500'}`}><Square className="w-3 h-3" /></button>
          </div>
        </div>
        <div className="flex items-center space-x-3">
          <button onClick={handleEnhanceSpeech} disabled={isEnhancing} className="flex items-center px-4 py-2.5 bg-indigo-600 rounded-xl text-[10px] font-black uppercase text-white shadow-lg transition-all active:scale-95">
            {isEnhancing ? <RefreshCw className="w-3.5 h-3.5 animate-spin mr-2" /> : <Sparkles className="w-3.5 h-3.5 mr-2" />}
            Enhance Speech
          </button>
          <button onClick={() => setShowSaveToast(true)} className="flex items-center px-6 py-2.5 bg-blue-600 hover:bg-blue-500 rounded-xl text-[10px] font-black uppercase text-white shadow-xl">
            <Download className="w-4 h-4 mr-2" /> Export MP4
          </button>
        </div>
      </div>

      <div className="flex-1 grid grid-cols-1 md:grid-cols-12 gap-6 min-h-0">
        <div className="md:col-span-8 flex flex-col min-h-0 bg-slate-900 rounded-[2.5rem] border border-slate-800 p-8 shadow-inner overflow-hidden">
          <div className="flex-1 rounded-[2rem] flex items-center justify-center relative overflow-hidden shadow-2xl border border-white/5 group" style={{ backgroundColor: canvasColor }}>
            <div className={`relative transition-all duration-500 flex items-center justify-center ${aspectRatio === '9:16' ? 'h-full aspect-[9/16]' : aspectRatio === '1:1' ? 'h-full aspect-square' : 'w-full aspect-video'}`}>
               <img 
                src={activeLayer.content} 
                style={{ 
                  filter: `opacity(${activeLayer.opacity}%)`,
                  borderRadius: `${activeLayer.borderRadius}px`,
                  transform: `scale(${activeLayer.scale})`,
                  objectFit: 'cover'
                }}
                className={`max-h-full max-w-full transition-all duration-700 ${activeLayer.animation === 'fade' ? 'animate-in fade-in' : activeLayer.animation === 'slide' ? 'animate-in slide-in-from-left' : activeLayer.animation === 'zoom' ? 'animate-in zoom-in' : ''}`}
               />
            </div>
            <div className="absolute bottom-8 flex items-center space-x-8 bg-slate-950/80 backdrop-blur-2xl px-10 py-4 rounded-full border border-white/10 opacity-0 group-hover:opacity-100 transition-all">
               <SkipBack className="w-5 h-5 text-slate-500 cursor-pointer" />
               <button onClick={() => setIsPlaying(!isPlaying)} className="w-12 h-12 bg-white rounded-full flex items-center justify-center text-slate-950">
                  {isPlaying ? <Pause /> : <Play className="ml-1" />}
               </button>
               <SkipForward className="w-5 h-5 text-slate-500 cursor-pointer" />
            </div>
          </div>
        </div>

        <div className="md:col-span-4 bg-slate-900 rounded-[2.5rem] border border-slate-800 p-8 space-y-6 overflow-y-auto shadow-2xl custom-scrollbar">
          <div className="flex items-center justify-between">
            <h3 className="text-[10px] font-black text-slate-500 uppercase tracking-widest flex items-center"><Sliders className="w-3.5 h-3.5 mr-2" /> Adjustments</h3>
            <div className="flex space-x-1">
               <button onClick={handleCopy} title="Copy Props" className="p-2 bg-slate-800 rounded-lg text-slate-400 hover:text-white"><Copy className="w-3.5 h-3.5" /></button>
               <button onClick={handlePaste} disabled={!clipboard} title="Paste Props" className="p-2 bg-slate-800 rounded-lg text-slate-400 hover:text-white disabled:opacity-30"><Clipboard className="w-3.5 h-3.5" /></button>
            </div>
          </div>

          <div className="space-y-6">
            {[
              { id: 'volume', label: 'Volume', icon: Volume2 },
              { id: 'opacity', label: 'Opacity', icon: Maximize },
              { id: 'borderRadius', label: 'Corners', icon: Crop, max: 200 },
              { id: 'scale', label: 'Resize', icon: Move, max: 3, step: 0.1 }
            ].map(adj => (
              <div key={adj.id} className="space-y-2">
                <div className="flex justify-between text-[9px] font-black text-slate-400 uppercase">
                  <span className="flex items-center"><adj.icon className="w-3 h-3 mr-2" /> {adj.label}</span>
                  <span>{activeLayer.locked ? '---' : (activeLayer as any)[adj.id]}</span>
                </div>
                <input 
