             <button onClick={() => uploadInputRef.current?.click()} className="flex items-center justify-center py-3 bg-slate-800 rounded-xl text-[10px] font-black uppercase text-blue-400 border border-slate-700"><CornerUpRight className="w-3 h-3 mr-2" /> Replace</button>
