import React, { useState, useRef } from 'react';
import { 
  ImageIcon, Layers, Wand2, Maximize, Contrast, Sun, RotateCcw,
  Upload, Save, Palette, Download, CheckCircle, FileUp, 
  Stamp, CreditCard, Layout, Sparkles, Image as ImgIcon, Type
} from 'lucide-react';
import { GeminiService } from '../services/geminiService';
import { Project, StudioMode } from '../types';

interface PhotoEditorProps {
  onSave: (project: Project) => void;
}

type PhotoMode = 'retouch' | 'logo' | 'card';

const PhotoEditor: React.FC<PhotoEditorProps> = ({ onSave }) => {
  const [activeMode, setActiveMode] = useState<PhotoMode>('retouch');
  const [image, setImage] = useState<string>("https://picsum.photos/seed/studio-pro/1200/800");
  const [isProcessing, setIsProcessing] = useState(false);
  const [instruction, setInstruction] = useState("");
  const [brandName, setBrandName] = useState("");
  const [showSavedToast, setShowSavedToast] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const logUsage = (action: string) => {
    const session = JSON.parse(localStorage.getItem('lumina_session') || '{}');
    const logs = JSON.parse(localStorage.getItem('lumina_logs') || '[]');
    const newLog = {
      id: Math.random().toString(36).substring(2, 9).toUpperCase(),
      timestamp: new Date().toISOString(),
      userEmail: session.email || 'guest@lumina.com',
      action,
      status: 'Success',
      ip: '127.0.0.1',
      product: StudioMode.PHOTO
    };
    localStorage.setItem('lumina_logs', JSON.stringify([newLog, ...logs].slice(0, 100)));
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const url = URL.createObjectURL(file);
      setImage(url);
      logUsage(`Imported Asset: ${file.name}`);
    }
  };

  const handleAIAction = async () => {
    setIsProcessing(true);
    const gemini = GeminiService.getInstance();
    let result = null;

    if (activeMode === 'retouch') {
      result = await gemini.editImage(image, instruction);
    } else if (activeMode === 'logo') {
      result = await gemini.generateImage(`Professional minimalist logo for brand "${brandName}". ${instruction}. Vector style, clean background, high resolution.`, "1:1");
    } else if (activeMode === 'card') {
      result = await gemini.generateImage(`Professional business card design for "${brandName}". ${instruction}. Clean layout, premium typography.`, "16:9");
    }

    if (result) {
      setImage(result);
      logUsage(`AI Synthesis (${activeMode}): ${instruction}`);
    }
    setIsProcessing(false);
    setInstruction("");
  };

  const handleSaveToCloud = () => {
    onSave({
      id: Date.now().toString(),
      name: `Lumina ${activeMode.toUpperCase()} ${new Date().toLocaleTimeString()}`,
      type: StudioMode.PHOTO,
      thumbnail: image,
      updatedAt: Date.now(),
      status: 'draft',
      data: { image, mode: activeMode }
    });
    logUsage(`Synced ${activeMode} to Cloud`);
    setShowSavedToast(true);
    setTimeout(() => setShowSavedToast(false), 3000);
  };

  return (
    <div className="h-full flex flex-col space-y-4 animate-in fade-in duration-500 max-w-7xl mx-auto pb-10">
      <input type="file" ref={fileInputRef} onChange={handleFileUpload} className="hidden" accept="image/*" />

      {showSavedToast && (
        <div className="fixed top-20 right-10 bg-emerald-500 text-white px-6 py-3 rounded-2xl shadow-2xl z-[100] flex items-center animate-in slide-in-from-right duration-300">
          <CheckCircle className="w-5 h-5 mr-3" />
          <span className="font-bold uppercase tracking-widest text-xs">Work Synced!</span>
        </div>
      )}

      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div className="flex items-center space-x-4">
          <div className="p-3 bg-cyan-500/10 rounded-2xl border border-cyan-500/20 text-cyan-400">
            <ImageIcon className="w-6 h-6" />
          </div>
          <div>
            <h2 className="text-2xl font-black uppercase tracking-tight">Photo Studio Pro</h2>
            <div className="flex space-x-4 mt-1">
              {[
                { id: 'retouch', label: 'Retouch', icon: Wand2 },
                { id: 'logo', label: 'Logo Maker', icon: Stamp },
                { id: 'card', label: 'Card Maker', icon: CreditCard }
              ].map(tab => (
                <button 
                  key={tab.id}
                  onClick={() => setActiveMode(tab.id as PhotoMode)}
                  className={`text-[9px] font-black uppercase tracking-widest transition-all flex items-center ${activeMode === tab.id ? 'text-cyan-400 border-b-2 border-cyan-500 pb-1' : 'text-slate-500 hover:text-white'}`}
                >
                  <tab.icon className="w-3 h-3 mr-2" /> {tab.label}
                </button>
              ))}
            </div>
          </div>
        </div>
        <div className="flex space-x-2">
          <button onClick={() => fileInputRef.current?.click()} className="flex items-center px-4 py-2 bg-slate-800 hover:bg-slate-700 rounded-xl text-xs font-bold uppercase tracking-widest border border-slate-700">
            <FileUp className="w-4 h-4 mr-2 text-cyan-400" /> {activeMode === 'retouch' ? 'Import' : 'Add Image'}
          </button>
          <button onClick={handleSaveToCloud} className="flex items-center px-6 py-2.5 bg-blue-600 hover:bg-blue-500 rounded-xl text-xs font-black uppercase tracking-widest shadow-xl transition-all">
            <Save className="w-4 h-4 mr-2" /> Sync Cloud
          </button>
        </div>
      </div>

      <div className="flex-1 flex flex-col lg:flex-row space-y-6 lg:space-y-0 lg:space-x-6 min-h-0">
        <div className="flex-1 bg-slate-900 rounded-[2.5rem] border border-slate-800 p-8 flex flex-col shadow-inner relative overflow-hidden">
          <div className="flex-1 bg-black/40 rounded-[2rem] flex items-center justify-center relative overflow-hidden border border-white/5">
            <img 
              src={image} 
              alt="Studio Canvas" 
              className={`max-h-full max-w-full object-contain transition-all duration-700 shadow-2xl ${isProcessing ? 'blur-md scale-95 opacity-50' : 'scale-100'}`}
            />
            {isProcessing && (
              <div className="absolute inset-0 flex flex-col items-center justify-center bg-black/20 backdrop-blur-sm z-10">
                <div className="w-16 h-16 border-4 border-cyan-500 border-t-transparent rounded-full animate-spin mb-6" />
                <p className="text-cyan-400 font-black uppercase tracking-[0.2em] text-xs animate-pulse">Lumina Synthesizer Active...</p>
              </div>
            )}
          </div>

          <div className="mt-8 space-y-4">
             {(activeMode === 'logo' || activeMode === 'card') && (
               <div className="flex space-x-4">
                 <div className="flex-1 relative">
                    <label className="absolute -top-2 left-4 px-2 bg-slate-900 text-[8px] font-black uppercase text-slate-500">Brand / Name</label>
                    <input 
                      value={brandName}
                      onChange={(e) => setBrandName(e.target.value)}
                      placeholder="Enter brand or name..." 
                      className="w-full bg-slate-800 border border-slate-700 rounded-2xl py-4 px-6 focus:outline-none focus:ring-4 focus:ring-cyan-500/10 transition-all text-slate-100 font-medium"
                    />
                 </div>
               </div>
             )}
             <div className="flex space-x-4">
                <div className="flex-1 relative">
                    <label className="absolute -top-2 left-4 px-2 bg-slate-900 text-[8px] font-black uppercase text-slate-500">Style Instructions</label>
                    <input 
                      value={instruction}
                      onChange={(e) => setInstruction(e.target.value)}
                      placeholder={activeMode === 'retouch' ? "Describe retouching: 'Change hair to blue', 'Add cinematic lighting'..." : "Describe style: 'Minimalist tech style', 'Elegant floral', 'Vintage'..."} 
                      className="w-full bg-slate-800 border border-slate-700 rounded-2xl py-4.5 px-6 focus:outline-none focus:ring-4 focus:ring-cyan-500/10 transition-all text-slate-100 font-medium"
                    />
                </div>
                <button 
                  onClick={handleAIAction}
                  disabled={isProcessing || (!instruction && activeMode === 'retouch') || (!brandName && (activeMode === 'logo' || activeMode === 'card'))}
                  className="px-8 bg-cyan-600 rounded-2xl text-white disabled:opacity-50 hover:scale-105 active:scale-95 transition-all shadow-lg flex items-center justify-center font-black uppercase text-[10px] tracking-widest"
                >
                  <Sparkles className="w-4 h-4 mr-2" /> {activeMode === 'retouch' ? 'Retouch' : 'Generate'}
                </button>
             </div>
          </div>
        </div>

        <div className="w-full lg:w-80 bg-slate-900 rounded-[2.5rem] border border-slate-800 p-8 space-y-8 overflow-y-auto custom-scrollbar">
          <div>
            <h3 className="text-[10px] font-black text-slate-500 uppercase tracking-widest mb-6 flex items-center"><Palette className="w-3.5 h-3.5 mr-2" /> Studio Controls</h3>
            <div className="space-y-6">
              {[
                { icon: Sun, label: 'Exposure', color: 'text-amber-400' },
                { icon: Contrast, label: 'Clarity', color: 'text-blue-400' },
                { icon: Maximize, label: 'Vibrance', color: 'text-rose-400' }
              ].map((adj, i) => (
                <div key={i} className="space-y-3">
                  <div className="flex justify-between text-[9px] font-black uppercase tracking-widest">
                    <span className={`flex items-center ${adj.color}`}><adj.icon className="w-3.5 h-3.5 mr-2" /> {adj.label}</span>
                    <span className="text-slate-500">Normal</span>
                  </div>
                  <input type="range" className="w-full accent-cyan-500 h-1 bg-slate-800 rounded-full appearance-none cursor-pointer" />
                </div>
              ))}
            </div>
          </div>

          <div className="space-y-3">
             <h3 className="text-[10px] font-black text-slate-500 uppercase tracking-widest mb-4 flex items-center"><Layout className="w-3.5 h-3.5 mr-2" /> Templates</h3>
             <div className="grid grid-cols-2 gap-3">
                {[1, 2, 3, 4].map(i => (
