                <RotateCcw className="w-4 h-4 mr-3 text-slate-500" /> Reset Canvas
             </button>
             <button onClick={() => {
                const link = document.createElement('a');
                link.href = image;
                link.download = `lumina-${activeMode}-${Date.now()}.png`;
                link.click();
             }} className="w-full flex items-center justify-center py-4 bg-slate-950 rounded-2xl text-[10px] font-black uppercase tracking-[0.2em] transition-all text-cyan-400 border border-cyan-500/20">
                <Download className="w-4 h-4 mr-3" /> Download Final
             </button>
          </div>
        </div>
      </div>
    </div>
  );
};

