import React, { useState, useEffect, useMemo } from 'react';
import { 
  ShieldAlert, 
  Users, 
  Activity, 
  Search, 
  CheckCircle, 
  RefreshCw, 
  ShieldCheck,
  Trash2,
  DollarSign,
  History,
  CreditCard,
  UserCheck,
  UserMinus,
  Coins,
  ArrowUpCircle,
  Video,
  ImageIcon,
  Paintbrush,
  Megaphone,
  BookOpen,
  FileText,
  Settings,
  Globe,
  Server,
  Terminal,
  Copy,
  ChevronDown
} from 'lucide-react';
import { SubscriptionTier, UserProfile, StudioMode } from '../types';

type AdminTab = 'master' | 'history' | 'transactions' | 'system';

interface AuditLog {
  id: string;
  timestamp: string;
  userEmail: string;
  action: string;
  status: 'Success' | 'Warning' | 'Critical';
  ip: string;
  product?: StudioMode;
}

interface Transaction {
  id: string;
  timestamp: string;
  userEmail: string;
  plan: SubscriptionTier;
  amount: number;
  status: 'Completed' | 'Refunded' | 'Pending';
}

interface StoredUser extends UserProfile {
  password?: string;
  signupDate?: string;
  lastActive?: string;
}

const AdminPanel: React.FC = () => {
  const [activeTab, setActiveTab] = useState<AdminTab>('master');
  const [isRefreshing, setIsRefreshing] = useState(false);
  const [searchQuery, setSearchQuery] = useState('');
  const [showCreditModal, setShowCreditModal] = useState<{email: string, current: number} | null>(null);
  const [creditAmount, setCreditAmount] = useState<number>(100);
  const [showToast, setShowToast] = useState<{show: boolean, msg: string}>({show: false, msg: ''});

  const [users, setUsers] = useState<StoredUser[]>([]);
  const [logs, setLogs] = useState<AuditLog[]>([]);
  const [transactions, setTransactions] = useState<Transaction[]>([]);

  const loadAdminData = () => {
    setIsRefreshing(true);
    const storedUsers = JSON.parse(localStorage.getItem('lumina_users') || '[]');
    const storedLogs = JSON.parse(localStorage.getItem('lumina_logs') || '[]');
    const storedTransactions = JSON.parse(localStorage.getItem('lumina_transactions') || '[]');

    setUsers(storedUsers);
    setLogs(storedLogs.sort((a: any, b: any) => new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime()));
    setTransactions(storedTransactions.sort((a: any, b: any) => new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime()));

    setTimeout(() => setIsRefreshing(false), 600);
  };

  useEffect(() => {
    loadAdminData();
  }, []);

  const stats = useMemo(() => {
    const totalRev = transactions.reduce((acc, curr) => acc + (curr.status === 'Completed' ? curr.amount : 0), 0);
    return [
      { label: 'Total Revenue', val: `₹${totalRev.toLocaleString()}`, change: '+12%', icon: DollarSign, color: 'text-emerald-400' },
      { label: 'Registered Nodes', val: users.length.toString(), change: '+5%', icon: Users, color: 'text-blue-400' },
      { label: 'System Logs', val: logs.length.toString(), change: '+22%', icon: History, color: 'text-rose-400' },
      { label: 'Product Events', val: logs.filter(l => l.product).length.toString(), change: '+18%', icon: Activity, color: 'text-amber-400' },
    ];
  }, [users, logs, transactions]);

  const filteredUsers = users.filter(u => 
    u.name.toLowerCase().includes(searchQuery.toLowerCase()) || 
    u.email.toLowerCase().includes(searchQuery.toLowerCase())
  );

  const triggerToast = (msg: string) => {
    setShowToast({ show: true, msg });
    setTimeout(() => setShowToast({ show: false, msg: '' }), 3000);
  };

  const handleUpdatePlan = (email: string, newPlan: SubscriptionTier) => {
    const updated = users.map(u => {
      if (u.email === email) {
        return { ...u, plan: newPlan };
      }
      return u;
    });
    localStorage.setItem('lumina_users', JSON.stringify(updated));
    setUsers(updated);

    // Update session if it's the current user (edge case in local storage demo)
    const session = JSON.parse(localStorage.getItem('lumina_session') || '{}');
    if (session.email === email) {
      localStorage.setItem('lumina_session', JSON.stringify({ ...session, plan: newPlan }));
    }

    const newLog: AuditLog = {
      id: Math.random().toString(36).substring(2, 9).toUpperCase(),
      timestamp: new Date().toISOString(),
      userEmail: email,
      action: `Subscription Tier Migrated to ${newPlan}`,
      status: 'Success',
      ip: 'ADMIN-NODE'
    };
    const storedLogs = JSON.parse(localStorage.getItem('lumina_logs') || '[]');
    localStorage.setItem('lumina_logs', JSON.stringify([newLog, ...storedLogs].slice(0, 100)));
    setLogs([newLog, ...storedLogs]);

    triggerToast(`Node ${email} migrated to ${newPlan}`);
  };

  const handleAddCredits = () => {
    if (!showCreditModal) return;
    const updated = users.map(u => {
      if (u.email === showCreditModal.email) {
        return { ...u, credits: (u.credits || 0) + creditAmount };
      }
      return u;
    });
    localStorage.setItem('lumina_users', JSON.stringify(updated));
    setUsers(updated);

    const storedLogs = JSON.parse(localStorage.getItem('lumina_logs') || '[]');
    const newLog: AuditLog = {
      id: Math.random().toString(36).substring(2, 9).toUpperCase(),
      timestamp: new Date().toISOString(),
      userEmail: showCreditModal.email,
      action: `Admin Injected ${creditAmount} Credits`,
      status: 'Success',
      ip: 'ADMIN-NODE'
    };
    localStorage.setItem('lumina_logs', JSON.stringify([newLog, ...storedLogs].slice(-100)));
    setLogs([newLog, ...storedLogs]);

    setShowCreditModal(null);
    triggerToast(`${creditAmount} Credits Injected!`);
  };

  const getProductIcon = (mode?: StudioMode) => {
    switch (mode) {
      case StudioMode.VIDEO: return <Video className="w-4 h-4 text-rose-400" />;
      case StudioMode.PHOTO: return <ImageIcon className="w-4 h-4 text-cyan-400" />;
      case StudioMode.PAINT: return <Paintbrush className="w-4 h-4 text-emerald-400" />;
      case StudioMode.AD_BUILDER: return <Megaphone className="w-4 h-4 text-amber-400" />;
      case StudioMode.AUDIOBOOK: return <BookOpen className="w-4 h-4 text-indigo-400" />;
      case StudioMode.OFFICE: return <FileText className="w-4 h-4 text-blue-400" />;
      default: return <Activity className="w-4 h-4 text-slate-500" />;
    }
  };

  const copyToClipboard = (text: string) => {
    navigator.clipboard.writeText(text);
    triggerToast("URL Copied to Clipboard");
  };

  const planOptions: SubscriptionTier[] = ['Individual', 'Creator', 'Studio', 'Enterprise'];

  return (
    <div className="max-w-7xl mx-auto space-y-8 animate-in fade-in duration-700 pb-12">

      {showToast.show && (
        <div className="fixed top-20 right-10 bg-indigo-600 text-white px-6 py-4 rounded-2xl shadow-2xl z-[110] flex items-center animate-in slide-in-from-right duration-300">
          <CheckCircle className="w-5 h-5 mr-3" />
          <span className="font-bold uppercase tracking-widest text-xs">{showToast.msg}</span>
        </div>
      )}

      {/* Credit Modal */}
      {showCreditModal && (
        <div className="fixed inset-0 z-[100] bg-slate-950/80 backdrop-blur-md flex items-center justify-center p-6 animate-in fade-in duration-200">
          <div className="w-full max-w-md bg-slate-900 border border-slate-800 rounded-[2.5rem] p-10 shadow-2xl">
            <h3 className="text-xl font-black uppercase mb-2">Inject Studio Credits</h3>
            <p className="text-slate-500 text-sm mb-8">Manually adjust account balance for {showCreditModal.email}</p>
            <div className="space-y-6">
              <div className="bg-slate-950 p-6 rounded-2xl border border-slate-800 text-center">
                <p className="text-[10px] font-black uppercase text-slate-600 mb-2 tracking-widest">Current Balance</p>
                <p className="text-3xl font-black text-amber-400">{showCreditModal.current}</p>
              </div>
              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-500 uppercase ml-1">Injection Amount</label>
                <input 
                  type="number" 
                  value={creditAmount}
                  onChange={e => setCreditAmount(Number(e.target.value))}
                  className="w-full bg-slate-800 border border-slate-700 rounded-xl p-4 text-xl font-black text-blue-400 focus:outline-none focus:ring-2 focus:ring-blue-500/50"
                />
              </div>
              <div className="flex gap-4">
                <button onClick={() => setShowCreditModal(null)} className="flex-1 py-4 bg-slate-800 rounded-xl text-xs font-black uppercase tracking-widest">Cancel</button>
                <button onClick={handleAddCredits} className="flex-1 py-4 bg-blue-600 rounded-xl text-xs font-black uppercase tracking-widest shadow-xl shadow-blue-600/20">Authorize Injection</button>
              </div>
            </div>
          </div>
        </div>
      )}

      <div className="flex flex-col md:flex-row md:items-end justify-between gap-6">
        <div>
          <h2 className="text-3xl font-black tracking-tight flex items-center uppercase">
            <ShieldAlert className="w-8 h-8 mr-4 text-rose-500" />
            Control Center
          </h2>
          <p className="text-slate-400 mt-2 font-medium">Monitoring revenue, node health, and product usage streams.</p>
        </div>
        <div className="flex items-center space-x-3">
          <button 
            onClick={loadAdminData}
            className={`p-3 bg-slate-900 border border-slate-800 rounded-2xl hover:bg-slate-800 transition-all ${isRefreshing ? 'animate-spin' : ''}`}
          >
            <RefreshCw className="w-5 h-5 text-slate-400" />
          </button>
          <div className="flex bg-slate-900 border border-slate-800 p-1.5 rounded-2xl shadow-inner">
            {[
