import React, { useState, useEffect } from 'react';
import { Search, Bell, Cloud, Settings, LogOut, Globe, ChevronDown, Terminal, ShieldAlert } from 'lucide-react';
import { useNavigate } from 'react-router-dom';
import { UserProfile } from '../types';
import { translations } from '../App';

interface HeaderProps {
  user: UserProfile;
  onLogout: () => void;
  setLanguage: (lang: 'en' | 'bn' | 'hi') => void;
  onElevate: () => void;
}

const Header: React.FC<HeaderProps> = ({ user, onLogout, setLanguage, onElevate }) => {
  const navigate = useNavigate();
  const [showLangMenu, setShowLangMenu] = useState(false);
  const [searchVal, setSearchVal] = useState("");
  const [isElevating, setIsElevating] = useState(false);
  const t = translations[user.language];

  const languages = [
    { code: 'en', label: 'English', flag: '🇺🇸' },
    { code: 'bn', label: 'বাংলা', flag: '🇧🇩' },
    { code: 'hi', label: 'हिन्दी', flag: '🇮🇳' }
  ];

  const handleSearch = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter') {
      // SECRET ADMIN PROTOCOL KEY
      if (searchVal.trim().toUpperCase() === 'LUMINA-SYS-ROOT') {
        setIsElevating(true);
        setSearchVal("");
        setTimeout(() => {
          onElevate();
          setIsElevating(false);
          navigate('/admin');
        }, 1200);
      }
    }
  };

  return (
    <header className="h-16 border-b border-slate-800 bg-slate-950/50 backdrop-blur-md flex items-center justify-between px-6 sticky top-0 z-40">
      <div className="flex-1 max-w-xl relative group">
        <Search className={`absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 transition-colors ${isElevating ? 'text-indigo-400 animate-pulse' : 'text-slate-500'}`} />
        <input 
          type="text" 
          value={searchVal}
          onChange={(e) => setSearchVal(e.target.value)}
          onKeyDown={handleSearch}
          placeholder={isElevating ? "EXECUTING ROOT PROTOCOL..." : "Search projects..."} 
          className={`w-full bg-slate-900 border rounded-full py-2.5 pl-12 pr-4 text-xs focus:outline-none transition-all ${
            isElevating 
            ? 'border-indigo-500 shadow-[0_0_20px_rgba(99,102,241,0.3)] text-indigo-400 font-black' 
            : 'border-slate-800 focus:border-blue-500/50 text-slate-100'
          }`}
        />
        {isElevating && (
          <div className="absolute right-4 top-1/2 -translate-y-1/2">
            <Terminal className="w-4 h-4 text-indigo-500 animate-bounce" />
          </div>
        )}
      </div>

      <div className="flex items-center space-x-4 ml-4">
        {user.role === 'Studio Admin' && (
          <div className="hidden md:flex items-center px-4 py-1.5 bg-rose-500/10 border border-rose-500/20 rounded-full text-[9px] font-black text-rose-500 uppercase tracking-[0.2em] animate-pulse">
            <ShieldAlert className="w-3 h-3 mr-2" />
            Root Active
          </div>
        )}

        <div className="relative">
          <button 
            onClick={() => setShowLangMenu(!showLangMenu)}
            className="flex items-center space-x-2 px-3 py-1.5 bg-slate-900 border border-slate-800 rounded-full text-[10px] font-black uppercase tracking-widest text-slate-400 hover:text-white transition-all"
          >
            <Globe className="w-3.5 h-3.5" />
            <span>{languages.find(l => l.code === user.language)?.label}</span>
            <ChevronDown className="w-3 h-3" />
          </button>

          {showLangMenu && (
            <div className="absolute top-full right-0 mt-2 w-40 bg-slate-900 border border-slate-800 rounded-2xl shadow-2xl p-2 animate-in fade-in zoom-in-95 duration-200">
              {languages.map(lang => (
                <button
                  key={lang.code}
                  onClick={() => {
                    setLanguage(lang.code as any);
                    setShowLangMenu(false);
                  }}
                  className={`w-full flex items-center space-x-3 p-2 rounded-xl text-xs font-bold transition-all ${user.language === lang.code ? 'bg-blue-600 text-white' : 'hover:bg-slate-800 text-slate-400'}`}
                >
                  <span>{lang.flag}</span>
                  <span>{lang.label}</span>
                </button>
              ))}
            </div>
          )}
        </div>

        <button className="p-2 text-slate-400 hover:text-slate-100 hover:bg-slate-800 rounded-lg transition-all relative group">
          <Bell className="w-5 h-5" />
          <span className="absolute top-2 right-2 w-2 h-2 bg-red-500 rounded-full border-2 border-slate-950"></span>
        </button>

        <div className="h-6 w-px bg-slate-800 mx-2" />

        <div className="flex items-center space-x-4">
          <div 
            onClick={() => navigate('/profile')}
            className="flex items-center space-x-3 cursor-pointer group"
          >
            <div className="text-right hidden sm:block">
              <p className="text-sm font-black group-hover:text-blue-400 transition-colors">{user.name}</p>
              <p className="text-[10px] text-slate-500 font-mono tracking-tighter uppercase">{user.plan} Account</p>
            </div>
            <div className={`w-10 h-10 rounded-full bg-slate-800 border-2 p-0.5 overflow-hidden transition-all group-hover:scale-105 shadow-lg ${user.role === 'Studio Admin' ? 'border-rose-500 shadow-rose-500/20' : 'border-blue-500 shadow-blue-500/20'}`}>
              <img src={user.avatar} alt="Avatar" className="w-full h-full rounded-full object-cover" />
            </div>
          </div>

          <button 
            onClick={onLogout}
            className="p-2 text-slate-500 hover:text-rose-500 hover:bg-rose-500/10 rounded-xl transition-all"
            title={t.logout}
          >
            <LogOut className="w-5 h-5" />
          </button>
        </div>
      </div>
    </header>
  );
};

export default Header;

