const App: React.FC = () => {
  const [activeMode, setActiveMode] = useState<StudioMode>(StudioMode.VIDEO);
  const [projects, setProjects] = useState<Project[]>([]);
  const [isSidebarOpen, setIsSidebarOpen] = useState(true);
  const [user, setUser] = useState<UserProfile | null>(() => {
    const saved = localStorage.getItem('lumina_session');
    return saved ? JSON.parse(saved) : null;
  });

  useEffect(() => {
    if (user && !user.isApproved) {
      const interval = setInterval(() => {
        const users = JSON.parse(localStorage.getItem('lumina_users') || '[]');
        const updatedUser = users.find((u: any) => u.email === user.email);
        if (updatedUser && updatedUser.isApproved) {
          const { password, ...userProfile } = updatedUser;
          setUser(userProfile);
          localStorage.setItem('lumina_session', JSON.stringify(userProfile));
        }
      }, 5000);
      return () => clearInterval(interval);
    }
  }, [user]);

  useEffect(() => {
    if (user) {
      localStorage.setItem('lumina_session', JSON.stringify(user));
      const saved = localStorage.getItem(`lumina_projects_${user.email}`);
      setProjects(saved ? JSON.parse(saved) : []);
    }
  }, [user]);

  const saveProject = (project: Project) => {
    if (!user) return;
    const updated = [project, ...projects.filter(p => p.id !== project.id)];
    setProjects(updated);
    localStorage.setItem(`lumina_projects_${user.email}`, JSON.stringify(updated));
  };

  const handleElevate = () => {
    if (!user) return;
    const elevatedUser = { ...user, role: 'Studio Admin' };
    setUser(elevatedUser);
    localStorage.setItem('lumina_session', JSON.stringify(elevatedUser));

    // Also update in master user list
    const users = JSON.parse(localStorage.getItem('lumina_users') || '[]');
    const updatedUsers = users.map((u: any) => u.email === user.email ? { ...u, role: 'Studio Admin', isApproved: true } : u);
    localStorage.setItem('lumina_users', JSON.stringify(updatedUsers));
  };

  if (!user) return <Auth onLogin={setUser} />;
  if (!user.isApproved) return (
    <div className="min-h-screen bg-slate-950 flex flex-col items-center justify-center p-6 text-center">
      <div className="w-full max-w-md bg-slate-900 border border-slate-800 p-12 rounded-[3rem] shadow-2xl">
        <Clock className="w-20 h-20 text-blue-500 animate-pulse mx-auto mb-8" />
        <h2 className="text-3xl font-black uppercase mb-4 text-white">Access Pending</h2>
        <p className="text-slate-400 mb-8">Your identity has been synthesized. Admin approval required.</p>
        <button onClick={() => setUser(null)} className="w-full py-4 bg-slate-800 rounded-2xl text-xs font-black uppercase tracking-widest text-white border border-slate-700">Log Out</button>
      </div>
    </div>
  );

  return (
    <HashRouter>
      <div className="flex h-screen bg-slate-950 text-slate-100 overflow-hidden">
        <Sidebar isOpen={isSidebarOpen} toggle={() => setIsSidebarOpen(!isSidebarOpen)} activeMode={activeMode} setActiveMode={setActiveMode} lang={user.language} isAdmin={user.role === 'Studio Admin'} />
        <div className="flex-1 flex flex-col min-w-0 h-full relative">
          <Header user={user} onLogout={() => setUser(null)} setLanguage={(l) => setUser({...user, language: l})} onElevate={handleElevate} />
          <main className="flex-1 overflow-auto p-4 md:p-6">
            <Routes>
              <Route path="/" element={<Dashboard projects={projects} setActiveMode={setActiveMode} user={user} />} />
              <Route path="/video" element={<VideoEditor onSave={saveProject} />} />
              <Route path="/photo" element={<PhotoEditor onSave={saveProject} />} />
              <Route path="/paint" element={<PaintStudio onSave={saveProject} />} />
              <Route path="/ads" element={<AdBuilder onSave={saveProject} />} />
              <Route path="/audiobook" element={<AudiobookStudio onSave={saveProject} />} />
              <Route path="/education" element={<EducationStudio />} />
              <Route path="/templates" element={<TemplatesGallery />} />
              <Route path="/admin" element={user.role === 'Studio Admin' ? <AdminPanel /> : <Navigate to="/" />} />
              <Route path="/profile" element={<UserProfilePage user={user} setUser={setUser} onLogout={() => setUser(null)} />} />
              <Route path="/storage" element={<CloudStorage projects={projects} />} />
              <Route path="/shop" element={<Shop user={user} />} />
              <Route path="/communication" element={<CommunicationStudio user={user} />} />
              <Route path="/office" element={<OfficeSuite user={user} onSave={saveProject} />} />
              <Route path="/support" element={<SupportCenter user={user} />} />
            </Routes>
          </main>
        </div>
      </div>
    </HashRouter>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { 
  User, 
  ShieldCheck, 
  Mail, 
  Lock, 
  Sparkles, 
  UserPlus, 
  LogIn, 
  Key,
  AlertCircle,
  Eye,
  EyeOff,
  CheckCircle2,
  ChevronLeft,
  RefreshCw,
  Info
} from 'lucide-react';
import { UserProfile, SubscriptionTier } from '../types';

interface AuthProps {
  onLogin: (user: UserProfile) => void;
}

interface StoredUser extends UserProfile {
  password: string;
}

const Auth: React.FC<AuthProps> = ({ onLogin }) => {
  const [authView, setAuthView] = useState<'login' | 'signup' | 'forgot'>('login');
  // Admin toggle is now internal/hidden from the main UI toggle
  const [isAdmin, setIsAdmin] = useState(false); 
  const [showPassword, setShowPassword] = useState(false);
  const [error, setError] = useState("");
  const [success, setSuccess] = useState("");
  const [isSubmitting, setIsSubmitting] = useState(false);

  const [formData, setFormData] = useState({
    name: '',
    email: '',
    password: ''
  });

  // Log activity helper
  const logActivity = (email: string, action: string, status: 'Success' | 'Warning' | 'Critical' = 'Success') => {
    const logs = JSON.parse(localStorage.getItem('lumina_logs') || '[]');
    const newLog = {
      id: Math.random().toString(36).substring(2, 9).toUpperCase(),
      timestamp: new Date().toISOString(),
      userEmail: email,
      action: action,
      status: status,
      ip: '127.0.0.1' 
    };
    localStorage.setItem('lumina_logs', JSON.stringify([...logs, newLog].slice(-100)));
  };

  useEffect(() => {
    const existingUsers = localStorage.getItem('lumina_users');
    if (!existingUsers) {
      const defaultUsers: StoredUser[] = [
        {
          name: 'Master Admin',
          role: 'Studio Admin',
          avatar: 'https://api.dicebear.com/7.x/avataaars/svg?seed=admin',
          email: 'admin@lumina.com',
          password: 'admin123',
          plan: 'Enterprise',
          credits: 99999,
          referralCode: 'ADMIN-001',
          referralCount: 0,
          facebookConnected: false,
          githubConnected: false,
          twitterConnected: false,
          language: 'en',
          studentVerificationStatus: 'verified',
          isApproved: true,
        }
      ];
      localStorage.setItem('lumina_users', JSON.stringify(defaultUsers));
    }
  }, []);

  const getStoredUsers = (): StoredUser[] => {
    const users = localStorage.getItem('lumina_users');
    return users ? JSON.parse(users) : [];
  };

  const handleAuth = (e: React.FormEvent) => {
    e.preventDefault();
    setError("");
    setSuccess("");
    setIsSubmitting(true);

    const users = getStoredUsers();

    setTimeout(() => {
      setIsSubmitting(false);

      if (authView === 'login') {
        const user = users.find(u => u.email.toLowerCase() === formData.email.toLowerCase() && u.password === formData.password);

        if (!user) {
          logActivity(formData.email, "Failed Login Attempt", "Warning");
          setError("Invalid email or password. Check your credentials.");
          return;
        }

        logActivity(formData.email, "Successful Login");
        const { password, ...userProfile } = user;
        localStorage.setItem('lumina_session', JSON.stringify(userProfile));
        onLogin(userProfile);

      } else if (authView === 'signup') {
        if (!formData.name || !formData.email || !formData.password) {
          setError("Fill in all fields to synthesize your identity.");
          return;
        }

        if (users.some(u => u.email.toLowerCase() === formData.email.toLowerCase())) {
          setError("Email already exists in the Lumina network.");
          return;
        }

        const newUser: StoredUser = {
          name: formData.name,
          role: 'Lead Creative', // Everyone signs up as creative initially
          avatar: `https://api.dicebear.com/7.x/avataaars/svg?seed=${formData.email}`,
          email: formData.email,
          password: formData.password,
          plan: 'Individual' as SubscriptionTier,
          credits: 500,
          referralCode: `LUMINA-${Math.random().toString(36).substring(7).toUpperCase()}`,
          referralCount: 0,
          facebookConnected: false,
          githubConnected: false,
          twitterConnected: false,
          language: 'en',
          studentVerificationStatus: 'none',
          isApproved: false, // Pending admin approval
        };

        const updatedUsers = [...users, newUser];
        localStorage.setItem('lumina_users', JSON.stringify(updatedUsers));

        logActivity(formData.email, "New Account Synthesized");
        setSuccess("Identity initialized! Access is pending Admin approval.");
        setAuthView('login');
        setFormData({ name: '', email: '', password: '' });

      } else if (authView === 'forgot') {
        const userExists = users.some(u => u.email.toLowerCase() === formData.email.toLowerCase());
        if (!userExists) {
          setError("Email not found in our creative registry.");
          return;
        }
        logActivity(formData.email, "Password Recovery Initiated");
        setSuccess("Recovery packet dispatched! Check your secure inbox.");
      }
    }, 800);
  };

  return (
    <div className="min-h-screen bg-slate-950 flex items-center justify-center p-6 relative overflow-hidden">
      <div className="absolute top-[-10%] left-[-10%] w-[40%] h-[40%] bg-blue-600/10 blur-[120px] rounded-full" />
      <div className="absolute bottom-[-10%] right-[-10%] w-[40%] h-[40%] bg-purple-600/10 blur-[120px] rounded-full" />

      <div className="w-full max-w-[1000px] grid grid-cols-1 lg:grid-cols-2 bg-slate-900 rounded-[3rem] border border-slate-800 shadow-2xl overflow-hidden animate-in zoom-in-95 duration-500">

        <div className={`hidden lg:flex flex-col justify-between p-12 bg-blue-900/20 border-r border-slate-800`}>
          <div>
            <div className="flex items-center space-x-3 mb-8">
              <div className="w-10 h-10 rounded-xl flex items-center justify-center shadow-lg bg-blue-600">
                <Sparkles className="w-6 h-6 text-white" />
              </div>
              <h1 className="text-2xl font-black tracking-widest uppercase">Lumina</h1>
            </div>
            <h2 className="text-4xl font-black leading-tight mb-6 animate-in slide-in-from-left duration-700">
              Synthesize Your Vision.
            </h2>
            <p className="text-slate-400 text-lg font-medium leading-relaxed opacity-70">
              Access 4K video editing, AI character paint, and professional ad building tools. Join thousands of creators in the most advanced studio environment.
            </p>
          </div>

          <div className="p-6 bg-slate-950/40 rounded-3xl border border-white/5 backdrop-blur-md">
            <div className="flex items-center space-x-3 mb-4">
              <Info className="w-4 h-4 text-blue-400" />
              <span className="text-[10px] font-black uppercase tracking-widest text-slate-400">Creative Hub</span>
            </div>
            <p className="text-[10px] font-mono text-slate-500">Lumina is an end-to-end creative workstation for professionals.</p>
          </div>
        </div>

        <div className="p-10 md:p-16 flex flex-col justify-center bg-slate-900/40 backdrop-blur-sm">
          <div className="mb-8">
            <h3 className="text-2xl font-black uppercase tracking-tight mb-2">
              {authView === 'login' && 'Welcome Back'}
              {authView === 'signup' && 'Create Identity'}
              {authView === 'forgot' && 'Identity Recovery'}
            </h3>
            <p className="text-slate-500 font-medium text-sm">
              {authView === 'login' && 'Sign in to access your creative workspace.'}
              {authView === 'signup' && 'Enter your details to begin your journey.'}
              {authView === 'forgot' && 'Reset your credentials via secure channel.'}
            </p>
          </div>

          <form onSubmit={handleAuth} className="space-y-5">
            {error && (
              <div className="p-4 bg-rose-500/10 border border-rose-500/20 rounded-2xl flex items-center text-rose-500 text-xs font-bold animate-in shake duration-300">
                <AlertCircle className="w-4 h-4 mr-3 shrink-0" />
                {error}
              </div>
            )}

            {success && (
              <div className="p-4 bg-emerald-500/10 border border-emerald-500/20 rounded-2xl flex items-center text-emerald-500 text-xs font-bold animate-in zoom-in-95 duration-300">
                <CheckCircle2 className="w-4 h-4 mr-3 shrink-0" />
                {success}
              </div>
            )}

            {authView === 'signup' && (
              <div className="space-y-2 group animate-in slide-in-from-top-2">
                <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1 group-focus-within:text-blue-500 transition-colors">Full Name</label>
                <div className="relative">
                  <User className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-600" />
                  <input 
                    type="text"
                    required
                    value={formData.name}
                    onChange={e => setFormData({...formData, name: e.target.value})}
                    placeholder="Enter your name"
                    className="w-full bg-slate-950 border border-slate-800 rounded-2xl py-4 pl-12 pr-4 focus:outline-none focus:ring-2 focus:ring-blue-500/50 transition-all text-slate-200"
                  />
                </div>
              </div>
            )}

            <div className="space-y-2 group">
              <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1 group-focus-within:text-blue-500 transition-colors">Work Email</label>
              <div className="relative">
                <Mail className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-600" />
                <input 
                  type="email"
                  required
                  value={formData.email}
                  onChange={e => setFormData({...formData, email: e.target.value})}
                  placeholder="name@studio.com"
                  className="w-full bg-slate-950 border border-slate-800 rounded-2xl py-4 pl-12 pr-4 focus:outline-none focus:ring-2 focus:ring-blue-500/50 transition-all text-slate-200"
                />
              </div>
            </div>

            {authView !== 'forgot' && (
              <div className="space-y-2 group animate-in slide-in-from-top-2">
                <div className="flex justify-between items-center ml-1">
                  <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest group-focus-within:text-blue-500 transition-colors">Secret Key</label>
                  {authView === 'login' && (
                    <button 
                      type="button" 
                      onClick={() => { setAuthView('forgot'); setError(""); setSuccess(""); }}
                      className="text-[9px] font-black text-slate-600 hover:text-blue-400 uppercase tracking-widest transition-all"
                    >
                      Forgot?
                    </button>
                  )}
                </div>
                <div className="relative">
                  <Lock className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-600" />
                  <input 
                    type={showPassword ? "text" : "password"}
                    required
                    value={formData.password}
                    onChange={e => setFormData({...formData, password: e.target.value})}
                    placeholder="••••••••"
                    className="w-full bg-slate-950 border border-slate-800 rounded-2xl py-4 pl-12 pr-12 focus:outline-none focus:ring-2 focus:ring-blue-500/50 transition-all text-slate-200"
                  />
                  <button 
                    type="button"
                    onClick={() => setShowPassword(!showPassword)}
                    className="absolute right-4 top-1/2 -translate-y-1/2 text-slate-600 hover:text-slate-400 transition-colors"
                  >
                    {showPassword ? <EyeOff className="w-4 h-4" /> : <Eye className="w-4 h-4" />}
                  </button>
                </div>
              </div>
            )}

            <button 
              type="submit"
              disabled={isSubmitting}
              className="w-full py-5 rounded-2xl font-black uppercase tracking-widest text-[11px] shadow-xl bg-blue-600 hover:bg-blue-500 shadow-blue-600/20 text-white flex items-center justify-center group transition-all transform active:scale-95 disabled:opacity-50"
            >
              {isSubmitting ? (
                <RefreshCw className="w-4 h-4 animate-spin" />
              ) : (
                <>
                  {authView === 'login' && <>Access Studio <LogIn className="w-4 h-4 ml-3 group-hover:translate-x-1 transition-transform" /></>}
                  {authView === 'signup' && <>Initialize Account <UserPlus className="w-4 h-4 ml-3 group-hover:translate-x-1 transition-transform" /></>}
                  {authView === 'forgot' && <>Recover Identity <RefreshCw className="w-4 h-4 ml-3 group-hover:rotate-180 transition-transform duration-500" /></>}
                </>
              )}
            </button>
          </form>

          <div className="mt-8 pt-8 border-t border-slate-800 flex flex-col items-center justify-center space-y-4">
            <button 
              onClick={() => { setAuthView(authView === 'login' ? 'signup' : 'login'); setError(""); setSuccess(""); }}
              className="text-xs font-black uppercase tracking-widest text-slate-500 hover:text-white transition-all flex items-center group"
            >
              {authView === 'login' ? "Don't have an identity? Create one" : "Already registered? Sign in"}
              <ArrowRight className="w-3 h-3 ml-2 group-hover:translate-x-1 transition-transform" />
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

