  });

  const uploadRef = useRef<HTMLInputElement>(null);

  const getAspectRatio = (type: AssetType): "1:1" | "16:9" | "9:16" => {
    switch(type) {
      case 'poster':
      case 'flyer':
        return "9:16";
      case 'web_banner':
        return "16:9";
      case 'business_card':
        return "16:9"; // Approximation for landscape card
      default:
        return "1:1";
    }
  };

  const getFormat = (type: AssetType): PreviewFormat => {
    switch(type) {
      case 'poster':
      case 'flyer':
        return 'portrait';
      case 'web_banner':
      case 'business_card':
      case 'certificate':
        return 'landscape';
