    { id: 'flyer', label: 'Flyer', icon: FileStack },
    { id: 'invitation', label: 'Invite', icon: Wand2 },
    { id: 'business_card', label: 'Business Card', icon: CreditCard },
    { id: 'certificate', label: 'Certificate', icon: Award },
    { id: 'web_banner', label: 'Web Banner', icon: Monitor },
    { id: 'qr_code', label: 'QR Generator', icon: QrCode },
  ];

  return (
    <div className="h-full flex flex-col space-y-6 animate-in fade-in duration-500 max-w-7xl mx-auto pb-12">
      {showSaved && (
        <div className="fixed top-20 right-10 bg-emerald-600 text-white px-8 py-4 rounded-2xl shadow-2xl z-[100] animate-in slide-in-from-right">
          <CheckCircle className="w-5 h-5 mr-3" />
          <span className="font-bold uppercase tracking-widest text-xs">Asset Synced to Studio</span>
        </div>
      )}

      <div className="flex flex-col md:flex-row md:items-end justify-between gap-4">
        <div>
          <h2 className="text-3xl font-black tracking-tight flex items-center uppercase">
            <Megaphone className="w-8 h-8 mr-4 text-amber-500" /> Marketing Omni-Studio
          </h2>
          <p className="text-slate-400 mt-2 font-medium">Professional grade marketing material synthesizer for shop owners and brands.</p>
        </div>
        <div className="flex space-x-3">
          <button onClick={handleSaveFile} className="px-6 py-3 bg-slate-800 border border-slate-700 rounded-2xl text-[10px] font-black uppercase text-slate-100 flex items-center">
